// src/components/ColorCompare.tsx
import type { RGB } from '../config';
import { cn } from '../utils/cn';
import { useSplitCompare } from '../hooks/useSplitCompare';

export function ColorCompare({ targetRgb, approxRgb, targetHex, approxHex }: {
  targetRgb: RGB; approxRgb: RGB; targetHex: string; approxHex: string;
}) {
  const {
    containerRef,
    approxLayerRef,
    handleLineRef,
    handleDotRef,
    ariaValue,
    handleMouseDown,
    handleTouchStart,
    handleKeyDown
  } = useSplitCompare(50);

  const lum = (rgb: RGB) => (0.299 * rgb[0] + 0.587 * rgb[1] + 0.114 * rgb[2]) / 255;
  const targetTextColor = lum(targetRgb) > 0.5 ? 'text-black/50' : 'text-white/60';
  const approxTextColor = lum(approxRgb) > 0.5 ? 'text-black/50' : 'text-white/60';

  return (
    <div className="bg-white dark:bg-slate-900 rounded-[2rem] p-4 sm:p-5 border-2 border-slate-50 dark:border-slate-800 shadow-sm">
      <div className="flex items-center justify-between mb-4 px-1">
        <div className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500">Сравнение</div>
        <div className="text-[9px] font-black uppercase tracking-widest text-indigo-500/50 flex items-center gap-1.5">
           <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="m11 17-5-5 5-5m6 10 5-5-5-5"/></svg>
           <span className="hidden sm:block">Перетаскивайте для анализа</span>
           <span className="sm:hidden">Тяните ползунок</span>
           <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="m13 17 5-5-5-5m-6 10-5-5 5-5"/></svg>
        </div>
      </div>

      <div
        ref={containerRef} tabIndex={0} role="slider" aria-label="Слайдер сравнения" aria-valuemin={5} aria-valuemax={95} aria-valuenow={ariaValue}
        className={cn(
          "relative w-full rounded-[1.5rem] overflow-hidden shadow-premium border-4 border-white dark:border-slate-800 h-24 sm:h-28 select-none cursor-grab active:cursor-grabbing focus:outline-none focus:ring-4 focus:ring-indigo-500/20 transition-all",
        )}
        onMouseDown={handleMouseDown} onTouchStart={handleTouchStart} onKeyDown={handleKeyDown}
      >
        <div className="absolute inset-0" style={{ backgroundColor: `rgb(${targetRgb})` }} />
        <div ref={approxLayerRef} className="absolute inset-0" style={{ backgroundColor: `rgb(${approxRgb})`, clipPath: `polygon(${ariaValue}% 0, 100% 0, 100% 100%, ${ariaValue}% 100%)` }} />

        <div className={cn("absolute top-3 left-4 px-2 py-1 rounded-lg backdrop-blur-md bg-black/10 border border-white/10 pointer-events-none transition-opacity duration-300", ariaValue < 15 && "opacity-0")}>
           <div className="text-[8px] font-black uppercase tracking-[0.2em] text-white/70 leading-none mb-1">Цель</div>
           <div className="text-[10px] font-black font-mono text-white leading-none">{targetHex}</div>
        </div>

        <div className={cn("absolute top-3 right-4 px-2 py-1 rounded-lg backdrop-blur-md bg-black/10 border border-white/10 text-right pointer-events-none transition-opacity duration-300", ariaValue > 85 && "opacity-0")}>
           <div className="text-[8px] font-black uppercase tracking-[0.2em] text-white/70 leading-none mb-1">Итог</div>
           <div className="text-[10px] font-black font-mono text-white leading-none">{approxHex}</div>
        </div>

        <div ref={handleLineRef} className="absolute top-0 bottom-0 pointer-events-none z-10" style={{ left: `${ariaValue}%` }}>
          <div className="w-0.5 h-full bg-white shadow-[0_0_10px_rgba(0,0,0,0.3)]" />
        </div>

        <div ref={handleDotRef} className="absolute top-1/2 pointer-events-none w-10 h-10 rounded-full bg-indigo-600 shadow-premium border-4 border-white dark:border-slate-800 flex items-center justify-center z-20 transition-transform active:scale-110" style={{ left: `${ariaValue}%`, transform: 'translate(-50%, -50%)' }}>
          <svg className="w-4 h-4 text-white" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round"><path d="m9 18-6-6 6-6m6 12 6-6-6-6"/></svg>
        </div>
      </div>
    </div>
  );
}