// src/components/ui/ToastContainer.tsx
import { cn } from '../../utils/cn';
import type { ToastData } from '../../types';

// Упрощенная генерация ID вместо избыточного замыкания
let toastIdCounter = 0;
export const nextToastId = () => ++toastIdCounter;

export function ToastContainer({ toasts, onRemove }: { toasts: ToastData[]; onRemove: (id: number) => void }) {
  return (
    <div className="fixed top-[calc(4.5rem+env(safe-area-inset-top,0px))] sm:top-auto sm:bottom-20 left-1/2 -translate-x-1/2 z-[150] flex flex-col gap-2.5 items-center pointer-events-none w-[calc(100%-2rem)] sm:w-auto">
      {toasts.map((t) => (
        <div 
          key={t.id} 
          onClick={() => onRemove(t.id)}
          className={cn(
            "pointer-events-auto px-5 py-3 rounded-2xl shadow-premium border backdrop-blur-2xl text-xs font-black uppercase tracking-widest max-w-xs text-center cursor-pointer transition-all hover:scale-105 active:scale-95 flex items-center gap-3",
            t.exiting ? "animate-toast-out" : "animate-toast-in",
            t.type === 'success' && "bg-emerald-500/80 border-emerald-400/30 text-white",
            t.type === 'info' && "bg-slate-900/80 border-slate-700/50 text-white dark:bg-white/80 dark:border-white/20 dark:text-slate-900",
            t.type === 'error' && "bg-red-500/80 border-red-400/30 text-white"
          )}
        >
          <div className="flex-shrink-0 w-6 h-6 rounded-lg bg-white/20 flex items-center justify-center shadow-inner">
             {t.type === 'success' && <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>}
             {t.type === 'error' && <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="15" y1="9" x2="9" y2="15"></line><line x1="9" y1="9" x2="15" y2="15"></line></svg>}
             {t.type === 'info' && <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="16" x2="12" y2="12"></line><line x1="12" y1="8" x2="12.01" y2="8"></line></svg>}
          </div>
          <span className="leading-tight">{t.message}</span>
        </div>
      ))}
    </div>
  );
}