// src/hooks/useColorInput.ts
import { useState, useEffect, useCallback } from 'react';
import { smartParseColor, formatRgbInput } from '../utils/colorParsing';
import { rgbToHex } from '../utils/colorMath';
import type { InputMode } from '../types';
import type { RGB } from '../config';

export function useColorInput(addToast: (msg: string, type?: 'info' | 'error' | 'success') => void) {
  const [inputMode, setInputMode] = useState<InputMode>('hex');
  const [hexInput, setHexInput] = useState('');
  const [rgbInputMain, setRgbInputMain] = useState('');
  const [previewRgb, setPreviewRgb] = useState<RGB | null>(null);
  const [errorMsg, setErrorMsg] = useState('');

  useEffect(() => {
    const src = inputMode === 'hex' ? hexInput : rgbInputMain;
    const parsed = smartParseColor(src);
    setPreviewRgb(parsed?.rgb || null);
  }, [inputMode, hexInput, rgbInputMain]);

  useEffect(() => {
    if (previewRgb) {
      if (inputMode === 'rgb') {
        setRgbInputMain(`${previewRgb[0]}, ${previewRgb[1]}, ${previewRgb[2]}`);
      } else {
        setHexInput(rgbToHex(previewRgb));
      }
    }
  }, [inputMode]);

  const handleSmartPaste = useCallback(
    async (e: React.ClipboardEvent) => {
      const text = e.clipboardData.getData('text').trim();
      const parsed = smartParseColor(text);
      if (parsed) {
        e.preventDefault();
        if (inputMode === 'hex') setHexInput(parsed.hex);
        else setRgbInputMain(`${parsed.rgb[0]}, ${parsed.rgb[1]}, ${parsed.rgb[2]}`);
        setErrorMsg('');
        addToast(`Распознан: ${parsed.hex}`, 'info');
      }
    },
    [inputMode, addToast]
  );

  const handleRgbChange = useCallback((value: string) => {
    if (!value) {
      setRgbInputMain('');
      setErrorMsg('');
      return;
    }
    
    // Переиспользуем логику форматирования, убирая дублирование 25+ строк кода
    setRgbInputMain(formatRgbInput(value));
    setErrorMsg('');
  }, []);

  const handleEye = useCallback(async () => {
    if (!(window as any).EyeDropper) {
      addToast('Пипетка не поддерживается браузером', 'error');
      return;
    }
    try {
      const ed = new (window as any).EyeDropper();
      const r = await ed.open();
      setHexInput(r.sRGBHex.toUpperCase());
      setInputMode('hex');
      setErrorMsg('');
      addToast('Цвет выбран', 'success');
    } catch { }
  }, [addToast]);

  return {
    inputMode, setInputMode,
    hexInput, setHexInput,
    rgbInputMain, setRgbInputMain,
    previewRgb,
    errorMsg, setErrorMsg,
    handleSmartPaste,
    handleRgbChange,
    handleEye
  };
}