import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { PaintType, SurfaceType, ColorComponent, RGB } from '../config';
import { PAINT_PROFILES } from '../config';
import {
  type LabWell,
  type LabSwatch,
  type LabChallenge,
  type ChallengeResult,
  createEmptyWell,
  addColorToWell,
  removeColorFromWell,
  clearWell,
  mergeWells,
  createSwatchId,
  checkChallenge,
  checkPrediction,
  changeWellPaintType,
} from '../lab';
