// ============================================================
// ТИПЫ
// ============================================================

export type BrushType = 'round' | 'flat' | 'bristle' | 'sponge';

/** Настройки кисти — выделены отдельно для удобства расширения */
export interface BrushSettings {
  type:        BrushType;
  size:        number;   // px, базовый размер до учёта давления
  opacity:     number;   // 0..1 базовая непрозрачность
  stabilizer:  number;   // 0..1 (0=нет сглаживания, 1=максимум)
  pressureCurve: number; // 0.5=линейное, >1=более резкое
}

/** Точка мазка с расширенными данными стилуса */
export interface StrokePoint {
  x:        number;
  y:        number;
  pressure: number;  // 0..1
  tiltX:    number;  // градусы
  tiltY:    number;  // градусы
  twist:    number;  // градусы (поворот стилуса)
  t:        number;  // timestamp ms
}

/** Стабилизатор кисти — буфер усреднения */
interface StabilizerBuffer {
  points: StrokePoint[];
  capacity: number;
}

function createStabilizer(capacity: number): StabilizerBuffer {
  return { points: [], capacity: Math.max(1, capacity) };
}

function pushStabilizer(buf: StabilizerBuffer, pt: StrokePoint): StrokePoint {
  buf.points.push(pt);
  if (buf.points.length > buf.capacity) {
    buf.points.shift();
  }
  // Возвращаем взвешенное среднее (последние точки весят больше)
  let wx = 0, wy = 0, wp = 0, totalW = 0;
  for (let i = 0; i < buf.points.length; i++) {
    const w = i + 1; // линейный вес: чем новее — тем тяжелее
    wx     += buf.points[i].x        * w;
    wy     += buf.points[i].y        * w;
    wp     += buf.points[i].pressure * w;
    totalW += w;
  }
  return {
    ...pt,
    x:        wx / totalW,
    y:        wy / totalW,
    pressure: wp / totalW,
  };
}

// ============================================================
// ИНТЕРФЕЙС СОСТОЯНИЯ
// ============================================================

interface LabState {
  // ── Среда лаборатории ──────────────────────────────────────
  surfaceType: SurfaceType;
  setSurfaceType: (t: SurfaceType) => void;

  // ── Рабочий стол ──────────────────────────────────────────
  wells:           LabWell[];
  swatches:        LabSwatch[];
  activeWellIndex: number;
  mergeSource:     number | null;
  showDry:         boolean;

  // ── Настройки кисти ───────────────────────────────────────
  brush: BrushSettings;
  setBrushType:       (t: BrushType) => void;
  setBrushSize:       (s: number)    => void;
  setBrushOpacity:    (o: number)    => void;
  setBrushStabilizer: (v: number)    => void;

  // Алиас для обратной совместимости с LabDialog
  selectedBrush:    BrushType;
  setSelectedBrush: (b: BrushType) => void;

  // ── Рисование ─────────────────────────────────────────────
  isDrawingActive:  boolean;
  startStroke:      (pt: PointerEventData, canvasW: number, canvasH: number) => void;
  continueStroke:   (pt: PointerEventData, canvasW: number, canvasH: number) => void;
  endStroke:        ()                                                        => void;

  // Старый API (для совместимости с PaperCanvas)
  startStrokeLegacy:    (x: number, y: number, isDot?: boolean) => void;
  addStrokePointLegacy: (x: number, y: number)                  => void;

  // ── Холст ─────────────────────────────────────────────────
  canvasSize: { w: number; h: number };
  setCanvasSize: (w: number, h: number) => void;

  clearPaper: () => void;
  clearAll:   () => void;

  // ── Лунки ─────────────────────────────────────────────────
  setWells:            (wells: LabWell[]) => void;
  setActiveWellIndex:  (i: number)        => void;
  setMergeSource:      (i: number | null) => void;
  setShowDry:          (v: boolean)       => void;
  addWell:             ()                 => void;
  deleteWell:          ()                 => void;
  clearActiveWell:     ()                 => void;
  setWellPaintType:    (t: PaintType)     => void;
  addColor:            (c: ColorComponent) => void;
  removeColor:         (name: string)     => void;
  mergeActiveWithSource: ()               => boolean;

  // ── Академия ──────────────────────────────────────────────
  currentChallenge:  LabChallenge | null;
  challengeWell:     LabWell;
  challengeResult:   ChallengeResult | null;
  completedIds:      string[];
  predictAnswer:     number | null;
  showHint:          boolean;
  showExplanation:   boolean;

  startChallenge:       (ch: LabChallenge) => void;
  clearChallenge:       ()                 => void;
  challengeAddColor:    (c: ColorComponent) => void;
  challengeRemoveColor: (name: string)     => void;
  clearChallengeWell:   ()                 => void;
  setPredictAnswer:     (i: number | null) => void;
  setShowHint:          (v: boolean)       => void;
  runCheckChallenge:    ()                 => ChallengeResult | null;

  // ── Служебные ─────────────────────────────────────────────
  triggerHaptic: (type?: 'light' | 'medium' | 'heavy') => void;

  // Внутренние (не экспортируются наружу)
  _stabilizer: StabilizerBuffer;
  _animFrameId: number | null;
  _startDryingLoop: () => void;
  _stopDryingLoop:  () => void;
}

// ============================================================
// ДАННЫЕ СОБЫТИЯ УКАЗАТЕЛЯ
// (абстракция над PointerEvent для тестируемости)
// ============================================================

export interface PointerEventData {
  x:        number;   // нормализованные [0..1]
  y:        number;
  pressure: number;   // 0..1 (mouse даёт 0.5)
  tiltX:    number;
  tiltY:    number;
  twist:    number;
  pointerType: 'mouse' | 'pen' | 'touch';
}

export function pointerEventToData(
  e:      React.PointerEvent,
  rect:   DOMRect,
): PointerEventData {
  // Нормализуем давление: мышь всегда 0.5 → приводим к 1.0
  const rawPressure = e.pressure;
  const pressure    = e.pointerType === 'mouse'
    ? 1.0
    : rawPressure < 0.01
      ? 0.0
      : rawPressure;

  return {
    x:           (e.clientX - rect.left)  / rect.width,
    y:           (e.clientY - rect.top)   / rect.height,
    pressure:    Math.max(0, Math.min(1, pressure)),
    tiltX:       e.tiltX  ?? 0,
    tiltY:       e.tiltY  ?? 0,
    twist:       (e as any).twist ?? 0,
    pointerType: (e.pointerType as any) ?? 'mouse',
  };
}

// ============================================================
// ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ
// ============================================================

function applyPressureCurve(pressure: number, curve: number): number {
  return Math.pow(Math.max(0, Math.min(1, pressure)), curve);
}

/**
 * Вычисляет угол наклона стилуса в радианах.
 * Используется для поворота плоской кисти.
 */
function tiltToAngle(tiltX: number, tiltY: number): number {
  if (Math.abs(tiltX) < 1 && Math.abs(tiltY) < 1) return 0;
  return Math.atan2(tiltY, tiltX);
}

function createSwatchFromWell(
  well:        LabWell,
  brushSettings: BrushSettings,
  firstPt:     StrokePoint,
  isDot:       boolean,
): LabSwatch {
  const baseOpacity =
    well.paintType === 'watercolor' ? 0.42 :
    well.paintType === 'oil'        ? 0.98 :
    well.paintType === 'gouache'    ? 0.95 :
                                      0.92;

  // Финальная непрозрачность учитывает настройку кисти
  const opacity = baseOpacity * brushSettings.opacity;

  // Размер кисти с учётом давления
  const pressured = applyPressureCurve(firstPt.pressure, brushSettings.pressureCurve);
  const size      = brushSettings.size * (0.75 + pressured * 0.25);

  // Поворот: для плоской кисти — по наклону стилуса
  const rotation = (brushSettings.type === 'flat' || brushSettings.type === 'bristle')
    ? tiltToAngle(firstPt.tiltX, firstPt.tiltY)
    : Math.random() * Math.PI * 2;

  return {
    id:         createSwatchId(),
    wellId:     well.id,
    type:       isDot ? 'stamp' : 'stroke',
    points:     [{ x: firstPt.x, y: firstPt.y, pressure: firstPt.pressure }],
    wetColor:   [...well.wetColor]  as RGB,
    dryColor:   [...well.dryColor]  as RGB,
    appliedAt:  Date.now(),
    components: well.components.map(c => ({ ...c })),
    paintType:  well.paintType,
    brushType:  brushSettings.type,
    size,
    rotation,
    opacity,
  };
}

// ============================================================
// STORE
// ============================================================

export const useLabStore = create<LabState>()(
  persist(
    (set, get) => ({

      // ── Начальное состояние ──────────────────────────────────

      surfaceType: 'white_paper',

      wells: [
        createEmptyWell('watercolor'),
        createEmptyWell('acrylic'),
        createEmptyWell('gouache'),
      ],
      swatches:        [],
      activeWellIndex: 0,
      mergeSource:     null,
      showDry:         false,

      brush: {
        type:          'round',
        size:          28,
        opacity:       1.0,
        stabilizer:    0.4,
        pressureCurve: 0.8,
      },

      // алиас
      selectedBrush: 'round',

      isDrawingActive: false,

      canvasSize: { w: 800, h: 600 },

      currentChallenge:  null,
      challengeWell:     createEmptyWell('watercolor'),
      challengeResult:   null,
      completedIds:      [],
      predictAnswer:     null,
      showHint:          false,
      showExplanation:   false,

      // Внутренний стабилизатор (не сериализуется)
      _stabilizer:   createStabilizer(5),
      _animFrameId:  null,

      // ── Петля высыхания ──────────────────────────────────────

      _startDryingLoop: () => {
        const state = get();
        if (state._animFrameId !== null) return;

        const loop = () => {
          tickDrying();
          const id = requestAnimationFrame(loop);
          // Сохраняем id напрямую в объект, не через set (избегаем лишних ре-рендеров)
          (get() as any)._animFrameId = id;
        };

        const id = requestAnimationFrame(loop);
        (get() as any)._animFrameId = id;
      },

      _stopDryingLoop: () => {
        const id = get()._animFrameId;
        if (id !== null) {
          cancelAnimationFrame(id);
          (get() as any)._animFrameId = null;
        }
      },

      // ── Тактильный отклик ────────────────────────────────────

      triggerHaptic: (type = 'light') => {
        if (typeof window === 'undefined' || !navigator.vibrate) return;
        try {
          if (type === 'light')  navigator.vibrate(10);
          if (type === 'medium') navigator.vibrate(25);
          if (type === 'heavy')  navigator.vibrate([30, 50, 30]);
        } catch (_) { /* игнорируем */ }
      },

      // ── Поверхность ──────────────────────────────────────────

      setSurfaceType: (surfaceType) => {
        clearBrushCaches();
        set({ surfaceType });
      },

      // ── Размер холста ────────────────────────────────────────

      setCanvasSize: (w, h) => {
        const prev = get().canvasSize;
        if (prev.w === w && prev.h === h) return;
        resizeWetnessMap(w, h);
        clearBrushCaches();
        set({ canvasSize: { w, h } });
      },

      // ── Настройки кисти ──────────────────────────────────────

      setBrushType: (type) => {
        const state = get();
        state.triggerHaptic('light');

        // Автоматически подстраиваем размер под тип кисти
        const sizeMap: Record<BrushType, number> = {
          round:   28,
          flat:    36,
          bristle: 32,
          sponge:  65,
        };

        set((s) => ({
          brush:         { ...s.brush, type, size: sizeMap[type] },
          selectedBrush: type,
        }));
      },

      setBrushSize: (size) =>
        set((s) => ({ brush: { ...s.brush, size: Math.max(4, Math.min(120, size)) } })),

      setBrushOpacity: (opacity) =>
        set((s) => ({ brush: { ...s.brush, opacity: Math.max(0.05, Math.min(1, opacity)) } })),

      setBrushStabilizer: (v) => {
        const capacity = Math.max(1, Math.round(v * 12));
        set((s) => ({
          brush:       { ...s.brush, stabilizer: v },
          _stabilizer: createStabilizer(capacity),
        }));
      },

      setSelectedBrush: (brush) => {
        get().setBrushType(brush);
      },

      // ── РИСОВАНИЕ (новый API с PointerEventData) ─────────────

      startStroke: (ptData, canvasW, canvasH) => {
        const state = get();
        const well  = state.wells[state.activeWellIndex];
        if (!well || well.totalParts === 0) return;

        state.triggerHaptic('medium');
        state._startDryingLoop();

        // Сбрасываем стабилизатор
        const stab = createStabilizer(
          Math.max(1, Math.round(state.brush.stabilizer * 12))
        );

        const pressure = applyPressureCurve(ptData.pressure, state.brush.pressureCurve);
        const rawPt: StrokePoint = {
          x:        ptData.x,
          y:        ptData.y,
          pressure,
          tiltX:    ptData.tiltX,
          tiltY:    ptData.tiltY,
          twist:    ptData.twist,
          t:        Date.now(),
        };
        const stabilized = pushStabilizer(stab, rawPt);

        const newSwatch = createSwatchFromWell(well, state.brush, stabilized, false);

        set((s) => ({
          swatches:       [...s.swatches.slice(-199), newSwatch],
          isDrawingActive: true,
          _stabilizer:    stab,
          canvasSize:     { w: canvasW, h: canvasH },
        }));

        // Обновляем карту влажности
        resizeWetnessMap(canvasW, canvasH);
      },

      continueStroke: (ptData, canvasW, canvasH) => {
        const state = get();
        if (!state.isDrawingActive || state.swatches.length === 0) return;

        const pressure   = applyPressureCurve(ptData.pressure, state.brush.pressureCurve);
        const rawPt: StrokePoint = {
          x:        ptData.x,
          y:        ptData.y,
          pressure,
          tiltX:    ptData.tiltX,
          tiltY:    ptData.tiltY,
          twist:    ptData.twist,
          t:        Date.now(),
        };

        // Применяем стабилизатор
        const stabilized = pushStabilizer(state._stabilizer, rawPt);

        set((s) => {
          if (s.swatches.length === 0) return s;

          const swatches  = [...s.swatches];
          const lastIdx   = swatches.length - 1;
          const last      = { ...swatches[lastIdx] };

          if (last.type !== 'stroke') return s;

          const lastPt = last.points[last.points.length - 1];
          const dx     = stabilized.x - lastPt.x;
          const dy     = stabilized.y - lastPt.y;
          const distSq = dx * dx + dy * dy;

          // Минимальный сдвиг ~0.05% экрана
          if (distSq < 0.000025) return s;

          // Скорость движения для расчёта давления (если стилус не даёт pressure)
          const dt    = Math.max(1, stabilized.t - (last.points[last.points.length - 1] as any).t ?? 16);
          const speed = Math.sqrt(distSq) / dt;

          // Для мышки эмулируем давление через скорость
          let finalPressure = stabilized.pressure;
          if (ptData.pointerType === 'mouse') {
            finalPressure = Math.max(0.3, 1 - speed * 800);
          }

          // Обновляем поворот для плоской/щетинной кисти
          let rotation = last.rotation;
          if (last.brushType === 'flat' || last.brushType === 'bristle') {
            const newAngle = Math.atan2(dy, dx);
            // Плавно интерполируем угол (избегаем резких скачков)
            const diff = newAngle - rotation;
            const normalizedDiff = Math.atan2(Math.sin(diff), Math.cos(diff));
            rotation  = rotation + normalizedDiff * 0.25;
          }

          last.points  = [
            ...last.points,
            { x: stabilized.x, y: stabilized.y, pressure: finalPressure, t: stabilized.t } as any,
          ];
          last.rotation = rotation;
          swatches[lastIdx] = last;

          return { swatches, canvasSize: { w: canvasW, h: canvasH } };
        });
      },

      endStroke: () => {
        set({ isDrawingActive: false });
      },

      // ── РИСОВАНИЕ (старый API — совместимость с PaperCanvas) ─

      startStrokeLegacy: (x, y, isDot = false) => {
        const state = get();
        const well  = state.wells[state.activeWellIndex];
        if (!well || well.totalParts === 0) return;

        state.triggerHaptic('medium');
        state._startDryingLoop();

        const pt: StrokePoint = {
          x, y,
          pressure: 1.0,
          tiltX: 0, tiltY: 0, twist: 0,
          t: Date.now(),
        };

        const newSwatch = createSwatchFromWell(well, state.brush, pt, isDot);

        set((s) => ({
          swatches:       [...s.swatches.slice(-199), newSwatch],
          isDrawingActive: !isDot,
        }));
      },

      addStrokePointLegacy: (x, y) => {
        set((state) => {
          if (state.swatches.length === 0) return state;

          const swatches = [...state.swatches];
          const lastIdx  = swatches.length - 1;
          const last     = { ...swatches[lastIdx] };

          if (last.type !== 'stroke') return state;

          const lastPt = last.points[last.points.length - 1];
          const dx     = x - lastPt.x;
          const dy     = y - lastPt.y;
          const distSq = dx * dx + dy * dy;

          if (distSq < 0.000001) return state;

          const speed    = Math.sqrt(distSq) * 100;
          const pressure = Math.max(0.2, 1 - speed * 0.4);

          last.points = [...last.points, { x, y, pressure }];
          swatches[lastIdx] = last;
          return { swatches };
        });
      },

      // ── Холст ────────────────────────────────────────────────

      clearPaper: () => {
        get().triggerHaptic('heavy');
        clearWetnessMap();
        set({ swatches: [] });
      },

      clearAll: () => {
        get().triggerHaptic('heavy');
        clearWetnessMap();
        set({
          wells: [
            createEmptyWell('watercolor'),
            createEmptyWell('acrylic'),
            createEmptyWell('gouache'),
          ],
          swatches:        [],
          activeWellIndex: 0,
          mergeSource:     null,
        });
      },

      // ── Лунки ────────────────────────────────────────────────

      setWells: (wells) => set({ wells }),

      setActiveWellIndex: (index) => {
        get().triggerHaptic('light');
        set({ activeWellIndex: index });
      },

      setMergeSource: (index) => {
        get().triggerHaptic('medium');
        set({ mergeSource: index });
      },

      setShowDry: (show) => set({ showDry: show }),

      addWell: () => set((state) => {
        if (state.wells.length >= 8) return state;
        state.triggerHaptic('medium');
        const currentPaintType = state.wells[state.activeWellIndex]?.paintType ?? 'watercolor';
        return {
          wells:           [...state.wells, createEmptyWell(currentPaintType)],
          activeWellIndex: state.wells.length,
        };
      }),

      deleteWell: () => set((state) => {
        if (state.wells.length <= 1) return state;
        state.triggerHaptic('heavy');
        return {
          wells:           state.wells.filter((_, i) => i !== state.activeWellIndex),
          activeWellIndex: Math.max(0, state.activeWellIndex - 1),
          mergeSource:     null,
        };
      }),

      clearActiveWell: () => set((state) => {
        state.triggerHaptic('heavy');
        return {
          wells: state.wells.map((w, i) =>
            i === state.activeWellIndex ? createEmptyWell(w.paintType) : w
          ),
        };
      }),

      setWellPaintType: (paintType) => set((state) => {
        state.triggerHaptic('light');

        // Автоматически подбираем кисть под тип краски
        const autoBrush: Partial<BrushSettings> =
          paintType === 'watercolor' ? { type: 'round',   size: 28 } :
          paintType === 'oil'        ? { type: 'bristle', size: 32 } :
          paintType === 'acrylic'    ? { type: 'flat',    size: 36 } :
                                       { type: 'round',   size: 28 };

        return {
          wells: state.wells.map((w, i) =>
            i === state.activeWellIndex ? changeWellPaintType(w, paintType) : w
          ),
          brush:         { ...state.brush, ...autoBrush },
          selectedBrush: autoBrush.type ?? state.brush.type,
        };
      }),

      addColor: (color) => set((state) => {
        state.triggerHaptic('light');
        return {
          wells: state.wells.map((w, i) =>
            i === state.activeWellIndex ? addColorToWell(w, color, 1) : w
          ),
        };
      }),

      removeColor: (name) => set((state) => {
        state.triggerHaptic('light');
        return {
          wells: state.wells.map((w, i) =>
            i === state.activeWellIndex ? removeColorFromWell(w, name, 1) : w
          ),
        };
      }),

      mergeActiveWithSource: () => {
        const state = get();
        if (state.mergeSource === null || state.mergeSource === state.activeWellIndex) return false;

        const wellA = state.wells[state.mergeSource];
        const wellB = state.wells[state.activeWellIndex];
        if (wellA.totalParts === 0 && wellB.totalParts === 0) return false;

        state.triggerHaptic('heavy');
        const merged = mergeWells(wellA, wellB);

        set((s) => {
          const next = [...s.wells];
          next[s.activeWellIndex] = merged;
          next[s.mergeSource!]    = createEmptyWell(next[s.mergeSource!].paintType);
          return { wells: next, mergeSource: null };
        });
        return true;
      },

      // ── Академия ─────────────────────────────────────────────

      startChallenge: (challenge) => {
        let well = createEmptyWell('watercolor');
        if (challenge.type === 'predict_result' && challenge.prefilledWell) {
          well = challenge.prefilledWell.reduce(
            (w, comp) => addColorToWell(w, { name: comp.name, rgb: comp.rgb }, comp.parts),
            well
          );
        }
        set({
          currentChallenge: challenge,
          challengeWell:    well,
          challengeResult:  null,
          showHint:         false,
          showExplanation:  false,
          predictAnswer:    null,
        });
      },

      clearChallenge: () => set({ currentChallenge: null }),

      challengeAddColor: (color) => set((state) => {
        state.triggerHaptic('light');
        return {
          challengeWell:   addColorToWell(state.challengeWell, color, 1),
          challengeResult: null,
        };
      }),

      challengeRemoveColor: (name) => set((state) => {
        state.triggerHaptic('light');
        return {
          challengeWell:   removeColorFromWell(state.challengeWell, name, 1),
          challengeResult: null,
        };
      }),

      clearChallengeWell: () => {
        const state = get();
        state.triggerHaptic('heavy');
        set({
          challengeWell:   createEmptyWell(state.challengeWell.paintType),
          challengeResult: null,
        });
      },

      setPredictAnswer: (index) => {
        get().triggerHaptic('light');
        set({ predictAnswer: index, challengeResult: null });
      },

      setShowHint: (show) => set({ showHint: show }),

      runCheckChallenge: () => {
        const state = get();
        if (!state.currentChallenge) return null;

        let result: ChallengeResult;
        if (state.currentChallenge.type === 'predict_result') {
          if (state.predictAnswer === null) return null;
          result = checkPrediction(state.currentChallenge, state.predictAnswer);
        } else {
          result = checkChallenge(state.currentChallenge, state.challengeWell);
        }

        if (result.passed) state.triggerHaptic('heavy');
        else               state.triggerHaptic('medium');

        set((s) => ({
          challengeResult: result,
          completedIds:    result.passed && !s.completedIds.includes(s.currentChallenge!.id)
            ? [...s.completedIds, s.currentChallenge!.id]
            : s.completedIds,
          showExplanation: result.passed,
        }));

        return result;
      },
    }),

    // ── Персистентность ─────────────────────────────────────────
    {
      name: 'melura_lab_state',
      partialize: (state) => ({
        wells:        state.wells,
        completedIds: state.completedIds,
        surfaceType:  state.surfaceType,
        brush:        state.brush,
      }),
      // После восстановления из localStorage — пересоздаём стабилизатор
      onRehydrateStorage: () => (state) => {
        if (!state) return;
        const capacity = Math.max(1, Math.round((state.brush?.stabilizer ?? 0.4) * 12));
        (state as any)._stabilizer  = createStabilizer(capacity);
        (state as any)._animFrameId = null;
      },
    }
  )
);