// src/hooks/useCalculator.ts
import { useState, useCallback, useRef } from 'react';
import { calculateDrops, type CalculationResult, type RGB } from '../engine';
import { useAppStore } from '../store/appStore';
import type { ColorComponent } from '../config';
import { vibrate } from '../utils/haptics';

export function useCalculator(
  previewRgb: RGB | null,
  calcColors: () => ColorComponent[],
  addToast: (msg: string, type?: 'info' | 'error' | 'success') => void,
  setErrorMsg: (msg: string) => void,
  inputMode: 'hex' | 'rgb'
) {
  const store = useAppStore();
  const [isCalc, setIsCalc] = useState(false);
  const [progress, setProgress] = useState(0);
  const [result, setResult] = useState<CalculationResult | null>(null);
  const [activeVariant, setActiveVariant] = useState(0);
  const calcLock = useRef(false);

  const handleCalc = useCallback(async () => {
    if (calcLock.current || isCalc) return;

    if (!previewRgb) {
      setErrorMsg(inputMode === 'hex' 
        ? 'Введите цвет: HEX, rgb(), hsl() или имя' 
        : 'Формат: 255, 128, 64 или rgb()/hsl()'
      );
      return;
    }

    calcLock.current = true;
    setIsCalc(true);
    setProgress(0);
    setErrorMsg('');
    setActiveVariant(0);

    const comps = calcColors();
    const tt = store.totalPartsLimit === 'авто' || store.totalPartsLimit === '' 
      ? null 
      : parseInt(String(store.totalPartsLimit)) || null;

    try {
      const res = await calculateDrops(
        previewRgb, 
        comps, 
        { ...store.engineSettings, targetTotalParts: tt }, 
        setProgress
      );
      
      setResult(res);
      const bestVar = res.variants[0];

      if (bestVar && bestVar.deltaE > 20) {
        vibrate(50);
        addToast('Точное совпадение не найдено.', 'error');
      } else {
        vibrate([20, 50, 20]);
      }

      if (bestVar) {
        store.addHistory([{
          id: Date.now(), 
          hex: res.targetHex, 
          rgb: res.targetRgb,
          approxRgb: bestVar.approxRgb, 
          deltaE: bestVar.deltaE,
          totalDrops: bestVar.totalDrops, 
          timestamp: Date.now(),
          variantLabel: bestVar.label, 
          paintType: store.engineSettings.paintType,
          recipe: bestVar.recipe,
        }]);
      }
    } catch {
      setErrorMsg('Ошибка при расчёте');
      addToast('Ошибка', 'error');
    } finally {
      setIsCalc(false);
      calcLock.current = false;
    }
  }, [isCalc, previewRgb, inputMode, calcColors, store, addToast, setErrorMsg]);

  return {
    isCalc, progress, result, 
    activeVariant, setActiveVariant, 
    handleCalc
  };
}