import type { RGB, ColorComponent, PaintProfile } from '../config';
import { mixColors } from '../utils/mixing';
import type { RecipeItem, RecipeVariant, SolverCandidate } from './types';

export function getErrorRating(delta: number): string {
  if (delta < 1) return "Идеально";
  if (delta < 2) return "Отлично";
  if (delta < 3.5) return "Очень хорошо";
  if (delta < 5) return "Хорошо";
  if (delta < 10) return "Средне";
  if (delta < 20) return "Слабо";
  return "Плохо";
}

export function buildRecipe(drops: number[], components: ColorComponent[]): RecipeItem[] {
  const total = drops.reduce((s, d) => s + d, 0);
  const items: RecipeItem[] = [];

  for (let i = 0; i < drops.length; i++) {
    if (drops[i] > 0) {
      items.push({
        name: components[i].name,
        rgb: components[i].rgb,
        parts: drops[i],
        percent: total > 0 ? Math.round((drops[i] / total) * 100) : 0,
      });
    }
  }

  if (items.length > 0) {
    const sum = items.reduce((s, it) => s + it.percent, 0);
    if (sum !== 100 && sum > 0) {
      const maxIdx = items.reduce((mi, it, i) => (it.percent > items[mi].percent ? i : mi), 0);
      items[maxIdx].percent += 100 - sum;
    }
  }

  return items;
}

export function makeVariant(
  c: SolverCandidate,
  components: ColorComponent[],
  label: string,
  profile: PaintProfile,
  substrateColor: RGB,
): RecipeVariant {
  return {
    drops: c.drops,
    components,
    deltaE: c.delta,
    totalDrops: c.total,
    approxRgb: mixColors(c.drops, components.map((co) => co.rgb), profile, substrateColor),
    rating: getErrorRating(c.delta),
    usedColors: c.used,
    label,
    recipe: buildRecipe(c.drops, components),
  };
}

export function selectVariants(
  candidates: SolverCandidate[],
  components: ColorComponent[],
  profile: PaintProfile,
  substrateColor: RGB,
): RecipeVariant[] {
  if (candidates.length === 0) return [];

  const seen = new Set<string>();
  const unique = candidates.filter((c) => {
    const k = c.drops.join(',');
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });

  const scored = unique.map((c) => ({
    ...c,
    cs: c.delta + 0.01 * c.total + 0.05 * c.used,
  }));

  scored.sort((a, b) => a.cs - b.cs);

  const variants: RecipeVariant[] = [];
  const best = scored[0];
  variants.push(makeVariant(best, components, ' Лучший', profile, substrateColor));

  const acc = [...scored].sort((a, b) => a.delta - b.delta)[0];
  if (acc.drops.join(',') !== best.drops.join(',') && acc.delta < best.delta - 0.3) {
    variants.push(makeVariant(acc, components, ' Точный', profile, substrateColor));
  }

  const eco = [...scored]
    .filter((c) => c.delta < 8)
    .sort((a, b) => a.total - b.total || a.used - b.used)[0];
  
  if (eco && eco.drops.join(',') !== best.drops.join(',')) {
    variants.push(makeVariant(eco, components, ' Экономный', profile, substrateColor));
  }

  const sim = [...scored]
    .filter((c) => c.delta < 8)
    .sort((a, b) => a.used - b.used || a.total - b.total)[0];
  
  if (
    sim &&
    sim.drops.join(',') !== best.drops.join(',') &&
    (!eco || sim.drops.join(',') !== eco.drops.join(','))
  ) {
    variants.push(makeVariant(sim, components, ' Простой', profile, substrateColor));
  }

  return variants.slice(0, 4);
}