// src/engine/calculator.ts
import type { RGB, ColorComponent, EngineSettings } from '../config';
import { PAINT_PROFILES, SURFACE_PROFILES } from '../config';
import { rgbToLab } from '../utils/colorMath';
import EngineWorker from './worker?worker';
import type { CalculationResult, SolverCandidate } from './types';
import { selectVariants } from './variants';
import { generateWarnings } from './warnings';

// --- Singleton Pattern для Worker'a ---
// Переиспользуем один воркер для экономии памяти и ускорения запуска (особенно для пакетного расчета)
let sharedWorker: Worker | null = null;
let jobCounter = 0;
const activeJobs = new Map<number, { resolve: Function, reject: Function, onProgress: Function, timeout: ReturnType<typeof setTimeout> }>();

function getEngineWorker() {
  if (!sharedWorker) {
    sharedWorker = new EngineWorker();
    
    sharedWorker.onmessage = (e: MessageEvent) => {
      const { type, value, candidates, jobId } = e.data;
      const job = activeJobs.get(jobId);
      if (!job) return; // Задача уже была отменена по таймауту

      if (type === 'progress') {
        job.onProgress(value);
      } else if (type === 'result') {
        clearTimeout(job.timeout);
        activeJobs.delete(jobId);
        job.resolve(candidates);
      }
    };

    sharedWorker.onerror = (err) => {
      activeJobs.forEach(job => {
        clearTimeout(job.timeout);
        job.reject(new Error(`worker error: ${err.message}`));
      });
      activeJobs.clear();
      sharedWorker?.terminate();
      sharedWorker = null;
    };
  }
  return sharedWorker;
}

export async function calculateDrops(
  target: RGB,
  components: ColorComponent[],
  settings: EngineSettings,
  onProgress: (p: number) => void,
): Promise<CalculationResult> {
  const profile = PAINT_PROFILES[settings.paintType];
  const surface = settings.surfaceType === 'custom'
    ? { ...SURFACE_PROFILES.custom, color: settings.customSurfaceColor }
    : SURFACE_PROFILES[settings.surfaceType];
    
  const substrateColor = profile.usesSubstrate ? surface.color : ([255, 255, 255] as RGB);

  const componentsRgb = components.map((c) => c.rgb);
  const n = components.length;
  const maxPC = settings.maxPartsPerColor;
  const maxMix = settings.maxColorsInMix;
  const isFixed = settings.targetTotalParts !== null && settings.targetTotalParts > 0;
  const targetTotal = settings.targetTotalParts;
  const targetLab = rgbToLab(target);

  const worker = getEngineWorker();
  const jobId = ++jobCounter;

  try {
    const candidates: SolverCandidate[] = await new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        activeJobs.delete(jobId);
        reject(new Error('timeout'));
      }, 30000);

      activeJobs.set(jobId, { resolve, reject, onProgress, timeout });

      worker.postMessage({
        jobId, // Отправляем ID задачи воркеру
        target,
        crgb: componentsRgb,
        n,
        mpc: maxPC,
        isF: isFixed,
        tt: targetTotal,
        tLab: targetLab,
        profile: {
          kmWeight: profile.kmWeight,
          transparency: profile.transparency,
          usesSubstrate: profile.usesSubstrate,
          darkeningFactor: profile.darkeningFactor,
        },
        subColor: substrateColor,
        maxMix,
      });
    });

    const variants = selectVariants(candidates, components, profile, substrateColor);

    const best = variants[0] || {
      drops: new Array(n).fill(0),
      components,
      deltaE: 999,
      totalDrops: 0,
      approxRgb: [0, 0, 0] as RGB,
      rating: 'Плохо',
      usedColors: 0,
      label: '',
      recipe: [],
    };

    const targetHex = `#${target.map((v) => v.toString(16).padStart(2, '0')).join('').toUpperCase()}`;
    const warnings = generateWarnings(target, best.deltaE, profile, best.usedColors);

    return {
      targetRgb: target,
      targetHex,
      drops: best.drops,
      components,
      deltaE: best.deltaE,
      totalDrops: best.totalDrops,
      approxRgb: best.approxRgb,
      rating: best.rating,
      variants,
      paintType: settings.paintType,
      warnings,
    };
  } catch (e) {
    throw e;
  }
}