// src/generator/components/CalculatorBottomSheet.tsx
import { useEffect, useRef, useState, useCallback } from "react";
import { useAppStore } from "../store";
import { CalculatorContent } from "./CalculatorPanel";
import { cn } from "../../utils/cn";
import { useBackButton } from "../../hooks/useBackButton";

export function CalculatorBottomSheet() {
  const isMobileView = useAppStore((s) => s.colorPickerActive);
  const pickedColor = useAppStore((s) => s.pickedColor);
  const isOpen = useAppStore((s) => s.colorPickerPanelOpen && s.colorPickerActive);
  const isDark = useAppStore((s) => s.isDark);
  const update = useAppStore((s) => s.update);

  const sheetRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const [dragY, setDragY] = useState(0);

  const touchingRef = useRef(false);
  const startY = useRef(0);
  const startScroll = useRef(0);
  const ignoreDragRef = useRef(false);
  const dragStartedFromHandleRef = useRef(false);

  const close = useCallback(() => {
    update({ colorPickerPanelOpen: false });
  }, [update]);

  useBackButton(isOpen, close);

  useEffect(() => {
    if (isOpen) {
      // document.body.style.overflow = "hidden"; // Don't block scroll if we want to pick colors
    } else {
      setDragY(0);
    }
  }, [isOpen]);

  useEffect(() => {
    const sheet = sheetRef.current;
    if (!sheet || !isOpen) return;

    const isInteractiveTarget = (target: HTMLElement | null) => {
      if (!target) return false;
      return !!(
        target.closest('input') ||
        target.closest('button') ||
        target.closest('select') ||
        target.closest('label')
      );
    };

    const handleTouchStart = (e: TouchEvent) => {
      const target = e.target as HTMLElement;
      dragStartedFromHandleRef.current = !!target.closest("[data-handle]");
      if (isInteractiveTarget(target) && !dragStartedFromHandleRef.current) {
        ignoreDragRef.current = true;
        return;
      }
      ignoreDragRef.current = false;
      const scrollContainer = contentRef.current ?? sheet;
      if (!dragStartedFromHandleRef.current && scrollContainer.scrollTop > 0) return;
      touchingRef.current = true;
      startY.current = e.touches[0].clientY;
      startScroll.current = scrollContainer.scrollTop;
      setDragY(0);
    };

    const handleTouchMove = (e: TouchEvent) => {
      if (ignoreDragRef.current || !touchingRef.current) return;
      const dy = e.touches[0].clientY - startY.current;
      const scrollContainer = contentRef.current ?? sheet;
      if (dragStartedFromHandleRef.current) {
        if (dy > 0) { setDragY(dy); e.preventDefault(); }
        else setDragY(0);
        return;
      }
      if (scrollContainer.scrollTop <= 0 && dy > 0 && startScroll.current <= 0) {
        setDragY(dy);
        e.preventDefault();
      }
    };

    const handleTouchEnd = () => {
      ignoreDragRef.current = false;
      dragStartedFromHandleRef.current = false;
      if (!touchingRef.current) return;
      touchingRef.current = false;
      setDragY((currentDragY) => {
        if (currentDragY > 100) close();
        return 0;
      });
    };

    sheet.addEventListener("touchstart", handleTouchStart, { passive: true });
    sheet.addEventListener("touchmove", handleTouchMove, { passive: false });
    sheet.addEventListener("touchend", handleTouchEnd, { passive: true });
    sheet.addEventListener("touchcancel", handleTouchEnd, { passive: true });

    return () => {
      sheet.removeEventListener("touchstart", handleTouchStart);
      sheet.removeEventListener("touchmove", handleTouchMove);
      sheet.removeEventListener("touchend", handleTouchEnd);
      sheet.removeEventListener("touchcancel", handleTouchEnd);
    };
  }, [isOpen, close]);

  if (!isMobileView) return null;

  const sheetTransform = isOpen ? (dragY > 0 ? `translateY(${dragY}px)` : "translateY(0)") : "translateY(100%)";
  
  return (
    <>
      {/* Кнопка открытия если закрыто */}
      {!isOpen && isMobileView && (
        <button 
          onClick={() => update({ colorPickerPanelOpen: true })}
          className="lg:hidden fixed bottom-6 left-1/2 -translate-x-1/2 z-[45] flex items-center justify-center w-14 h-14 rounded-full bg-indigo-600 text-white shadow-xl animate-fade-in-up active:scale-95 transition-transform"
          aria-label="Показать рецепт"
        >
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
            <path d="m2 22 1-1h3l9-9" /><path d="M3 21v-3l9-9" /><path d="m15 6 3 3 3-3-3-3z" />
          </svg>
        </button>
      )}

      {/* Затемнение фона */}
      {isOpen && (
        <div 
          className="lg:hidden fixed inset-0 bg-black/40 z-[60] animate-fade-in backdrop-blur-sm"
          onClick={close}
        />
      )}

      {/* Bottom Sheet -> Centered Modal on mobile */}
      <div
        ref={sheetRef}
        role="dialog"
        aria-modal="true"
        aria-label="Рецепт цвета"
        className={cn(
          "lg:hidden fixed inset-0 z-[70] flex items-center justify-center p-4 pt-[max(1.5rem,env(safe-area-inset-top))]",
          !isOpen && "pointer-events-none"
        )}
      >
        <div 
          className={cn(
            "w-full max-w-md max-h-[82dvh] rounded-[2.5rem] shadow-2xl overflow-hidden transition-all duration-300 ease-out flex flex-col",
            isDark ? "bg-slate-900 border border-slate-800" : "bg-white",
            isOpen ? "opacity-100 translate-y-0 scale-100" : "opacity-0 translate-y-8 scale-95"
          )}
        >
          <div data-handle className="shrink-0 pt-4 pb-2 flex flex-col items-center">
            <div className={cn("w-10 h-1 rounded-full mb-4", isDark ? "bg-slate-800" : "bg-slate-100")} />
            <div className="flex items-center justify-between w-full px-6 mb-2">
              <div>
                 <h2 className={cn("text-lg font-black tracking-tight", isDark ? "text-white" : "text-slate-900")}>Рецепт цвета</h2>
                 <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest leading-none mt-0.5">Melura Studio Smart Calc</p>
              </div>
              <button onClick={close} className={cn("w-11 h-11 rounded-2xl flex items-center justify-center transition-colors shadow-sm", isDark ? "bg-slate-800 text-slate-500 hover:bg-slate-700" : "bg-slate-100 text-slate-600 hover:bg-slate-200")} aria-label="Закрыть">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M18 6 6 18M6 6l12 12" />
                </svg>
              </button>
            </div>
          </div>

          <div ref={contentRef} className="flex-1 overflow-y-auto overscroll-contain custom-scrollbar px-2 pb-24">
             <CalculatorContent 
               pickedColor={pickedColor} 
               onClose={() => update({ colorPickerActive: false, pickedColor: null, colorPickerPanelOpen: false })} 
               isMobileView 
             />
          </div>
        </div>
      </div>
    </>
  );
}
