import React from 'react';

export type RGB = [number, number, number];

export interface ColorComponent {
  name: string;
  rgb: RGB;
}

/* ─── Типы красок ─── */
export type PaintType = 'gouache' | 'acrylic' | 'watercolor' | 'oil';

export interface PaintProfile {
  id: PaintType;
  name: string;
  description: string;
  icon: React.ReactNode; 
  /** Вес Kubelka-Munk модели (0 = чистый линейный RGB, 1 = чистый KM) */
  kmWeight: number;
  /** Прозрачность краски (0 = полностью укрывистая, 1 = полностью прозрачная) */
  transparency: number;
  /** Учитывать ли подложку */
  usesSubstrate: boolean;
  /** Максимум цветов в смеси (рекомендация) */
  maxColorsInMix: number;
  /** Коэффициент затемнения при смешивании (больше = темнее результат) */
  darkeningFactor: number;
  /** Единица измерения */
  unitName: string;
  unitNamePlural: string;
  unitNameGenitive: string;
  unitAbbrev: string;
  /** Параметры высыхания */
  drying: DryingProfile;
}

/* ─── Профиль высыхания ─── */
export interface DryingProfile {
  /** Множитель яркости при высыхании (>1 = светлеет, <1 = темнеет, 1 = не меняется) */
  brightnessFactor: number;
  /** Изменение насыщенности при высыхании (>0 = ярче, <0 = приглушённее, 0 = нет) */
  saturationShift: number;
  /** Время полного высыхания в секундах (для анимации) */
  dryTimeSeconds: number;
  /** Описание для UI */
  description: string;
}

