/* ─── Утилиты для единиц измерения ─── */
export function getUnitLabel(count: number, profile: PaintProfile): string {
  const abs = Math.abs(count);
  const lastTwo = abs % 100;
  const lastOne = abs % 10;

  if (lastTwo >= 11 && lastTwo <= 19) return profile.unitNameGenitive;
  if (lastOne === 1) return profile.unitName;
  if (lastOne >= 2 && lastOne <= 4) return profile.unitNamePlural;
  return profile.unitNameGenitive;
}

export function formatParts(count: number, profile: PaintProfile): string {
  return `${count} ${profile.unitAbbrev}`;
}

export function formatPartsFull(count: number, profile: PaintProfile): string {
  return `${count} ${getUnitLabel(count, profile)}`;
}

