// src/components/ToolButton.tsx
export function ToolButton({ icon, label, onClick, hidden, badge }: {
  icon: React.ReactNode;
  label: string; 
  onClick: () => void; 
  hidden?: boolean; 
  badge?: number;
}) {
  if (hidden) return null;
  return (
    <button onClick={onClick}
      className="w-full flex items-center gap-3 py-3 px-4 rounded-2xl text-sm font-medium text-left border border-slate-200/50 dark:border-slate-700/50 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-900 dark:hover:text-white hover:border-slate-300/50 dark:hover:border-slate-600/50 transition-all shadow-sm hover:shadow-md hover:scale-[1.02] active:scale-95 group">
      <span className="text-base w-5 flex items-center justify-center shrink-0 group-hover:scale-110 transition-transform">{icon}</span>
      <span className="text-left flex-1">{label}</span>
      {badge !== undefined && badge > 0 && (
        <span className="px-2 py-0.5 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-200 text-[10px] rounded-full font-bold shadow-inner">{badge}</span>
      )}
    </button>
  );
}