// src/generator/components/PreviewControls.tsx
import React from "react";
import { useAppStore } from "../store";
import { cn } from "../../utils/cn";
import { ZoomBtn, VisualGridBtn } from "./ui/ToolButtons";

interface Props {
  doZoom: (f: number) => void;
  resetView: (force?: boolean) => void;
  flushViewSnapshotToStore: () => void;
  zoomTextRef: React.RefObject<HTMLDivElement | null>;
}

export function PreviewControls({ doZoom, resetView, flushViewSnapshotToStore, zoomTextRef }: Props) {
  const s = useAppStore();
  const hasImage = !!(s.originalImageUrl || s.correctedImageUrl);
  const hasRes = !!s.result;
  const hasOrig = !!s.originalImageUrl;
  const showCorrectionBtn = hasOrig && !hasRes;
  const hasCorrectionChanges =
    s.correction.brightness !== 0 ||
    s.correction.contrast !== 0 ||
    s.correction.saturation !== 0 ||
    s.correction.sharpness !== 0;
  const isArtistic = s.presetKey === "artistic";
  const colorPickerActive = s.colorPickerActive;

  if (!hasImage) return null;

  return (
    <div data-overlay-controls className="pointer-events-none absolute inset-0 z-20 flex flex-col justify-between overflow-hidden p-3 sm:p-5">
      {/* ВЕРХНИЙ РЯД: Коррекция + Пипетка (мобилки) */}
      <div className="flex justify-between items-start w-full">
        <div className="pointer-events-auto flex items-start gap-2">
           {hasRes && (
             <button
                onClick={(e) => {
                  e.stopPropagation();
                  const next = !colorPickerActive;
                  s.update({ colorPickerActive: next });
                  if (!next) {
                    s.update({ pickedColor: null, colorPickerPanelOpen: false });
                  }
                  flushViewSnapshotToStore();
                }}
                className={cn(
                  "flex items-center gap-2.5 px-4 h-11 rounded-2xl font-black text-[10px] uppercase tracking-[0.15em] shadow-xl transition-all border backdrop-blur-xl",
                  colorPickerActive
                    ? "bg-indigo-600 text-white border-indigo-500 animate-pulse shadow-indigo-500/20"
                    : "bg-white/95 dark:bg-slate-900/95 text-slate-700 dark:text-slate-300 border-slate-200/50 dark:border-slate-800/50 hover:bg-slate-50"
                )}
                title="Определить цвет (P)"
             >
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <path d="m2 22 1-1h3l9-9" /><path d="M3 21v-3l9-9" /><path d="m15 6 3 3 3-3-3-3z" />
                </svg>
                <span className="hidden sm:inline">Пипетка</span>
             </button>
           )}
        </div>

        <div className="pointer-events-auto flex flex-col gap-2 items-end">
          {showCorrectionBtn && (
            <button
              onClick={() => s.update({ mobileCorrectionOpen: !s.mobileCorrectionOpen })}
              className={cn(
                "lg:hidden flex items-center gap-2 px-4 h-11 rounded-2xl font-black text-[11px] uppercase tracking-wider shadow-xl transition-all border backdrop-blur-xl",
                s.mobileCorrectionOpen || hasCorrectionChanges
                  ? "bg-amber-500 text-white border-amber-400"
                  : "bg-white/95 dark:bg-gray-900/95 text-slate-700 dark:text-slate-300 border-slate-200/50 dark:border-slate-800/50 hover:bg-slate-50 dark:hover:bg-slate-800"
              )}
            >
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10" />
                <path d="M12 2a10 10 0 0 1 0 20" fill="currentColor" opacity="0.3" />
                <line x1="12" y1="6" x2="12" y2="18" />
              </svg>
              Коррекция
            </button>
          )}
        </div>
      </div>

      {/* СРЕДНИЙ РЯД: Сетки и Зум */}
      <div className="flex justify-between items-end md:items-center w-full mt-auto mb-4 md:mb-0 md:mt-0 pointer-events-none">
        {/* Панель Сеток (левая, вертикальная) */}
        <div className="pointer-events-auto flex flex-col gap-1.5 p-1.5 rounded-2xl shadow-xl border backdrop-blur-xl bg-white/95 dark:bg-gray-900/95 dark:border-gray-700/50 border-gray-200/50">
           <VisualGridBtn 
             active={s.gridType === "none"} 
             onClick={() => { s.setGridType("none"); flushViewSnapshotToStore(); }} 
             title="Без сетки"
             icon={<><rect x="4" y="4" width="16" height="16" rx="2" opacity="0.2"/><line x1="4" y1="4" x2="20" y2="20" opacity="0.6"/></>}
           />
           <div className="w-6 h-px mx-auto bg-slate-100 dark:bg-slate-800 my-0.5" />
           <VisualGridBtn 
             active={s.gridType === "thirds"} 
             onClick={() => { s.setGridType("thirds"); flushViewSnapshotToStore(); }} 
             title="Правило третей (3х3)"
             icon={<><line x1="8" y1="4" x2="8" y2="20"/><line x1="16" y1="4" x2="16" y2="20"/><line x1="4" y1="8" x2="20" y2="8"/><line x1="4" y1="16" x2="20" y2="16"/></>}
           />
           <VisualGridBtn 
             active={s.gridType === "golden"} 
             onClick={() => { s.setGridType("golden"); flushViewSnapshotToStore(); }} 
             title="Золотое сечение (Фи)"
             icon={<><line x1="9" y1="4" x2="9" y2="20" opacity="0.9"/><line x1="15" y1="4" x2="15" y2="20" opacity="0.9"/><line x1="4" y1="9" x2="20" y2="9" opacity="0.9"/><line x1="4" y1="15" x2="20" y2="15" opacity="0.9"/></>}
           />
           <VisualGridBtn 
             active={s.gridType === "grid"} 
             onClick={() => { s.setGridType("grid"); flushViewSnapshotToStore(); }} 
             title="Квадраты (Сетка)"
             icon={<><path d="M4 4h16v16H4z" opacity="0.1"/><path d="M8 4v16M12 4v16M16 4v16M4 8h16M4 12h16M4 16h16" strokeWidth="1.2"/></>}
           />
        </div>

        {/* Панель Зума и Зеркала (справа, скрыта на мобилках) */}
        <div className="pointer-events-auto hidden md:flex flex-col gap-1 p-1.5 rounded-2xl shadow-xl border backdrop-blur-xl bg-white/95 dark:bg-gray-900/95 dark:border-gray-700/50 border-gray-200/50 items-center">
          <ZoomBtn icon={<path d="M12 5v14M5 12h14" />} onClick={() => doZoom(1.3)} title="Увеличить" />
          <ZoomBtn icon={<path d="M5 12h14" />} onClick={() => doZoom(0.77)} title="Уменьшить" />
          <div className="md:h-px md:w-6 w-px h-6 mx-auto bg-slate-200 dark:bg-slate-800 my-auto md:my-1" />
          <ZoomBtn icon={<><circle cx="12" cy="12" r="10" /><path d="M12 8v8" /><path d="M8 12h8" /></>} onClick={() => { resetView(true); flushViewSnapshotToStore(); }} title="Сбросить (1:1)" />
          <ZoomBtn icon={<><path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3" /></>} onClick={() => doZoom(-1)} title="На весь экран" />
          <div className="md:h-px md:w-6 w-px h-6 mx-auto bg-slate-200 dark:bg-slate-800 my-auto md:my-1" />
          <ZoomBtn 
            icon={<path d="M7 10L3 14l4 4M17 10l4 4-4 4M12 3v18" />} 
            onClick={() => { s.toggleFlip(); flushViewSnapshotToStore(); }} 
            title="Отразить холст (F)" 
          />
          <div ref={zoomTextRef} className="hidden md:block text-[10px] font-black font-mono text-center pt-1 text-slate-500 dark:text-slate-300 tabular-nums">100%</div>
        </div>
      </div>

      {/* НИЖНИЙ РЯД: Только этапы для Живописи */}
      <div className="flex flex-col items-center gap-2 pointer-events-auto mb-2 md:mb-0">
        {hasRes && isArtistic && (
          <div className="flex p-1.5 rounded-2xl shadow-xl border backdrop-blur-xl overflow-x-auto scrollbar-none bg-white/95 dark:bg-slate-900/90 border-slate-200/50 dark:border-slate-800/50 max-w-full">
            {[
              { step: 0, label: "Контуры" },
              { step: 1, label: "Подмалёвок" },
              { step: 10, label: "Температура", isTemp: true },
              { step: 2, label: "Цвет" },
              { step: 3, label: "Детали" },
            ].map((btn) => {
              const isActive = btn.isTemp ? s.showTemperatureMap : (s.artisticStep === btn.step && !s.showTemperatureMap);
              
              return (
                <button
                  key={btn.step}
                  onClick={() => {
                    if (btn.isTemp) {
                      const next = !s.showTemperatureMap;
                      s.update({ showTemperatureMap: next, artisticStep: next ? -1 : s.artisticStep === -1 ? 0 : s.artisticStep });
                      flushViewSnapshotToStore();
                    } else {
                      if (s.showTemperatureMap) s.update({ showTemperatureMap: false });
                      flushViewSnapshotToStore();
                      s.setArtisticStepAnimated(btn.step);
                    }
                  }}
                  className={cn(
                    "px-4 py-2.5 rounded-xl text-[10px] sm:text-[11px] font-black transition-all whitespace-nowrap uppercase tracking-wider",
                    isActive
                      ? "bg-indigo-600 text-white shadow-lg shadow-indigo-500/30 scale-105"
                      : "text-slate-600 dark:text-slate-200 hover:text-indigo-600 dark:hover:text-indigo-400 hover:bg-slate-100 dark:hover:bg-slate-800"
                  )}
                >
                  {btn.label}
                </button>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
