// src/components/dialogs/RecipeDetailDialog.tsx
import { useMemo } from 'react';
import { PAINT_PROFILES, type PaintProfile } from '../../config';
import { cn } from '../../utils/cn';
import { copyToClipboard } from '../../utils/clipboard';
import { formatSmartDate } from '../../utils/formatting';
import { formatRecipeText } from '../../utils/formatting';
import type { HistoryEntry } from '../../types';
import { ModalWide } from '../ui/Modal';
import { MetricCard } from '../ui/MetricCard';
import { StarsRating } from '../ui/StarsRating';
import { RecipeRow } from '../RecipeRow';

export function RecipeDetailDialog({ entry, onClose, onCopy, isFavorite, onToggleFav, onRecalculate, profile }: {
  entry: HistoryEntry; onClose: () => void; onCopy: (m: string) => void;
  isFavorite: boolean; onToggleFav: () => void; onRecalculate: (hex: string) => void;
  profile: PaintProfile;
}) {
  const handleExport = async () => {
    const text = formatRecipeText(entry, profile);
    const ok = await copyToClipboard(text);
    onCopy(ok ? 'Рецепт скопирован!' : 'Не удалось скопировать');
  };

  const entryProfile = entry.paintType ? PAINT_PROFILES[entry.paintType] : profile;

  const sortedRecipe = useMemo(() => {
    return [...entry.recipe].sort((a, b) => b.parts - a.parts);
  }, [entry.recipe]);

  const accuracyLabel = 
    entry.deltaE < 1 ? 'Идеальное попадание' :
    entry.deltaE < 2 ? 'Высокая точность' :
    entry.deltaE < 5 ? 'Хорошее соответствие' :
    entry.deltaE < 10 ? 'Заметное отличие' : 'Низкое соответствие';

  const accuracyColor = 
    entry.deltaE < 2 ? 'text-emerald-500' :
    entry.deltaE < 5 ? 'text-blue-500' :
    entry.deltaE < 10 ? 'text-amber-500' : 'text-red-500';

  return (
    <ModalWide onClose={onClose} zClass="z-[75]">
      <div className="px-5 pt-4 sm:pt-5 pb-4 border-b border-slate-200/50 dark:border-slate-800/50 flex flex-col shrink-0">
        <div className="flex items-center justify-between mb-1">
          <div className="flex items-center gap-2.5">
            <span className="text-2xl shrink-0">{entryProfile.icon}</span>
            <div>
               <h2 className="text-base sm:text-lg font-bold text-slate-900 dark:text-white leading-tight">Рецепт {entry.hex}</h2>
               <div className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500">{entryProfile.name}</div>
            </div>
          </div>
          <div className="flex items-center gap-1">
            <button onClick={onToggleFav} className={cn("w-10 h-10 rounded-full flex items-center justify-center transition-all active:scale-90", isFavorite ? "text-amber-500 bg-amber-50 dark:bg-amber-900/20 shadow-inner" : "text-slate-400 bg-slate-50 dark:bg-slate-800")}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill={isFavorite ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
              </svg>
            </button>
            <button onClick={onClose} className="w-10 h-10 -mr-2 rounded-full flex items-center justify-center bg-slate-100 dark:bg-slate-800 text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors" aria-label="Закрыть">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M18 6L6 18M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-5 space-y-6 pb-24 custom-scrollbar overscroll-contain touch-pan-y">
        {/* HERO SECTION: Сравнение цветов */}
        <div className="flex flex-col items-center justify-center py-4">
           <div className="relative flex items-center justify-center w-full max-w-[280px]">
              {/* Карточка ЦЕЛИ */}
              <div className="w-32 h-32 sm:w-40 sm:h-40 rounded-[2.5rem] shadow-2xl border-4 border-white dark:border-slate-800 transform -rotate-6 -translate-x-6 relative z-10 overflow-hidden" style={{ backgroundColor: entry.hex }}>
                 <div className="absolute inset-0 bg-gradient-to-tr from-black/20 to-transparent" />
                 <div className="absolute bottom-3 left-0 right-0 text-center">
                    <span className="text-[10px] font-black uppercase tracking-widest text-white/90 drop-shadow-md">Цель</span>
                 </div>
              </div>
              {/* Карточка РЕЗУЛЬТАТА */}
              <div className="w-32 h-32 sm:w-40 sm:h-40 rounded-[2.5rem] shadow-2xl border-4 border-white dark:border-slate-800 transform rotate-6 translate-x-6 relative z-20 overflow-hidden" style={{ backgroundColor: `rgb(${entry.approxRgb})` }}>
                 <div className="absolute inset-0 bg-gradient-to-tr from-black/20 to-transparent" />
                 <div className="absolute bottom-3 left-0 right-0 text-center">
                    <span className="text-[10px] font-black uppercase tracking-widest text-white/90 drop-shadow-md">Результат</span>
                 </div>
              </div>
           </div>
        </div>

        {/* DASHBOARD: Метрики точности */}
        <div className="bg-slate-50 dark:bg-indigo-950/20 rounded-[2rem] p-5 border border-slate-100 dark:border-indigo-900/30 shadow-premium relative overflow-hidden">
           <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/5 blur-3xl" />
           <div className="grid grid-cols-2 gap-4 relative z-10">
              <div className="space-y-1">
                 <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500">Точность расчёта</div>
                 <div className={cn("text-2xl font-black tabular-nums", accuracyColor)}>ΔE {entry.deltaE.toFixed(1)}</div>
                 <div className="text-[11px] font-bold text-slate-600 dark:text-slate-300">{accuracyLabel}</div>
              </div>
              <div className="flex flex-col items-end justify-center">
                 <StarsRating deltaE={entry.deltaE} />
                 <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mt-2">
                    {entry.totalDrops} {entryProfile.unitNameGenitive}
                 </div>
              </div>
           </div>
           
           <div className="mt-5 h-1.5 bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden shadow-inner">
              <div className={cn("h-full transition-all duration-1000 ease-out", 
                entry.deltaE < 2 ? 'bg-emerald-500' : entry.deltaE < 5 ? 'bg-blue-500' : 'bg-amber-500')} 
                style={{ width: `${Math.max(5, 100 - (entry.deltaE * 5))}%` }} />
           </div>
        </div>

        {/* СПИСОК КОМПОНЕНТОВ */}
        <div className="space-y-4">
          <div className="flex items-center gap-2 px-1">
             <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
             <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500">Состав смеси</h3>
             <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
          </div>

          <div className="space-y-2.5">
            {sortedRecipe.map(r => (
              <div key={r.name} className="group relative flex items-center gap-4 p-4 rounded-3xl bg-white dark:bg-slate-900 border-2 border-slate-50 dark:border-slate-800 shadow-sm overflow-hidden">
                <div className="absolute inset-0 bg-indigo-500/5 dark:bg-indigo-500/10 transition-all origin-left" style={{ width: `${r.percent}%` }} />
                
                <div className="relative z-10 w-10 h-10 rounded-xl shadow-md border-2 border-white dark:border-slate-800 shrink-0 overflow-hidden" style={{ backgroundColor: `rgb(${r.rgb})` }}>
                   <div className="absolute inset-0 bg-gradient-to-tr from-black/10 to-white/10" />
                </div>
                
                <div className="relative z-10 flex-1 min-w-0">
                  <div className="text-xs font-black text-slate-800 dark:text-slate-100 truncate uppercase tracking-tighter leading-none mb-1.5">{r.name}</div>
                  <div className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">{r.percent.toFixed(1)}% объема</div>
                </div>
                
                <div className="relative z-10 text-right">
                  <div className="text-sm font-black font-mono text-indigo-600 dark:text-indigo-400 leading-none mb-1">{r.parts}</div>
                  <div className="text-[8px] font-black text-slate-300 dark:text-slate-600 uppercase tracking-widest">{entryProfile.unitNameShort}</div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* КНОПКИ ДЕЙСТВИЙ */}
        <div className="grid grid-cols-2 gap-3 pt-2">
           <button onClick={handleExport} className="py-4 rounded-2xl font-black text-[11px] uppercase tracking-[0.15em] bg-white dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-750 transition-all active:scale-95 shadow-sm flex items-center justify-center gap-2">
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>
              Копировать
           </button>
           <button onClick={() => { onRecalculate(entry.hex); onClose(); }} className="py-4 rounded-2xl font-black text-[11px] uppercase tracking-[0.15em] bg-indigo-600 text-white hover:bg-indigo-700 transition-all active:scale-95 shadow-lg shadow-indigo-600/25 flex items-center justify-center gap-2">
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/></svg>
              Уточнить
           </button>
        </div>

        <div className="text-center space-y-1 pt-4 opacity-40 group hover:opacity-100 transition-opacity">
          <div className="text-[10px] font-black uppercase tracking-widest text-slate-500">{formatSmartDate(entry.timestamp)}</div>
          {entry.variantLabel && <div className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">Вариант: {entry.variantLabel}</div>}
        </div>
      </div>
    </ModalWide>
  );
}