import { SURFACE_PROFILES, type SurfaceType } from '../config';
import { cn } from '../utils/cn';
import { SectionTitle } from './ui/SectionTitle';

export function SurfaceSelector({ value, onChange }: { value: SurfaceType; onChange: (v: SurfaceType) => void }) {
  const types: SurfaceType[] = ['white_paper', 'cream_paper', 'craft_paper', 'canvas', 'wood'];

  return (
    <div className="space-y-4">
      <SectionTitle>Поверхность</SectionTitle>
      <div className="grid grid-cols-2 xs:grid-cols-3 gap-2 px-0.5">
        {types.map(t => {
          const p = SURFACE_PROFILES[t];
          const active = value === t;
          return (
            <button key={t} onClick={() => onChange(t)}
              className={cn(
                "relative flex items-center gap-2.5 py-3 px-3.5 rounded-2xl border-2 transition-all duration-300 active:scale-95 group shadow-sm",
                active
                  ? "border-indigo-600 bg-white dark:bg-slate-900 shadow-indigo-500/10 z-10"
                  : "border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950 hover:border-slate-200 dark:hover:border-slate-700"
              )}>
              <span className={cn(
                "text-lg flex items-center justify-center transition-transform",
                active 
                  ? "scale-110 text-indigo-600 dark:text-indigo-400 drop-shadow-[0_0_8px_rgba(99,102,241,0.4)]" 
                  : "text-slate-500 dark:text-slate-400 group-hover:text-slate-600 dark:group-hover:text-slate-300"
              )}>{p.icon}</span>
              <span className={cn(
                "text-[10px] font-black uppercase tracking-widest leading-none truncate",
                active ? "text-slate-900 dark:text-white" : "text-slate-500 dark:text-slate-400"
              )}>
                {p.name.split(' ')[0]}
              </span>
            </button>
          );
        })}
      </div>
    </div>
  );
}