import type { RGB, ArtisticPresetId } from '../../config';
import { clamp01, lerpRgb } from './mathHelpers';
import { 
  warmCoolStrategy, 
  fauvismStrategy, 
  impressionismStrategy, 
  noirStrategy, 
  vintageStrategy, 
  popArtStrategy, 
  customPaletteStrategy 
} from './presets';

export * from './mathHelpers';
export * from './notan';
export * from './temperature';
export * from './presets';
export * from './zoneInfo';

/**
 * Смешивает оригинальный цвет со стилизованным по заданной интенсивности.
 */
export function blendWithIntensity(original: RGB, styled: RGB, intensity: number): RGB {
  const t = clamp01(intensity / 100);
  return lerpRgb(original, styled, t);
}

/**
 * Применяет выбранную художественную стратегию к цвету.
 */
export function applyArtisticStrategy(
  rgb: RGB,
  presetId: ArtisticPresetId | 'custom_palette',
  intensity: number = 100,
  customPalette?: RGB[]
): RGB {
  let styled: RGB;

  switch (presetId) {
    case 'warm_cool':
      styled = warmCoolStrategy(rgb);
      break;
    case 'fauvism':
      styled = fauvismStrategy(rgb);
      break;
    case 'impressionism':
      styled = impressionismStrategy(rgb);
      break;
    case 'noir':
      styled = noirStrategy(rgb);
      break;
    case 'vintage':
      styled = vintageStrategy(rgb);
      break;
    case 'pop_art':
      styled = popArtStrategy(rgb);
      break;
    case 'custom_palette':
      if (customPalette && customPalette.length > 0) {
        styled = customPaletteStrategy(rgb, customPalette);
      } else {
        styled = warmCoolStrategy(rgb);
      }
      break;
    default:
      styled = warmCoolStrategy(rgb);
  }

  if (intensity < 100) {
    return blendWithIntensity(rgb, styled, intensity);
  }

  return styled;
}

/**
 * Генерирует превью палитры для пресета.
 * Возвращает 6 цветов, демонстрирующих характер палитры.
 */
export function getPresetPreviewColors(presetId: ArtisticPresetId): RGB[] {
  const baseGrayscale: RGB[] = [
    [30, 30, 30],
    [70, 70, 70],
    [120, 120, 120],
    [170, 170, 170],
    [210, 210, 210],
    [250, 250, 250],
  ];

  return baseGrayscale.map(rgb => applyArtisticStrategy(rgb, presetId));
}

export interface GridLine {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

/**
 * Генерирует линии сетки для превью.
 * @param gridType - тип сетки: "grid" (квадратная) или "diagonal" (диагональная)
 * @param gridSize - размер ячейки (количество делений)
 */
export function generateGridLines(gridType: string, gridSize: number): GridLine[] {
  const lines: GridLine[] = [];
  const size = Math.max(gridSize, 2);

  if (gridType === "grid") {
    // Вертикальные линии
    for (let i = 1; i < size; i++) {
      const x = i / size;
      lines.push({ x1: x, y1: 0, x2: x, y2: 1 });
    }
    // Горизонтальные линии
    for (let i = 1; i < size; i++) {
      const y = i / size;
      lines.push({ x1: 0, y1: y, x2: 1, y2: y });
    }
  } else if (gridType === "diagonal") {
    // Диагональные линии
    for (let i = 0; i <= size; i++) {
      const t = i / size;
      // Сверху-влево -> вниз-вправо
      lines.push({ x1: t, y1: 0, x2: 0, y2: t });
      lines.push({ x1: t, y1: 1, x2: 1, y2: t });
    }
  } else if (gridType === "thirds") {
    // Правило третей
    lines.push({ x1: 1/3, y1: 0, x2: 1/3, y2: 1 });
    lines.push({ x1: 2/3, y1: 0, x2: 2/3, y2: 1 });
    lines.push({ x1: 0, y1: 1/3, x2: 1, y2: 1/3 });
    lines.push({ x1: 0, y1: 2/3, x2: 1, y2: 2/3 });
  } else if (gridType === "golden") {
    // Золотое сечение (Фи)
    const phi = 0.61803398875;
    const invPhi = 1 - phi;
    lines.push({ x1: invPhi, y1: 0, x2: invPhi, y2: 1 });
    lines.push({ x1: phi, y1: 0, x2: phi, y2: 1 });
    lines.push({ x1: 0, y1: invPhi, x2: 1, y2: invPhi });
    lines.push({ x1: 0, y1: phi, x2: 1, y2: phi });
  }

  return lines;
}