// src/generator/hooks/useExport.ts
import { useState, useCallback, useMemo } from "react";
import { useAppStore } from "../store";
import { useAppStore as useGlobalStore } from "../../store/appStore";
import { BASE_COLORS, EXTENDED_COLORS, type PaintType, type SurfaceType } from "../../config";
import { generatePdf } from "../utils/pdfExport";
import { generateSVGContent, generateInteractiveHTML } from "../utils/imageProcessing";

export interface ExportSettings {
  format: "pdf" | "svg" | "html";
  paperSize: "a4" | "a3" | "a2";
  dpi: number;
  tileMode: boolean;
  includeRecipes: boolean;
}

export const PAPER_SIZES: Record<string, { w: number; h: number; label: string }> = {
  a4: { w: 210, h: 297, label: "A4 (210×297 мм)" },
  a3: { w: 297, h: 420, label: "A3 (297×420 мм)" },
  a2: { w: 420, h: 594, label: "A2 (420×594 мм)" },
};

export function useExport() {
  const s = useAppStore();
  const gs = useGlobalStore();

  const [exportPaintType, setExportPaintType] = useState<PaintType>(gs.engineSettings.paintType);
  const [exportSurfaceType, setExportSurfaceType] = useState<SurfaceType>(gs.engineSettings.surfaceType);
  const [paperSize, setPaperSize] = useState<"a4" | "a3" | "a2">("a4");
  const [dpi, setDpi] = useState(300);
  const [tileMode, setTileMode] = useState(false);
  const [includeRecipes, setIncludeRecipes] = useState(true);

  const close = useCallback(() => s.update({ exportModalOpen: false }), [s.update]);

  const allAvailableColors = useMemo(() => {
    const rawColors = [...BASE_COLORS, ...EXTENDED_COLORS, ...gs.customColors];
    const unique = [];
    const seen = new Set();
    for (const c of rawColors) {
      if (gs.deletedBuiltIns.includes(c.name)) continue;
      if (!seen.has(c.name)) {
        seen.add(c.name);
        unique.push(c);
      }
    }
    return unique;
  }, [gs.deletedBuiltIns, gs.customColors]);

  const activeComps = useMemo(() => {
    return allAvailableColors
      .filter((c) => gs.selectedNames.includes(c.name))
      .map((c) => ({ ...c, rgb: gs.overrides[c.name] || c.rgb }));
  }, [allAvailableColors, gs.selectedNames, gs.overrides]);

  const handlePdfExport = async () => {
    if (!s.result) return;
    s.update({ isExporting: true, statusMsg: "Инициализация экспорта...", progress: 0 });

    try {
      await generatePdf({
        res: s.result,
        originalImageUrl: s.originalImageUrl,
        paperSize,
        dpi,
        tileMode,
        includeRecipes,
        activeComps,
        exportPaintType,
        exportSurfaceType,
        isArtistic: s.presetKey === "artistic",
        contourWeight: s.presetKey === "artistic" ? s.artisticContourWeight : s.pbnContourWeight,
        numberWeight: s.numberWeight,
        artisticPresetId: s.artisticPresetId,
        notanLevels: s.notanLevels,
        notanThreshold: s.notanThreshold,
        artIntensity: s.artIntensity,
        customArtPalette: s.customArtPalette,
        detailsPhotoOpacity: s.detailsPhotoOpacity,
        totalPartsLimit: gs.totalPartsLimit === "авто" || gs.totalPartsLimit === "" ? null : Number(gs.totalPartsLimit) || null,
        engineSettings: gs.engineSettings,
        updateProgress: (msg, pct) => s.update({ statusMsg: msg, progress: pct })
      });
      s.update({ statusMsg: "Готово!", progress: 100 });
    } catch (e: any) {
      s.update({ statusMsg: `Ошибка: ${e.message}` });
    } finally {
      setTimeout(() => s.update({ isExporting: false }), 2000);
    }
  };

  const doExport = useCallback((format: "svg" | "html") => {
    s.update({ isExporting: true, statusMsg: "Подготовка данных...", progress: 10 });
    
    setTimeout(async () => {
      try {
        if (!s.result) throw new Error("Нет результата для экспорта");
        s.update({ statusMsg: "Генерация контента...", progress: 40 });

        const isArtistic = s.presetKey === "artistic";
        const contourWeight = isArtistic ? s.artisticContourWeight : s.pbnContourWeight;

        if (format === "svg") {
          const svgStr = await generateSVGContent(
            s.result,
            contourWeight,
            s.numberWeight,
            true,
            s.activeColors,
            s.showNumbers,
            isArtistic,
            s.artisticStep,
            s.artisticPresetId,
            s.notanLevels,
            s.notanThreshold,
            s.artIntensity,
            s.customArtPalette
          );
          
          s.update({ statusMsg: "Сохранение файла...", progress: 80 });
          const blob = new Blob([svgStr], { type: "image/svg+xml" });
          const url = URL.createObjectURL(blob);
          const a = document.createElement("a");
          a.href = url;
          a.download = `color_mixer_${isArtistic ? 'art' : 'pbn'}_${Date.now()}.svg`;
          a.click();
          URL.revokeObjectURL(url);
          
        } else if (format === "html") {
          s.update({ statusMsg: "Обработка изображений...", progress: 30 });
          let origBase64 = "";
          if (s.originalImageUrl) {
            const resp = await fetch(s.originalImageUrl);
            const blob = await resp.blob();
            origBase64 = await new Promise<string>((resolve) => {
              const reader = new FileReader();
              reader.onloadend = () => resolve(reader.result as string);
              reader.readAsDataURL(blob);
            });
          }

          s.update({ statusMsg: "Сборка плеера...", progress: 70 });
          const htmlStr = await generateInteractiveHTML(
            s.result,
            contourWeight,
            isArtistic,
            origBase64,
            s.artisticPresetId,
            s.notanLevels,
            s.notanThreshold,
            s.artIntensity,
            s.customArtPalette
          );

          const blob = new Blob([htmlStr], { type: "text/html" });
          const url = URL.createObjectURL(blob);
          const a = document.createElement("a");
          a.href = url;
          a.download = `color_mixer_${isArtistic ? 'art' : 'pbn'}_${Date.now()}.html`;
          a.click();
          URL.revokeObjectURL(url);
        }

        s.update({ statusMsg: "Успешно сохранено!", progress: 100 });
        setTimeout(() => {
          s.update({ isExporting: false });
        }, 1500);
      } catch (e: any) {
        s.update({ statusMsg: `Ошибка: ${e.message}`, progress: 0 });
        setTimeout(() => s.update({ isExporting: false }), 3000);
      }
    }, 100);
  }, [s]);

  return {
    exportPaintType, setExportPaintType,
    exportSurfaceType, setExportSurfaceType,
    paperSize, setPaperSize,
    dpi, setDpi,
    tileMode, setTileMode,
    includeRecipes, setIncludeRecipes,
    close,
    handlePdfExport,
    doExport,
    isArtistic: s.presetKey === "artistic",
    gs, s
  };
}