// src/App.tsx
import { useState, useCallback, useMemo, useEffect } from 'react';
import GeneratorModal from './generator/GeneratorModal';
import { InstallButton } from './components/InstallButton';
import { BASE_COLORS, EXTENDED_COLORS, PAINT_PROFILES, formatParts } from './config';
import type { RGB } from './engine';
import { useAppStore } from './store/appStore';
import { useLabStore } from './store/labStore';
import { cn } from './utils/cn';
import { useIsMobile } from './hooks/useIsMobile';
import { rgbToHex } from './utils/colorMath';
import type { ColorInfo, HistoryEntry } from './types';

// Хуки
import { useToasts } from './hooks/useToasts';
import { useColorInput } from './hooks/useColorInput';
import { useCalculator } from './hooks/useCalculator';
import { useEscapeKey } from './hooks/useEscapeKey';

// Компоненты UI
import { ToastContainer } from './components/ui/ToastContainer';
import { SectionTitle, Divider } from './components/ui/SectionTitle';
import { ColorBlock } from './components/ColorBlock';
import { ColorCompare } from './components/ColorCompare';
import { RecipeRow } from './components/RecipeRow';
import { TotalPartsSlider } from './components/TotalPartsSlider';
import { PaintTypeSelector } from './components/PaintTypeSelector';
import { SurfaceSelector } from './components/SurfaceSelector';
import { MaxColorsSlider } from './components/MaxColorsSlider';
import { InputModeSwitch } from './components/InputModeSwitch';
import { VariantSelector } from './components/VariantSelector';
import { ResultSkeleton } from './components/ResultSkeleton';
import { WarningsBlock } from './components/ui/WarningsBlock';
import { MetricCard } from './components/ui/MetricCard';
import { StarsRating } from './components/ui/StarsRating';
import { ToolButton } from './components/ToolButton';

// Диалоги
import { PaletteDialog } from './components/dialogs/PaletteDialog';
import { ColorEditorDialog } from './components/dialogs/ColorEditorDialog';
import { HistoryDialog } from './components/dialogs/HistoryDialog';
import { RecipeDetailDialog } from './components/dialogs/RecipeDetailDialog';
import { BatchDialog } from './components/dialogs/BatchDialog';
import { CalibrationDialog } from './components/dialogs/CalibrationDialog';
import { LabDialog } from './components/dialogs/LabDialog';

export function App() {
  const isMobile = useIsMobile();
  const { toasts, addToast, removeToast } = useToasts();
  const store = useAppStore();
  const { isDark, engineSettings, customColors, deletedBuiltIns, overrides, selectedNames } = store;

  const [currentScreen, setCurrentScreen] = useState<'generator' | 'calculator' | 'lab'>('generator');

  // Модальные окна
  const [showPalette, setShowPalette] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [editInfo, setEditInfo] = useState<{ color: any, isCustom: boolean } | null>(null);
  const [showHistory, setShowHistory] = useState(false);
  const [showRecipeDetail, setShowRecipeDetail] = useState<HistoryEntry | null>(null);
  const [showBatch, setShowBatch] = useState(false);
  const [showCalibration, setShowCalibration] = useState(false);

  useEscapeKey(() => {
    if (currentScreen === 'lab') {
      const labState = useLabStore.getState();
      const activeWell = labState.wells[labState.activeWellIndex];
      const hasWellColor = activeWell && activeWell.totalParts > 0;
      const hasChallengeColor = labState.currentChallenge && labState.challengeWell.totalParts > 0;
      
      if (hasWellColor || hasChallengeColor) {
        if (hasWellColor) labState.clearActiveWell();
        if (hasChallengeColor) labState.clearChallengeWell();
      } else {
        setCurrentScreen('generator');
      }
    }
  }, currentScreen === 'lab');

  useEffect(() => {
    const root = document.documentElement;
    if (isDark) root.classList.add('dark');
    else root.classList.remove('dark');
  }, [isDark]);

  const allColors = useMemo(() => {
    const ext = EXTENDED_COLORS.filter((c) => !deletedBuiltIns.includes(c.name));
    return [...ext, ...customColors];
  }, [customColors, deletedBuiltIns]);

  const colorInfos: ColorInfo[] = useMemo(() => {
    const builtInMap = new Map<string, any>();
    for (const c of EXTENDED_COLORS) builtInMap.set(c.name, c);
    return allColors.map(c => {
      const bi = builtInMap.get(c.name);
      const isCustom = !bi;
      return {
        color: { ...c, rgb: overrides[c.name] || c.rgb },
        isCustom,
        isOverridden: !isCustom && !!overrides[c.name],
        builtInKey: isCustom ? null : c.name,
      };
    });
  }, [allColors, overrides]);

  const calcColors = useCallback(() => {
    const selected = allColors.filter((c) => selectedNames.includes(c.name));
    if (selected.length === 0) return BASE_COLORS.slice(0, 12);
    return selected.map((c) => ({ ...c, rgb: overrides[c.name] || c.rgb }));
  }, [allColors, selectedNames, overrides]);

  const profile = PAINT_PROFILES[engineSettings.paintType];

  const {
    inputMode, setInputMode, hexInput, setHexInput,
    rgbInputMain, setRgbInputMain, previewRgb, errorMsg, setErrorMsg,
    handleSmartPaste, handleRgbChange, handleEye
  } = useColorInput(addToast);

  const {
    isCalc, progress, result, activeVariant, setActiveVariant, handleCalc
  } = useCalculator(previewRgb, calcColors, addToast, setErrorMsg, inputMode);

  const currentVar = result?.variants?.[activeVariant];
  const dApprox = currentVar?.approxRgb || result?.approxRgb || ([0, 0, 0] as RGB);
  const dDelta = currentVar?.deltaE ?? result?.deltaE ?? 0;
  const dTotal = currentVar?.totalDrops ?? result?.totalDrops ?? 0;
  const dRecipe = useMemo(() => [...(currentVar?.recipe || [])].sort((a, b) => b.parts - a.parts), [currentVar]);

  return (
    <div className="h-[100dvh] flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors duration-300 font-sans">
      <InstallButton />

      <header className="shrink-0 flex items-center justify-between px-4 sm:px-6 py-3 bg-white/70 dark:bg-slate-900/70 backdrop-blur-xl z-50 shadow-premium border-b border-slate-100 dark:border-slate-800">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg overflow-hidden flex items-center justify-center shadow-lg shrink-0">
            <img src="/Melura/favicon.png" alt="Logo" className="w-full h-full object-cover" />
          </div>
          <h1 className="text-lg font-extrabold text-slate-900 dark:text-white tracking-tight">Melura</h1>
        </div>

        <nav className="hidden sm:flex items-center gap-1">
          <TopTab active={currentScreen === 'generator'} onClick={() => setCurrentScreen('generator')} icon={<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 19l7-7 3 3-7 7-3-3z"/><path d="M18 13l-1.5-7.5L2 2l3.5 14.5L13 18l5-5z"/><path d="M2 2l7.586 7.586"/><circle cx="11" cy="11" r="2"/></svg>} label="Студия" />
          <TopTab active={currentScreen === 'lab'} onClick={() => setCurrentScreen('lab')} icon={<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 10v6M2 10l10-5 10 5-10 5z"/><path d="M6 12v5c3 3 9 3 12 0v-5"/></svg>} label="Академия" />
        </nav>

        <button onClick={store.toggleTheme} aria-label={isDark ? "Включить светлую тему" : "Включить тёмную тему"} className="w-9 h-9 rounded-xl flex items-center justify-center transition-colors text-slate-600 dark:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800">
          {isDark ? <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><circle cx="12" cy="12" r="5" /><path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"/></svg> : <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z" /></svg>}
        </button>
      </header>

      <main className="flex-1 flex flex-col relative min-w-0 overflow-hidden bg-transparent">
        {currentScreen === 'generator' && <GeneratorModal isOpen={true} onClose={() => {}} isDark={isDark} />}
        {currentScreen === 'lab' && <LabDialog />}
        {currentScreen === 'calculator' && (
          <div className="flex flex-col flex-1 overflow-hidden animate-fade-in-up">
            <div className="flex flex-1 overflow-hidden flex-col md:flex-row">
              <aside className="w-full md:w-[340px] shrink-0 md:overflow-y-auto glass-panel dark:glass-panel z-10 relative">
                <div className="p-4 sm:p-6 flex flex-col gap-4 sm:gap-6">
                  <section className="space-y-3">
                    <div className="flex items-center justify-between">
                      <SectionTitle>Ввод цвета</SectionTitle>
                      <div className="flex items-center gap-2">
                         {!isMobile && <button onClick={handleEye} aria-label="Пипетка" className="w-9 h-9 rounded-xl flex items-center justify-center bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-indigo-500 border border-transparent hover:border-indigo-500/30"><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="m2 22 1-1h3l9-9"/><path d="M3 21v-3l9-9"/><path d="m15 6 3 3l3-3-3-3z"/></svg></button>}
                         <InputModeSwitch mode={inputMode} onChange={setInputMode} />
                      </div>
                    </div>
                    <div className="relative">
                      <input type="text" value={inputMode === 'hex' ? hexInput : rgbInputMain} onChange={e => inputMode === 'hex' ? setHexInput(e.target.value) : handleRgbChange(e.target.value)} onPaste={handleSmartPaste} onKeyDown={e => { if (e.key === 'Enter' && !isCalc) handleCalc(); }} placeholder={inputMode === 'hex' ? "#0722A2" : "255, 128, 64"} className={cn("w-full pl-4 pr-14 py-3.5 rounded-2xl font-bold font-mono bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white focus:outline-none shadow-inner border border-transparent transition-all", errorMsg ? "border-red-400/50" : "focus:border-indigo-500/30 focus:ring-4 focus:ring-indigo-500/10")} />
                      {previewRgb && <div className="absolute right-3 top-1/2 -translate-y-1/2 w-9 h-9 rounded-xl border-2 border-white dark:border-slate-700 shadow-md" style={{ backgroundColor: `rgb(${previewRgb})` }} />}
                    </div>
                    <button onClick={handleCalc} disabled={isCalc} className="w-full py-4 rounded-2xl font-black text-xs uppercase tracking-widest text-white bg-indigo-600 hover:bg-indigo-700 shadow-lg shadow-indigo-600/20 active:scale-95 flex items-center justify-center gap-2">{isCalc ? `Расчёт... ${progress}%` : 'Рассчитать рецепт'}</button>
                  </section>
                  <Divider />
                  <PaintTypeSelector value={engineSettings.paintType} onChange={pt => store.updateEngineSettings({ paintType: pt })} />
                  {profile.usesSubstrate && <SurfaceSelector value={engineSettings.surfaceType} onChange={st => store.updateEngineSettings({ surfaceType: st })} />}
                  <Divider />
                  <section className="space-y-4">
                    <SectionTitle>Палитра</SectionTitle>
                    <TotalPartsSlider value={store.totalPartsLimit} onChange={store.setTotalPartsLimit} profile={profile} />
                    <MaxColorsSlider value={engineSettings.maxColorsInMix} onChange={v => store.updateEngineSettings({ maxColorsInMix: v })} recommended={profile.maxColorsInMix} />
                    <button onClick={() => setShowPalette(true)} className="w-full flex items-center gap-3 py-3 px-4 rounded-2xl text-xs font-bold bg-white dark:bg-slate-800 border-2 border-slate-50 dark:border-slate-700 hover:border-indigo-500/30 transition-all shadow-sm uppercase tracking-tighter">Ваши краски <span className="ml-auto px-2 py-0.5 bg-slate-100 dark:bg-slate-700 rounded-lg">{selectedNames.length}</span></button>
                  </section>
                  <Divider />
                  <section className="space-y-2">
                    <SectionTitle>Инструменты</SectionTitle>
                    <ToolButton icon={<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M3 3v18h18"/><path d="m19 9-5 5-4-4-3 3"/></svg>} label="Пакетный расчёт" onClick={() => setShowBatch(true)} />
                    <ToolButton icon={<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/><path d="M12 7v5l4 2"/></svg>} label="История" onClick={() => setShowHistory(true)} badge={store.history.length} />
                  </section>
                </div>
              </aside>
              <main className="flex-1 overflow-y-auto relative p-4 sm:p-8">
                {isCalc && !result ? <ResultSkeleton /> : !result ? (
                  <div className="h-full flex flex-col items-center justify-center opacity-30 text-center"><svg className="w-16 h-16 mb-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1"><path d="m2 22 1-1h3l9-9"/><path d="M3 21v-3l9-9"/><path d="m15 6 3 3l3-3-3-3z"/></svg><p className="text-sm font-black uppercase tracking-widest">Введите цвет для начала</p></div>
                ) : (
                  <div className="w-full max-w-2xl mx-auto space-y-6 animate-fade-in-up">
                    <WarningsBlock warnings={result.warnings} />
                    <VariantSelector variants={result.variants} activeVariant={activeVariant} onSelect={setActiveVariant} isMobile={isMobile} profile={profile} />
                    <div className="grid grid-cols-2 gap-4">
                      <ColorBlock title="Цель" hex={result.targetHex} rgb={result.targetRgb} onCopy={m => addToast(m, 'success')} />
                      <ColorBlock title="Итог" hex={rgbToHex(dApprox)} rgb={dApprox} onCopy={m => addToast(m, 'success')} />
                    </div>
                    <ColorCompare targetRgb={result.targetRgb} approxRgb={dApprox} targetHex={result.targetHex} approxHex={rgbToHex(dApprox)} />
                    <div className="grid grid-cols-3 gap-3">
                      <MetricCard title="Части" value={dTotal.toString()} />
                      <MetricCard title="ΔE" value={dDelta.toFixed(1)} accent={dDelta < 2 ? 'text-emerald-500' : dDelta < 5 ? 'text-blue-500' : 'text-amber-500'} />
                      <StarsRating deltaE={dDelta} />
                    </div>
                    <div className="bg-white dark:bg-slate-900 rounded-[2rem] border-2 border-slate-50 dark:border-slate-800 overflow-hidden shadow-premium">
                      {dRecipe.map(item => <RecipeRow key={item.name} name={item.name} parts={item.parts} percent={item.percent} rgb={item.rgb} profile={profile} />)}
                    </div>
                  </div>
                )}
              </main>
            </div>
          </div>
        )}
      </main>

      <ToastContainer toasts={toasts} onRemove={removeToast} />

      {/* Диалоги */}
      {showPalette && (
        <PaletteDialog colorInfos={colorInfos} selectedNames={new Set(selectedNames)}
          onToggleColor={store.toggleColorSelection} onToggleAll={(s) => store.setAllColorsSelection(s ? allColors.map(c => c.name) : [])} onFullReset={store.resetPalette}
          onClose={() => setShowPalette(false)}
          onEdit={i => { setEditInfo({ color: i.color, isCustom: i.isCustom }); setShowEditor(true); }}
          onAdd={() => { setEditInfo(null); setShowEditor(true); }}
          onDelete={(ci) => store.deleteColor(ci.color.name, ci.isCustom)}
          onRestoreBuiltIn={store.restoreBuiltIn} />
      )}

      {showEditor && (
        <ColorEditorDialog existingColor={editInfo?.color || null}
          allColorNames={colorInfos.map(ci => ci.color.name)} originalName={editInfo?.color.name}
          onSave={(c) => { store.saveColor(c, !editInfo?.isCustom, editInfo?.color.name); setShowEditor(false); }}
          onClose={() => { setShowEditor(false); setEditInfo(null); }} />
      )}

      {showHistory && (
        <HistoryDialog entries={store.history} favorites={new Set(store.favorites)}
          onViewRecipe={e => setShowRecipeDetail(e)}
          onClear={() => { store.clearHistory(); addToast('История очищена', 'info'); }}
          onClose={() => setShowHistory(false)} profile={profile} />
      )}

      {showRecipeDetail && (
        <RecipeDetailDialog entry={showRecipeDetail}
          onClose={() => setShowRecipeDetail(null)}
          onCopy={m => addToast(m, 'success')}
          isFavorite={store.favorites.includes(`${showRecipeDetail.hex}|${showRecipeDetail.recipe.map(r => `${r.name}:${r.parts}`).join(',')}`)}
          onToggleFav={() => store.toggleFavorite(`${showRecipeDetail.hex}|${showRecipeDetail.recipe.map(r => `${r.name}:${r.parts}`).join(',')}`)}
          onRecalculate={(h) => { setHexInput(h); setInputMode('hex'); setShowRecipeDetail(null); setShowHistory(false); setCurrentScreen('calculator'); setTimeout(() => handleCalc(), 100); }}
          profile={profile} />
      )}

      {showBatch && (
        <BatchDialog onClose={() => setShowBatch(false)}
          calcColors={calcColors}
          engineSettings={{ ...engineSettings, targetTotalParts: store.totalPartsLimit === 'авто' ? null : Number(store.totalPartsLimit) || null }}
          addToast={addToast}
          onAddHistory={store.addHistory}
          onViewRecipe={e => setShowRecipeDetail(e)} />
      )}

      <div className="sm:hidden shrink-0 z-50 bg-white/80 dark:bg-slate-900/80 backdrop-blur-2xl border-t border-slate-100 dark:border-slate-800 pb-safe">
        <div className="flex justify-around items-center h-16">
          <BottomTab active={currentScreen === 'generator'} onClick={() => setCurrentScreen('generator')} icon={<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 19l7-7 3 3-7 7-3-3z"/><path d="M18 13l-1.5-7.5L2 2l3.5 14.5L13 18l5-5z"/><path d="M2 2l7.586 7.586"/><circle cx="11" cy="11" r="2"/></svg>} label="Студия" />
          <BottomTab active={currentScreen === 'lab'} onClick={() => setCurrentScreen('lab')} icon={<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M22 10v6M2 10l10-5 10 5-10 5z"/><path d="M6 12v5c3 3 9 3 12 0v-5"/></svg>} label="Академия" />
        </div>
      </div>
    </div>
  );
}

function TopTab({ active, onClick, icon, label }: { active: boolean; onClick: () => void; icon: React.ReactNode; label: string }) {
  return (
    <button onClick={onClick} className={cn("flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all", active ? "bg-indigo-600 text-white shadow-lg shadow-indigo-500/20" : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>
      <span className="shrink-0">{icon}</span>
      <span>{label}</span>
    </button>
  );
}

function BottomTab({ active, onClick, icon, label }: { active: boolean; onClick: () => void; icon: React.ReactNode; label: string }) {
  return (
    <button onClick={onClick} className={cn("flex flex-col items-center justify-center gap-1 flex-1 transition-all", active ? "text-indigo-600 dark:text-indigo-400 scale-110" : "text-slate-500 dark:text-slate-400")}>
      <span className="shrink-0">{icon}</span>
      <span className="text-[9px] font-black uppercase tracking-tighter">{label}</span>
    </button>
  );
}
