// src/generator/components/CorrectionOverlay.tsx
import { useCallback, useEffect, useRef } from "react";
import { useAppStore } from "../store";
import { SmoothSlider } from "./SmoothSlider";
import { cn } from "../../utils/cn";

export function CorrectionOverlay() {
  const isDark = useAppStore((s) => s.isDark);
  const isOpen = useAppStore((s) => s.mobileCorrectionOpen);
  const correction = useAppStore((s) => s.correction);
  const updateCorrection = useAppStore((s) => s.updateCorrection);
  const pushHistory = useAppStore((s) => s.pushCorrectionHistory);
  const update = useAppStore((s) => s.update);

  const panelRef = useRef<HTMLDivElement>(null);

  const close = useCallback(() => {
    update({ mobileCorrectionOpen: false });
  }, [update]);

  useEffect(() => {
    const el = panelRef.current;
    if (!el || !isOpen) return;

    const stop = (e: TouchEvent) => e.stopPropagation();

    el.addEventListener("touchstart", stop, { passive: false });
    el.addEventListener("touchmove", stop, { passive: false });
    el.addEventListener("touchend", stop, { passive: false });
    el.addEventListener("touchcancel", stop, { passive: false });

    return () => {
      el.removeEventListener("touchstart", stop);
      el.removeEventListener("touchmove", stop);
      el.removeEventListener("touchend", stop);
      el.removeEventListener("touchcancel", stop);
    };
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen) return;

    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape") close();
    };

    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, [isOpen, close]);

  if (!isOpen) return null;

  return (
    <div
      ref={panelRef}
      data-correction-panel
      className={cn(
        "lg:hidden absolute bottom-0 left-0 right-0 z-30 rounded-t-[2.5rem] shadow-premium border-t transition-all duration-300 animate-fade-in-up",
        isDark ? "bg-slate-900/90 backdrop-blur-2xl border-white/10" : "bg-white/90 backdrop-blur-2xl border-black/5"
      )}
      style={{ paddingBottom: "max(12px, env(safe-area-inset-bottom))" }}
      role="region"
      aria-label="Коррекция"
      onMouseDown={(e) => e.stopPropagation()}
      onClick={(e) => e.stopPropagation()}
      onTouchStart={(e) => e.stopPropagation()}
    >
      <div className="flex items-center justify-between px-6 pt-4 pb-2">
        <div className="flex items-center gap-2.5">
           <div className="w-1 h-1 rounded-full bg-indigo-500 shadow-lg shadow-indigo-500/50" />
           <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 dark:text-slate-400">
             Коррекция изображения
           </h2>
        </div>

        <button
          onClick={close}
          aria-label="Закрыть"
          className={cn(
            "w-9 h-9 rounded-2xl flex items-center justify-center transition-all active:scale-90 shadow-sm",
            isDark ? "bg-slate-800 text-slate-400 hover:text-white" : "bg-slate-100 text-slate-500 hover:bg-slate-200"
          )}
        >
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <path d="M18 6L6 18M6 6l12 12" />
          </svg>
        </button>
      </div>

      <div className="px-6 pb-3 grid grid-cols-2 gap-x-6">
        <SmoothSlider label="Яркость" storeValue={correction.brightness} defaultValue={0} min={-100} max={100} onCommit={(v) => updateCorrection({ brightness: v })} onDragEnd={pushHistory} isDark={isDark} showSign compact />
        <SmoothSlider label="Контраст" storeValue={correction.contrast} defaultValue={0} min={-100} max={100} onCommit={(v) => updateCorrection({ contrast: v })} onDragEnd={pushHistory} isDark={isDark} showSign compact />
        <SmoothSlider label="Насыщенность" storeValue={correction.saturation} defaultValue={0} min={-100} max={100} onCommit={(v) => updateCorrection({ saturation: v })} onDragEnd={pushHistory} isDark={isDark} showSign compact />
        <SmoothSlider label="Резкость" storeValue={correction.sharpness} defaultValue={0} min={0} max={100} onCommit={(v) => updateCorrection({ sharpness: v })} onDragEnd={pushHistory} isDark={isDark} compact />
      </div>
    </div>
  );
}