export function applyCorrection(
  src: ImageData,
  params: { brightness: number; contrast: number; saturation: number; sharpness: number },
): ImageData {
  const { brightness, contrast, saturation, sharpness } = params;
  const w = src.width;
  const h = src.height;
  const srcData = src.data;
  const out = new ImageData(w, h);
  const dst = out.data;

  const bFactor = brightness / 100;
  const cFactor = (contrast + 100) / 100;
  const cMul = cFactor * cFactor;

  const lut = new Uint8Array(256);
  for (let i = 0; i < 256; i++) {
    let v = i / 255;
    v += bFactor * 0.5;
    v = (v - 0.5) * cMul + 0.5;
    lut[i] = Math.max(0, Math.min(255, Math.round(v * 255)));
  }

  const satMul = 1 + saturation / 100;

  for (let i = 0; i < srcData.length; i += 4) {
    let r = lut[srcData[i]];
    let g = lut[srcData[i + 1]];
    let b = lut[srcData[i + 2]];

    if (saturation !== 0) {
      const gray = 0.299 * r + 0.587 * g + 0.114 * b;
      r = Math.max(0, Math.min(255, Math.round(gray + (r - gray) * satMul)));
      g = Math.max(0, Math.min(255, Math.round(gray + (g - gray) * satMul)));
      b = Math.max(0, Math.min(255, Math.round(gray + (b - gray) * satMul)));
    }

    dst[i] = r;
    dst[i + 1] = g;
    dst[i + 2] = b;
    dst[i + 3] = srcData[i + 3];
  }

  if (sharpness > 0) {
    const amount = (sharpness / 100) * 1.5;
    const tmp = new Uint8ClampedArray(dst);

    for (let y = 1; y < h - 1; y++) {
      for (let x = 1; x < w - 1; x++) {
        const idx = (y * w + x) * 4;
        for (let c = 0; c < 3; c++) {
          const sum =
            tmp[((y - 1) * w + (x - 1)) * 4 + c] +
            tmp[((y - 1) * w + x) * 4 + c] +
            tmp[((y - 1) * w + (x + 1)) * 4 + c] +
            tmp[(y * w + (x - 1)) * 4 + c] +
            tmp[(y * w + (x + 1)) * 4 + c] +
            tmp[((y + 1) * w + (x - 1)) * 4 + c] +
            tmp[((y + 1) * w + x) * 4 + c] +
            tmp[((y + 1) * w + (x + 1)) * 4 + c];

          const blur = sum / 8;
          const sharp = tmp[idx + c] + (tmp[idx + c] - blur) * amount;
          dst[idx + c] = Math.max(0, Math.min(255, Math.round(sharp)));
        }
      }
    }
  }

  return out;
}