// src/lab/brushEngine.ts
import { PAINT_PROFILES, type PaintType, type RGB } from '../config';
import type { LabSwatch, BrushType } from './types';

// ============================================================
// КОНСТАНТЫ И ПРОФИЛИ
// ============================================================

const TWO_PI = Math.PI * 2;
const WETNESS_DECAY_PER_MS: Record<PaintType, number> = {
  watercolor: 1 / 180_000,
  acrylic:    1 / 600_000,
  gouache:    1 / 350_000,
  oil:        1 / 90_000_000,
};

interface RealisticPaintProfile {
  viscosity: number; transparency: number; bloom: number; granulation: number;
  smudge: number; flow: number; edge: number; impasto: number;
}

const REALISTIC_PROFILES: Record<PaintType, RealisticPaintProfile> = {
  watercolor: { viscosity: 0.05, transparency: 0.80, bloom: 0.85, granulation: 0.45, smudge: 0.90, flow: 0.90, edge: 0.60, impasto: 0.00 },
  acrylic:    { viscosity: 0.55, transparency: 0.15, bloom: 0.05, granulation: 0.05, smudge: 0.35, flow: 0.30, edge: 0.10, impasto: 0.40 },
  gouache:    { viscosity: 0.60, transparency: 0.05, bloom: 0.00, granulation: 0.15, smudge: 0.25, flow: 0.25, edge: 0.05, impasto: 0.25 },
  oil:        { viscosity: 0.95, transparency: 0.08, bloom: 0.00, granulation: 0.00, smudge: 0.95, flow: 0.15, edge: 0.00, impasto: 0.85 },
};

// ============================================================
// КАРТА ФИЗИКИ (Влажность + Пигмент)
// ============================================================

class CanvasPhysics {
  public wetness: Float32Array;
  public pigment: Uint8ClampedArray;
  private w: number; private h: number;

  constructor(w: number, h: number) {
    this.w = w; this.h = h;
    this.wetness = new Float32Array(w * h);
    this.pigment = new Uint8ClampedArray(w * h * 3).fill(255);
  }

  resize(w: number, h: number) {
    const nw = Math.max(1, Math.round(w));
    const nh = Math.max(1, Math.round(h));
    if (nw === this.w && nh === this.h) return;
    this.w = nw; this.h = nh;
    this.wetness = new Float32Array(nw * nh);
    this.pigment = new Uint8ClampedArray(nw * nh * 3).fill(255);
  }

  addState(nx: number, ny: number, radius: number, wetAmount: number, color: RGB) {
    if (!Number.isFinite(nx) || !Number.isFinite(ny)) return;
    const cx = Math.round(nx * this.w), cy = Math.round(ny * this.h);
    const r = Math.max(1, Math.round(radius / 4));
    for (let dy = -r; dy <= r; dy++) {
      for (let dx = -r; dx <= r; dx++) {
        const px = cx + dx, py = cy + dy;
        if (px < 0 || py < 0 || px >= this.w || py >= this.h) continue;
        const d2 = dx * dx + dy * dy;
        if (d2 > r * r) continue;
        const idx = py * this.w + px;
        const falloff = 1 - Math.sqrt(d2) / r;
        this.wetness[idx] = Math.min(1, this.wetness[idx] + (wetAmount || 0) * falloff);
        const pIdx = idx * 3;
        this.pigment[pIdx] = color[0]; this.pigment[pIdx+1] = color[1]; this.pigment[pIdx+2] = color[2];
      }
    }
  }

  getPhysicsAt(nx: number, ny: number): { wet: number, rgb: RGB } {
    if (!Number.isFinite(nx) || !Number.isFinite(ny)) return { wet: 0, rgb: [255,255,255] };
    const px = Math.max(0, Math.min(this.w - 1, Math.round(nx * (this.w - 1))));
    const py = Math.max(0, Math.min(this.h - 1, Math.round(ny * (this.h - 1))));
    const idx = py * this.w + px;
    return { wet: this.wetness[idx] || 0, rgb: [this.pigment[idx*3], this.pigment[idx*3+1], this.pigment[idx*3+2]] };
  }

  tick(paintType: PaintType) {
    const decay = (WETNESS_DECAY_PER_MS[paintType] || 0.0001) * 16;
    for (let i = 0; i < this.wetness.length; i++) {
      if (this.wetness[i] > 0) this.wetness[i] = Math.max(0, this.wetness[i] - decay);
    }
  }
}

const physics = new CanvasPhysics(128, 128);
export function tickDrying() { physics.tick('watercolor'); }
export function resizeWetnessMap(w: number, h: number) { physics.resize(w/4, h/4); }

// ============================================================
// ЦВЕТОВЫЕ УТИЛИТЫ
// ============================================================

function mixOklab(c1: RGB, c2: RGB, w: number): RGB {
  const weight = Math.max(0, Math.min(1, Number.isFinite(w) ? w : 0.5));
  return [
    Math.round(Math.sqrt((1-weight)*(c1[0]**2) + weight*(c2[0]**2))),
    Math.round(Math.sqrt((1-weight)*(c1[1]**2) + weight*(c2[1]**2))),
    Math.round(Math.sqrt((1-weight)*(c1[2]**2) + weight*(c2[2]**2))),
  ] as RGB;
}

const noiseCanvas = document.createElement('canvas'); noiseCanvas.width = noiseCanvas.height = 128;
(function buildNoise(){ 
    const cx = noiseCanvas.getContext('2d')!; 
    for(let i=0; i<128*128; i++){ const v = Math.random()*255; cx.fillStyle=`rgba(${v},${v},${v},0.12)`; cx.fillRect(i%128, Math.floor(i/128), 1, 1); } 
})();

// ============================================================
// ДВИЖОК КИСТЕЙ
// ============================================================

const tipCache: Record<string, HTMLCanvasElement> = {};
const coloredTipCache: Record<string, HTMLCanvasElement> = {};
const strokeBuffer = document.createElement('canvas');
const sctx = strokeBuffer.getContext('2d', { alpha: true })!;

function getBrushTip(type: BrushType, size: number, pressure: number): HTMLCanvasElement {
  const pB = Number.isFinite(pressure) ? Math.round(pressure * 4) / 4 : 1;
  const sV = Math.max(1, Math.round(Number.isFinite(size) ? size : 20));
  const key = `${type}-${sV}-${pB}`; if (tipCache[key]) return tipCache[key];

  const ts = Math.max(1, Math.round(sV * 2.2));
  const cv = document.createElement('canvas'); cv.width = cv.height = ts;
  const cx = cv.getContext('2d', { alpha: true })!;
  const c = ts / 2; cx.fillStyle = 'black';
  
  if (type === 'round') {
    for(let i=0; i<150; i++) {
        const r = Math.pow(Math.random(), 1.4) * sV, a = Math.random() * TWO_PI;
        cx.globalAlpha = 0.15 + Math.random() * 0.35;
        cx.beginPath(); cx.arc(c + Math.cos(a)*r, c + Math.sin(a)*r, 0.5 + Math.random()*0.8, 0, TWO_PI); cx.fill();
    }
  } else if (type === 'flat' || type === 'bristle') {
    const w = sV * 1.8, h = sV * 0.5;
    for(let i=0; i<160; i++) { cx.globalAlpha = 0.1 + Math.random()*0.4; cx.fillRect(c + (Math.random()-0.5)*w, c + (Math.random()-0.5)*h - h/2, 1.1, h * (0.4 + Math.random()*0.7)); }
  } else {
    for(let i=0; i<200; i++) { cx.globalAlpha = 0.05 + Math.random()*0.15; cx.beginPath(); cx.arc(c + (Math.random()-0.5)*sV*2.2, c + (Math.random()-0.5)*sV*2.2, 1 + Math.random()*1.5, 0, TWO_PI); cx.fill(); }
  }
  tipCache[key] = cv; return cv;
}

function getColoredTip(type: BrushType, size: number, rgb: RGB, pres: number, wet: number): HTMLCanvasElement {
  const pBin = Number.isFinite(pres) ? Math.round(pres * 4) / 4 : 1;
  const wBin = Number.isFinite(wet) ? Math.round(wet * 4) / 4 : 0.5;
  const sVal = Math.max(1, Math.round(size));
  const key = `${type}-${sVal}-${rgb.join(',')}-${pBin}-${wBin}`;
  if (coloredTipCache[key]) return coloredTipCache[key];

  const tip = getBrushTip(type, sVal, pBin);
  const cv = document.createElement('canvas'); cv.width = Math.max(1, tip.width); cv.height = Math.max(1, tip.height);
  const cx = cv.getContext('2d')!;
  cx.fillStyle = `rgb(${rgb[0]},${rgb[1]},${rgb[2]})`; cx.fillRect(0, 0, cv.width, cv.height);
  cx.globalCompositeOperation = 'destination-in'; cx.drawImage(tip, 0, 0);
  if (wet < 0.4) { cx.globalAlpha = (0.4 - wet) * 0.7; cx.globalCompositeOperation = 'destination-out'; cx.drawImage(noiseCanvas, 0, 0, cv.width, cv.height); }
  coloredTipCache[key] = cv; return cv;
}

export function drawSwatch(ctx: CanvasRenderingContext2D, swatch: LabSwatch, canvasW: number, canvasH: number, absorption: number, showDry: boolean, surfaceId?: string) {
  const pts = swatch.points; if (!pts || pts.length === 0) return;
  const dpr = window.devicePixelRatio || 1; 
  const bw = Math.max(1, Math.round(canvasW * dpr)), bh = Math.max(1, Math.round(canvasH * dpr));
  if (strokeBuffer.width !== bw || strokeBuffer.height !== bh) { strokeBuffer.width = bw; strokeBuffer.height = bh; }
  
  const paintCfg = PAINT_PROFILES[swatch.paintType];
  const age = (Date.now() - (swatch.appliedAt || Date.now())) / 1000;
  const wetness = showDry ? 0 : Math.max(0, 1 - age / (paintCfg?.drying?.dryTimeSeconds || 12));

  sctx.setTransform(dpr, 0, 0, dpr, 0, 0); sctx.clearRect(0, 0, canvasW, canvasH);

  const drawS = (x: number, y: number, ang: number, sz: number, op: number, pr: number, mColor: RGB) => {
    const sSize = Math.max(1, Math.round(sz));
    if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(sSize)) return;
    const tip = getColoredTip(swatch.brushType, sSize / 2, mColor, pr, wetness);
    sctx.save(); sctx.globalAlpha = Math.max(0, Math.min(1, op)); sctx.translate(x, y); if (ang !== 0) sctx.rotate(ang);
    sctx.drawImage(tip, -sSize / 2, -sSize / 2, sSize, sSize); sctx.restore();
  };

  let fL = 0.001; for(let i=0; i<pts.length-1; i++) fL += Math.sqrt(Math.pow((pts[i+1].x-pts[i].x)*canvasW, 2) + Math.pow((pts[i+1].y-pts[i].y)*canvasH, 2));
  const step = Math.max(0.8, (swatch.size || 20) / 22); let cD = 0;

  for (let i = 0; i < pts.length - 1; i++) {
    const p1 = pts[i], p2 = pts[i+1];
    const dx = (p2.x - p1.x) * canvasW, dy = (p2.y - p1.y) * canvasH, sL = Math.sqrt(dx*dx + dy*dy);
    if (!Number.isFinite(sL) || sL < 0.1) continue;
    const ang = (swatch.brushType === 'flat' || swatch.brushType === 'bristle') ? Math.atan2(dy, dx) : swatch.rotation;
    const nS = Math.max(1, Math.ceil(sL / step));
    for (let s = 0; s <= nS; s++) {
      const t = s / nS; const x = p1.x*canvasW + dx*t, y = p1.y*canvasH + dy*t;
      const pr = (p1.pressure ?? 1)*(1-t) + (p2.pressure ?? 1)*t;
      const local = physics.getPhysicsAt(x / canvasW, y / canvasH);
      const mColor = mixOklab(swatch.wetColor, local.rgb, local.wet * REALISTIC_PROFILES[swatch.paintType].smudge * (1 - pr*0.5));
      const finalColor = mixOklab(mColor, swatch.dryColor, 1 - Math.round(wetness*5)/5);
      const expansion = (swatch.paintType === 'watercolor') ? (local.wet * 10) : 0;
      const op = (swatch.paintType === 'watercolor' ? 0.35 : 0.94) * pr * Math.max(0.05, 1 - (cD + sL*t)/(fL * 1.5));
      drawS(x, y, ang, (swatch.size || 20) * (0.85 + pr*0.15) + expansion, op, pr, finalColor);
    }
    cD += sL;
  }

  if (pts.length > 0 && wetness > 0.1) physics.addState(pts[pts.length-1].x, pts[pts.length-1].y, swatch.size || 20, wetness * 0.8, swatch.wetColor);

  ctx.save();
  if (swatch.paintType === 'watercolor') ctx.globalCompositeOperation = 'multiply';
  ctx.drawImage(strokeBuffer, 0, 0, bw, bh, 0, 0, canvasW, canvasH);
  ctx.restore();
}

export function drawSurfaceTexture(ctx: CanvasRenderingContext2D, id: string, w: number, h: number) {}
export function clearBrushCaches() { for (const k in coloredTipCache) delete coloredTipCache[k]; for (const k in tipCache) delete tipCache[k]; }
export function clearWetnessMap() { physics.wetness.fill(0); physics.pigment.fill(255); }
