import { PAINT_PROFILES, type PaintType } from '../config';
import { cn } from '../utils/cn';
import { SectionTitle } from './ui/SectionTitle';

export function PaintTypeSelector({ value, onChange }: { value: PaintType; onChange: (v: PaintType) => void }) {
  const types: PaintType[] = ['gouache', 'acrylic', 'watercolor', 'oil'];

  return (
    <div className="space-y-4">
      <SectionTitle>Материал красок</SectionTitle>
      <div className="grid grid-cols-2 gap-2.5 sm:grid-cols-4 px-0.5">
        {types.map(t => {
          const p = PAINT_PROFILES[t];
          const active = value === t;
          return (
            <button key={t} onClick={() => onChange(t)}
              className={cn(
                "relative flex flex-col items-center gap-2 p-3.5 rounded-[1.75rem] border-2 transition-all duration-300 active:scale-95 group overflow-hidden shadow-sm",
                active
                  ? "border-indigo-600 bg-white dark:bg-slate-900 shadow-indigo-500/10 z-10"
                  : "border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-950 hover:border-slate-200 dark:hover:border-slate-700"
              )}>
              
              {active && (
                <div className="absolute top-0 right-0 w-12 h-12 bg-indigo-500/5 dark:bg-indigo-500/10 rounded-full blur-xl pointer-events-none transform translate-x-1/2 -translate-y-1/2" />
              )}

              <span className={cn(
                "text-2xl flex items-center justify-center transition-all duration-500",
                active 
                  ? "scale-110 text-indigo-600 dark:text-indigo-400 drop-shadow-[0_0_8px_rgba(99,102,241,0.4)]" 
                  : "text-slate-500 dark:text-slate-400 group-hover:text-slate-600 dark:group-hover:text-slate-300"
              )}>{p.icon}</span>
              
              <span className={cn(
                "text-[10px] font-black uppercase tracking-widest transition-colors",
                active ? "text-slate-900 dark:text-white" : "text-slate-500 dark:text-slate-400"
              )}>
                {p.name}
              </span>
            </button>
          );
        })}
      </div>
      
      <div className="bg-indigo-50/50 dark:bg-indigo-900/10 p-3.5 rounded-2xl border border-indigo-100 dark:border-indigo-900/30 flex items-start gap-3 shadow-sm animate-fade-in" key={value}>
         <div className="w-5 h-5 rounded-lg bg-indigo-100 dark:bg-indigo-500/20 text-indigo-600 flex items-center justify-center shrink-0 mt-0.5">
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4"/><path d="M12 8h.01"/></svg>
         </div>
         <p className="text-[10px] text-indigo-800/80 dark:text-indigo-300/70 font-bold leading-relaxed uppercase tracking-tighter">
           {PAINT_PROFILES[value].description}
         </p>
      </div>
    </div>
  );
}