// src/hooks/useSplitCompare.ts
import { useCallback, useRef, useEffect, useState } from 'react';

export function useSplitCompare(initialPct = 50) {
  const containerRef = useRef<HTMLDivElement>(null);
  const approxLayerRef = useRef<HTMLDivElement>(null);
  const handleLineRef = useRef<HTMLDivElement>(null);
  const handleDotRef = useRef<HTMLDivElement>(null);

  // Состояние для aria-valuenow (обновляется реже, чем ref, чтобы не спамить рендер)
  const[ariaValue, setAriaValue] = useState(initialPct);
  const pctRef = useRef(initialPct);

  // Храним ссылки на активные обработчики для очистки при размонтировании
  const activeListeners = useRef<{
    mousemove?: (e: MouseEvent) => void;
    mouseup?: () => void;
    touchmove?: (e: TouchEvent) => void;
    touchend?: () => void;
  }>({});

  // Выносим обновление DOM в отдельную функцию, принимающую проценты напрямую
  const updateDOM = useCallback((pct: number) => {
    pctRef.current = pct;
    if (!approxLayerRef.current || !handleLineRef.current || !handleDotRef.current) return;

    // Прямая мутация DOM (без setState) для 60 FPS
    approxLayerRef.current.style.clipPath = `polygon(${pct}% 0, 100% 0, 100% 100%, ${pct}% 100%)`;
    handleLineRef.current.style.left = `${pct}%`;
    handleDotRef.current.style.left = `${pct}%`;
  },[]);

  const updatePosFromClientX = useCallback((clientX: number) => {
    const el = containerRef.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const pct = Math.max(5, Math.min(95, ((clientX - rect.left) / rect.width) * 100));
    updateDOM(pct);
  }, [updateDOM]);

  // --- ОБРАБОТЧИКИ МЫШИ И ТАЧА ---
  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    if (containerRef.current) containerRef.current.style.cursor = 'cursor-grabbing';

    updatePosFromClientX(e.clientX);

    const move = (me: MouseEvent) => updatePosFromClientX(me.clientX);
    const up = () => {
      if (containerRef.current) containerRef.current.style.cursor = 'cursor-grab';
      document.removeEventListener('mousemove', move);
      document.removeEventListener('mouseup', up);
      activeListeners.current.mousemove = undefined;
      activeListeners.current.mouseup = undefined;
      setAriaValue(Math.round(pctRef.current)); // Синхронизируем a11y после окончания перетаскивания
    };

    activeListeners.current.mousemove = move;
    activeListeners.current.mouseup = up;

    document.addEventListener('mousemove', move);
    document.addEventListener('mouseup', up);
  },[updatePosFromClientX]);

  const handleTouchStart = useCallback((e: React.TouchEvent) => {
    const startX = e.touches[0].clientX;
    const startY = e.touches[0].clientY;
    let isSliding = false;
    let isScrolling = false;

    const move = (te: TouchEvent) => {
      if (isScrolling) return;
      const currentX = te.touches[0].clientX;
      const currentY = te.touches[0].clientY;
      const dx = Math.abs(currentX - startX);
      const dy = Math.abs(currentY - startY);

      if (!isSliding && !isScrolling) {
        if (dy > dx && dy > 8) { isScrolling = true; return; }
        if (dx > 8 || dx > dy) { isSliding = true; }
      }

      if (isSliding) {
        if (te.cancelable) te.preventDefault();
        updatePosFromClientX(currentX);
      }
    };

    const end = () => {
      document.removeEventListener('touchmove', move);
      document.removeEventListener('touchend', end);
      activeListeners.current.touchmove = undefined;
      activeListeners.current.touchend = undefined;
      setAriaValue(Math.round(pctRef.current));
    };

    activeListeners.current.touchmove = move;
    activeListeners.current.touchend = end;

    document.addEventListener('touchmove', move, { passive: false });
    document.addEventListener('touchend', end);
  }, [updatePosFromClientX]);

  // --- ОБРАБОТЧИК КЛАВИАТУРЫ (A11y) ---
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    let newPct = pctRef.current;
    const step = e.shiftKey ? 10 : 2; // Shift ускоряет шаг

    switch (e.key) {
      case 'ArrowLeft':
      case 'ArrowDown':
        newPct = Math.max(5, newPct - step);
        break;
      case 'ArrowRight':
      case 'ArrowUp':
        newPct = Math.min(95, newPct + step);
        break;
      case 'Home':
        newPct = 5;
        break;
      case 'End':
        newPct = 95;
        break;
      default:
        return;
    }

    e.preventDefault();
    updateDOM(newPct);
    setAriaValue(Math.round(newPct));
  }, [updateDOM]);

  // Восстанавливаем начальную позицию при рендере
  useEffect(() => {
    updateDOM(initialPct);
  }, [updateDOM, initialPct]);

  // Очистка событий при размонтировании (устранение утечки памяти)
  useEffect(() => {
    return () => {
      if (activeListeners.current.mousemove) document.removeEventListener('mousemove', activeListeners.current.mousemove);
      if (activeListeners.current.mouseup) document.removeEventListener('mouseup', activeListeners.current.mouseup);
      if (activeListeners.current.touchmove) document.removeEventListener('touchmove', activeListeners.current.touchmove);
      if (activeListeners.current.touchend) document.removeEventListener('touchend', activeListeners.current.touchend);
    };
  },[]);

  return {
    containerRef,
    approxLayerRef,
    handleLineRef,
    handleDotRef,
    ariaValue,
    handleMouseDown,
    handleTouchStart,
    handleKeyDown
  };
}