import { useRef, useState, useCallback, useEffect } from 'react';
import type { PaintProfile } from '../config';
import { cn } from '../utils/cn';

export function TotalPartsSlider({ value, onChange, profile }: {
  value: string | number; onChange: (v: string | number) => void; profile: PaintProfile;
}) {
  const isA = value === 'авто';
  const num = isA ? 0 : Number(value) || 0;
  
  const [localValue, setLocalValue] = useState(num);
  const isDragging = useRef(false);

  useEffect(() => {
    if (!isDragging.current) {
      setLocalValue(isA ? 0 : Number(value) || 0);
    }
  }, [value, isA]);

  const handleMove = useCallback((clientX: number, rect: DOMRect) => {
    const padding = 10;
    const percent = Math.max(0, Math.min(1, (clientX - rect.left - padding) / (rect.width - padding * 2)));
    const v = Math.round(percent * 100);
    setLocalValue(v);
    if (v === 0) onChange('авто'); else onChange(v);
  }, [onChange]);

  const onTouchStart = (e: React.TouchEvent) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const startX = e.touches[0].clientX;
    const startY = e.touches[0].clientY;
    let isSliding = false;
    let isScrolling = false;

    const move = (te: TouchEvent) => {
      if (isScrolling) return;
      const currentX = te.touches[0].clientX;
      const currentY = te.touches[0].clientY;
      const dx = Math.abs(currentX - startX);
      const dy = Math.abs(currentY - startY);

      if (!isSliding && !isScrolling) {
        if (dy > dx && dy > 8) { isScrolling = true; return; }
        if (dx > 8 || dx > dy) { isSliding = true; isDragging.current = true; }
      }

      if (isSliding) {
        if (te.cancelable) te.preventDefault();
        te.stopPropagation();
        handleMove(currentX, rect);
      }
    };

    const end = () => {
      if (isSliding) {
        isDragging.current = false;
      }
      document.removeEventListener("touchmove", move);
      document.removeEventListener("touchend", end);
    };

    document.addEventListener("touchmove", move, { passive: false });
    document.addEventListener("touchend", end);
  };

  const onMouseDown = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    isDragging.current = true;
    handleMove(e.clientX, rect);
    const move = (me: MouseEvent) => handleMove(me.clientX, rect);
    const up = () => {
      isDragging.current = false;
      document.removeEventListener("mousemove", move);
      document.removeEventListener("mouseup", up);
    };
    document.addEventListener("mousemove", move);
    document.addEventListener("mouseup", up);
  };

  return (
    <div className="space-y-1 mb-3">
      <div className="flex justify-between items-center mb-1 px-1">
        <span className="text-sm font-bold text-slate-800 dark:text-white">
          Всего {profile.unitNameGenitive}
        </span>
        <span className={cn("text-xs font-black px-2 py-0.5 rounded-md bg-slate-100 dark:bg-white/10 text-right tabular-nums shadow-inner", isA ? "text-indigo-600 dark:text-indigo-400" : "text-slate-800 dark:text-white")}>
          {isA ? 'АВТО' : localValue}
        </span>
      </div>
      
      <div 
        className="relative h-8 flex items-center cursor-pointer touch-pan-y select-none px-[10px]"
        onTouchStart={onTouchStart}
        onMouseDown={onMouseDown}
      >
        <div className="w-full h-2 bg-slate-200 dark:bg-white/20 rounded-full shadow-inner overflow-hidden">
          <div 
            className="h-full bg-indigo-500 rounded-full transition-all duration-75" 
            style={{ width: `${localValue}%` }}
          />
        </div>
        <div 
          className={cn(
            "absolute top-1/2 -translate-y-1/2 w-5 h-5 bg-white dark:bg-slate-200 rounded-full border-2 border-white dark:border-slate-700 shadow-premium transition-all duration-75",
            isDragging.current && "scale-110"
          )}
          style={{ left: `calc(${localValue}% - ${(localValue * 20) / 100}px)` }}
        />
      </div>

      <div className="flex justify-between text-[10px] font-extrabold text-slate-500 dark:text-slate-400 uppercase tracking-widest px-2">
        <span>Авто</span>
        <span>100</span>
      </div>
    </div>
  );
}
