// src/generator/hooks/usePanZoom.ts
import { useRef, useState, useCallback, useEffect } from "react";
import type { ProcessingResult } from "../utils/imageProcessing";
import type { ViewTransformState } from "../store";

interface UsePanZoomProps {
  result: ProcessingResult | null;
  imageDimensions: { w: number; h: number } | null;
  isArtistic: boolean;
  artisticSplitMode: boolean;
  viewTransform: ViewTransformState;
  setViewTransform: (patch: Partial<ViewTransformState>) => void;
  flipHorizontal: boolean;
  activeMode: string;
  originalImageUrl: string | null;
  correctedImageUrl: string | null;
  colorPickerActive: boolean;
  onColorPicked: (rgb: [number, number, number]) => void;
  schemeCanvasRef: React.RefObject<HTMLCanvasElement | null>;
  correction: { brightness: number; contrast: number; saturation: number };
  artisticStep: number;
  detailsPhotoOpacity: number;
}

export function usePanZoom({
  result,
  imageDimensions,
  isArtistic,
  artisticSplitMode,
  viewTransform,
  setViewTransform,
  flipHorizontal,
  activeMode,
  originalImageUrl,
  correctedImageUrl,
  colorPickerActive,
  onColorPicked,
  schemeCanvasRef,
  correction,
  artisticStep,
  detailsPhotoOpacity,
}: UsePanZoomProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const transformLayerRef = useRef<HTMLDivElement>(null);
  const zoomTextRef = useRef<HTMLDivElement>(null);
  const splitHandleRef = useRef<HTMLDivElement>(null);
  const splitClip1Ref = useRef<HTMLDivElement>(null);
  const splitClip2Ref = useRef<HTMLDivElement>(null);

  const transform = useRef({ x: 0, y: 0, z: 1 });
  const splitPosRef = useRef(0.5);
  const rafRef = useRef<number | null>(null);
  const [draggingCursor, setDraggingCursor] = useState(false);
  const modeSnapshotKeyRef = useRef<string>("");

  const flushViewSnapshotToStore = useCallback(() => {
    setViewTransform({
      x: transform.current.x,
      y: transform.current.y,
      z: transform.current.z,
      splitPos: splitPosRef.current,
    });
  }, [setViewTransform]);

  const applyTransform = useCallback(() => {
    if (rafRef.current !== null) return;
    rafRef.current = requestAnimationFrame(() => {
      rafRef.current = null;
      const { x, y, z } = transform.current;
      if (transformLayerRef.current) {
        transformLayerRef.current.style.transform = `translate3d(${x}px, ${y}px, 0) scale(${z})`;
      }
      if (zoomTextRef.current) {
        zoomTextRef.current.textContent = `${Math.round(z * 100)}%`;
      }
      if (splitHandleRef.current && result) {
        const hx = splitPosRef.current * result.imgW * z + x;
        splitHandleRef.current.style.transform = `translate3d(${hx - 18}px, ${y}px, 0)`;
        splitHandleRef.current.style.height = `${result.imgH * z}px`;
      }
    });
  }, [result]);

  const applySplit = useCallback(() => {
    const sp = splitPosRef.current;
    if (splitClip1Ref.current) splitClip1Ref.current.style.clipPath = `inset(0 ${(1 - sp) * 100}% 0 0)`;
    if (splitClip2Ref.current) splitClip2Ref.current.style.clipPath = `inset(0 0 0 ${sp * 100}%)`;
    applyTransform();
  }, [applyTransform]);

  const hydrateLocalViewFromStore = useCallback(() => {
    transform.current = {
      x: Number.isFinite(viewTransform.x) ? viewTransform.x : 0,
      y: Number.isFinite(viewTransform.y) ? viewTransform.y : 0,
      z: Number.isFinite(viewTransform.z) ? viewTransform.z : 1,
    };
    splitPosRef.current = Number.isFinite(viewTransform.splitPos) ? viewTransform.splitPos : 0.5;
    applySplit();
  }, [viewTransform, applySplit]);

  useEffect(() => { hydrateLocalViewFromStore(); }, [hydrateLocalViewFromStore]);

  useEffect(() => {
    const newKey = `${activeMode}|${originalImageUrl || ""}|${correctedImageUrl || ""}`;
    if (modeSnapshotKeyRef.current && modeSnapshotKeyRef.current !== newKey) {
      flushViewSnapshotToStore();
    }
    modeSnapshotKeyRef.current = newKey;
    hydrateLocalViewFromStore();
  }, [activeMode, originalImageUrl, correctedImageUrl, flushViewSnapshotToStore, hydrateLocalViewFromStore]);

  useEffect(() => {
    return () => flushViewSnapshotToStore();
  }, [flushViewSnapshotToStore]);

  const resetView = useCallback((force = false) => {
    const el = containerRef.current;
    const src = result ?? (imageDimensions ? { imgW: imageDimensions.w, imgH: imageDimensions.h } : null);
    if (!el || !src) {
      transform.current = { x: 0, y: 0, z: 1 };
      splitPosRef.current = 0.5;
      applySplit();
      return;
    }
    const cw = el.clientWidth, ch = el.clientHeight;
    if (cw === 0 || ch === 0) return;

    if (!force) {
      const hasSavedTransform = Number.isFinite(viewTransform.z) && viewTransform.z > 0 && (Math.abs(viewTransform.z - 1) > 0.0001 || Math.abs(viewTransform.x) > 0.01 || Math.abs(viewTransform.y) > 0.01);
      if (hasSavedTransform) { hydrateLocalViewFromStore(); return; }
    }

    const fs = Math.min(cw / src.imgW, ch / src.imgH) * 0.92;
    transform.current = { z: fs, x: (cw - src.imgW * fs) / 2, y: (ch - src.imgH * fs) / 2 };
    splitPosRef.current = 0.5;
    applySplit();
  }, [result, imageDimensions, applySplit, viewTransform, hydrateLocalViewFromStore]);

  const prevDim = useRef({ w: 0, h: 0 });
  useEffect(() => {
    const w = result ? result.imgW : imageDimensions?.w || 0;
    const h = result ? result.imgH : imageDimensions?.h || 0;
    if (w !== prevDim.current.w || h !== prevDim.current.h) {
      prevDim.current = { w, h };
      const timer = setTimeout(() => resetView(true), 60);
      return () => clearTimeout(timer);
    }
  }, [result?.imgW, result?.imgH, imageDimensions?.w, imageDimensions?.h, resetView]);

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    let t: ReturnType<typeof setTimeout>;
    const obs = new ResizeObserver(() => {
      clearTimeout(t);
      t = setTimeout(() => { if (result || imageDimensions) resetView(false); }, 100);
    });
    obs.observe(el);
    return () => { clearTimeout(t); obs.disconnect(); };
  }, [resetView, result, imageDimensions]);

  const doZoom = useCallback((f: number) => {
    if (f === -1) {
      if (!document.fullscreenElement) containerRef.current?.requestFullscreen().catch(() => {});
      else document.exitFullscreen();
      return;
    }
    const cw = containerRef.current?.clientWidth ?? 400;
    const ch = containerRef.current?.clientHeight ?? 400;
    const cx = cw / 2, cy = ch / 2;
    const t = transform.current;
    transform.current = { x: cx - (cx - t.x) * f, y: cy - (cy - t.y) * f, z: Math.max(0.05, Math.min(30, t.z * f)) };
    applyTransform();
  }, [applyTransform]);

  const handleCanvasClick = useCallback(async (clientX: number, clientY: number) => {
    if (!containerRef.current) return;

    // Определяем источник изображения
    const imgUrl = correctedImageUrl || originalImageUrl;
    if (!imgUrl) return;

    const rect = containerRef.current.getBoundingClientRect();
    const { x, y, z } = transform.current;

    // Размеры отображаемого изображения
    let displayW: number, displayH: number;
    if (imageDimensions) {
      displayW = imageDimensions.w;
      displayH = imageDimensions.h;
    } else if (result) {
      displayW = result.imgW;
      displayH = result.imgH;
    } else {
      return;
    }

    // Координаты относительно изображения
    let imgX = (clientX - rect.left - x) / z;
    let imgY = (clientY - rect.top - y) / z;

    if (flipHorizontal) imgX = displayW - imgX;

    if (imgX < 0 || imgX >= displayW || imgY < 0 || imgY >= displayH) return;

    // Решаем, с какой стороны разделителя был клик
    const isSplitVisible = !isArtistic || artisticSplitMode;
    const isRightSide = isSplitVisible ? (imgX / displayW >= splitPosRef.current) : true;

    // Создаём canvas для считывания пикселя
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = imgUrl;

    try {
      await new Promise((resolve, reject) => {
        img.onload = resolve;
        img.onerror = reject;
      });

      const canvas = document.createElement("canvas");
      canvas.width = displayW;
      canvas.height = displayH;
      const ctx = canvas.getContext("2d");
      if (!ctx) return;

      // 1. Рисуем слой с фото (если он виден)
      const shouldDrawPhoto = !isRightSide || (isArtistic && (artisticStep === 0 || artisticStep === 3));
      
      if (shouldDrawPhoto) {
        // Применяем фильтры коррекции
        const { brightness, contrast, saturation } = correction;
        let f = "";
        if (brightness !== 0) f += `brightness(${100 + brightness}%) `;
        if (contrast !== 0) f += `contrast(${100 + Math.max(-50, contrast)}%) `;
        if (saturation !== 0) f += `saturate(${100 + saturation}%) `;
        
        if (f) ctx.filter = f.trim();

        // Если это художественный режим на правой стороне — учитываем прозрачность
        if (isRightSide && isArtistic && (artisticStep === 0 || artisticStep === 3)) {
          ctx.globalAlpha = detailsPhotoOpacity / 100;
        }

        ctx.drawImage(img, 0, 0, displayW, displayH);
        
        // Сбрасываем фильтры и альфу
        ctx.filter = "none";
        ctx.globalAlpha = 1.0;
      }

      // 2. Рисуем основной холст схемы (если клик справа)
      if (isRightSide && schemeCanvasRef.current) {
        ctx.drawImage(schemeCanvasRef.current, 0, 0, displayW, displayH);
      }

      const pixel = ctx.getImageData(Math.floor(imgX), Math.floor(imgY), 1, 1).data;
      const rgb: [number, number, number] = [pixel[0], pixel[1], pixel[2]];

      onColorPicked(rgb);
    } catch {
      // CORS или другая ошибка — просто игнорируем
    }
  }, [correctedImageUrl, originalImageUrl, imageDimensions, result, flipHorizontal, onColorPicked, isArtistic, artisticSplitMode, correction, artisticStep, detailsPhotoOpacity, schemeCanvasRef]);

  const dragState = useRef({ dragging: false, splitDragging: false, sx: 0, sy: 0 });
  const clickStartRef = useRef<{ x: number; y: number; time: number } | null>(null);

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;

    const onMouseDown = (e: MouseEvent) => {
      if ((e.target as HTMLElement).closest("[data-overlay-controls]")) return;
      if ((e.target as HTMLElement).closest("[data-correction-panel]")) return;
      if ((e.target as HTMLElement).closest("[data-zone-popup]")) return;
      if ((e.target as HTMLElement).closest("[data-sh]")) { dragState.current.splitDragging = true; e.preventDefault(); return; }

      dragState.current.dragging = true;
      dragState.current.sx = e.clientX - transform.current.x;
      dragState.current.sy = e.clientY - transform.current.y;
      clickStartRef.current = { x: e.clientX, y: e.clientY, time: Date.now() };
      setDraggingCursor(true);
    };

    const onMouseMove = (e: MouseEvent) => {
      if (dragState.current.dragging) {
        transform.current.x = e.clientX - dragState.current.sx;
        transform.current.y = e.clientY - dragState.current.sy;
        applyTransform();
      }
      if (dragState.current.splitDragging && result && containerRef.current) {
        const r2 = containerRef.current.getBoundingClientRect();
        const rawX = (e.clientX - r2.left - transform.current.x) / (transform.current.z * result.imgW);
        splitPosRef.current = Math.max(0, Math.min(1, rawX));
        applySplit();
      }
    };

    const onMouseUp = (e: MouseEvent) => {
      if ((e.target as HTMLElement).closest("[data-overlay-controls]")) {
        dragState.current.dragging = false;
        dragState.current.splitDragging = false;
        clickStartRef.current = null;
        return;
      }
      const wasDragging = dragState.current.dragging;
      const wasSplitDragging = dragState.current.splitDragging;
      dragState.current.dragging = false;
      dragState.current.splitDragging = false;
      setDraggingCursor(false);

      if (wasDragging || wasSplitDragging) flushViewSnapshotToStore();

      if (wasDragging && clickStartRef.current) {
        const dx = Math.abs(e.clientX - clickStartRef.current.x);
        const dy = Math.abs(e.clientY - clickStartRef.current.y);
        const dt = Date.now() - clickStartRef.current.time;
        if (dx < 5 && dy < 5 && dt < 300) handleCanvasClick(e.clientX, e.clientY);
      }
      clickStartRef.current = null;
    };

    const onWheel = (e: WheelEvent) => {
      e.preventDefault();
      const f = e.deltaY < 0 ? 1.15 : 0.87;
      const r = el.getBoundingClientRect();
      const mx = e.clientX - r.left, my = e.clientY - r.top;
      const t = transform.current;
      transform.current = { x: mx - (mx - t.x) * f, y: my - (my - t.y) * f, z: Math.max(0.05, Math.min(30, t.z * f)) };
      applyTransform();
    };

    let tid = 0, tis = 1, tipx = 0, tipy = 0, ticx = 0, ticy = 0;

    const onTouchStart = (e: TouchEvent) => {
      if ((e.target as HTMLElement).closest("[data-overlay-controls]")) return;
      if ((e.target as HTMLElement).closest("[data-correction-panel]")) return;
      if ((e.target as HTMLElement).closest("[data-zone-popup]")) return;
      if ((e.target as HTMLElement).closest("[data-sh]")) { dragState.current.splitDragging = true; e.preventDefault(); return; }

      if (e.touches.length === 1) {
        dragState.current.dragging = true;
        dragState.current.sx = e.touches[0].clientX - transform.current.x;
        dragState.current.sy = e.touches[0].clientY - transform.current.y;
        clickStartRef.current = { x: e.touches[0].clientX, y: e.touches[0].clientY, time: Date.now() };
      } else if (e.touches.length === 2) {
        e.preventDefault();
        dragState.current.dragging = false;
        tid = Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY);
        tis = transform.current.z;
        tipx = transform.current.x;
        tipy = transform.current.y;
        const r2 = el.getBoundingClientRect();
        ticx = (e.touches[0].clientX + e.touches[1].clientX) / 2 - r2.left;
        ticy = (e.touches[0].clientY + e.touches[1].clientY) / 2 - r2.top;
      }
    };

    const onTouchMove = (e: TouchEvent) => {
      if (dragState.current.splitDragging && e.touches.length === 1 && result && containerRef.current) {
        e.preventDefault();
        const r2 = containerRef.current.getBoundingClientRect();
        const rawX = (e.touches[0].clientX - r2.left - transform.current.x) / (transform.current.z * result.imgW);
        splitPosRef.current = Math.max(0, Math.min(1, rawX));
        applySplit();
        return;
      }

      if (e.touches.length === 1 && dragState.current.dragging) {
        e.preventDefault();
        transform.current.x = e.touches[0].clientX - dragState.current.sx;
        transform.current.y = e.touches[0].clientY - dragState.current.sy;
        applyTransform();
      } else if (e.touches.length === 2) {
        e.preventDefault();
        const d = Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY);
        const f = d / tid;
        const r2 = el.getBoundingClientRect();
        const cx = (e.touches[0].clientX + e.touches[1].clientX) / 2 - r2.left;
        const cy = (e.touches[0].clientY + e.touches[1].clientY) / 2 - r2.top;
        transform.current = { z: Math.max(0.05, Math.min(30, tis * f)), x: cx - (ticx - tipx) * f, y: cy - (ticy - tipy) * f };
        applyTransform();
      }
    };

    const onTouchEnd = (e: TouchEvent) => {
      if ((e.target as HTMLElement).closest("[data-overlay-controls]")) {
        dragState.current.dragging = false;
        dragState.current.splitDragging = false;
        clickStartRef.current = null;
        return;
      }
      const wasDragging = dragState.current.dragging;
      const wasSplitDragging = dragState.current.splitDragging;
      dragState.current.splitDragging = false;

      if (dragState.current.dragging && clickStartRef.current && e.changedTouches.length > 0) {
        const touch = e.changedTouches[0];
        const dx = Math.abs(touch.clientX - clickStartRef.current.x);
        const dy = Math.abs(touch.clientY - clickStartRef.current.y);
        const dt = Date.now() - clickStartRef.current.time;
        if (dx < 10 && dy < 10 && dt < 300) {
          if (e.cancelable) e.preventDefault();
          handleCanvasClick(touch.clientX, touch.clientY);
        }
      }
      clickStartRef.current = null;

      if (e.touches.length === 0) dragState.current.dragging = false;
      else if (e.touches.length === 1) {
        dragState.current.dragging = true;
        dragState.current.sx = e.touches[0].clientX - transform.current.x;
        dragState.current.sy = e.touches[0].clientY - transform.current.y;
      }

      if (wasDragging || wasSplitDragging) flushViewSnapshotToStore();
    };

    el.addEventListener("mousedown", onMouseDown);
    document.addEventListener("mousemove", onMouseMove);
    document.addEventListener("mouseup", onMouseUp);
    el.addEventListener("wheel", onWheel, { passive: false });
    el.addEventListener("touchstart", onTouchStart, { passive: false });
    el.addEventListener("touchmove", onTouchMove, { passive: false });
    el.addEventListener("touchend", onTouchEnd);

    return () => {
      el.removeEventListener("mousedown", onMouseDown);
      document.removeEventListener("mousemove", onMouseMove);
      document.removeEventListener("mouseup", onMouseUp);
      el.removeEventListener("wheel", onWheel);
      el.removeEventListener("touchstart", onTouchStart);
      el.removeEventListener("touchmove", onTouchMove);
      el.removeEventListener("touchend", onTouchEnd);
    };
  }, [result, applyTransform, applySplit, handleCanvasClick, flushViewSnapshotToStore]);

  useEffect(() => {
    return () => {
      if (rafRef.current !== null) cancelAnimationFrame(rafRef.current);
      flushViewSnapshotToStore();
    };
  }, [flushViewSnapshotToStore]);

  return {
    containerRef,
    transformLayerRef,
    zoomTextRef,
    splitHandleRef,
    splitClip1Ref,
    splitClip2Ref,
    draggingCursor,
    resetView,
    doZoom,
    flushViewSnapshotToStore,
    applySplit,
  };
}