export function getAllChallenges(): LabChallenge[] {
  return createAcademyChallenges();
}

export function getChallengesByLevel(level: ChallengeLevel): LabChallenge[] {
  return getAllChallenges().filter(c => c.level === level);
}

export function checkChallenge(challenge: LabChallenge, well: LabWell): ChallengeResult {
  if (!challenge.targetColor) return { passed: false, deltaE: 999, message: 'Нет целевого цвета', stars: 0 };
  if (well.totalParts === 0) return { passed: false, deltaE: 999, message: 'Лунка пуста — добавьте краски', stars: 0 };
  
  const targetLab = rgbToLab(challenge.targetColor);
  const resultLab = rgbToLab(well.wetColor);
  const dE = deltaE00(targetLab, resultLab);
  
  const passed = dE <= challenge.tolerance;
  const targetL = targetLab[0];
  const resultL = resultLab[0];
  const targetWarmth = targetLab[1] + targetLab[2];
  const resultWarmth = resultLab[1] + resultLab[2];
  
  const tooLight = resultL > targetL + 6;
  const tooDark = resultL < targetL - 6;
  const tooWarm = resultWarmth > targetWarmth + 8;
  const tooCool = resultWarmth < targetWarmth - 8;
  
  let stars = 0, message = "";
  
  if (dE < challenge.tolerance * 0.3) { 
    stars = 3; message = 'Идеальное попадание!'; 
  } else if (dE < challenge.tolerance * 0.7) { 
    stars = 2; message = 'Отлично! Очень близко.'; 
  } else if (passed) { 
    stars = 1; message = 'Хорошо! Цвет подходит.'; 
  } else {
    const hints = [];
    if (tooDark) hints.push("светлее");
    if (tooLight) hints.push("темнее");
    if (tooCool) hints.push("теплее (добавьте жёлтый/красный)");
    if (tooWarm) hints.push("холоднее (добавьте синий)");
    
    if (hints.length > 0) {
      message = `Почти! Сделайте цвет ${hints.join(' и ')}.`;
    } else {
      message = 'Направление верное, немного подкорректируйте пропорции.';
    }
  }
  
  return { passed, deltaE: dE, message, stars, tooLight, tooDark, tooWarm, tooCool };
}

export function checkPrediction(challenge: LabChallenge, selectedIndex: number): ChallengeResult {
  if (challenge.correctAnswerIndex === undefined) return { passed: false, deltaE: 999, message: 'Ошибка задания', stars: 0 };
  const passed = selectedIndex === challenge.correctAnswerIndex;
  return { passed, deltaE: 0, message: passed ? 'Правильно!' : 'Неверно. Попробуйте подумать ещё раз.', stars: passed ? 3 : 0 };
}

