export function SectionTitle({ children }: { children: React.ReactNode }) {
  return (
    <div className="flex items-center gap-3 py-1">
      <div className="w-1 h-1 rounded-full bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.6)]" />
      <h3 className="text-[10px] font-black uppercase tracking-[0.25em] text-slate-600 dark:text-slate-400 whitespace-nowrap leading-none">{children}</h3>
      <div className="h-px flex-1 bg-gradient-to-r from-slate-100 to-transparent dark:from-slate-800/50" />
    </div>
  );
}

export function Divider() {
  return <div className="h-px bg-slate-100 dark:bg-slate-800/50 my-2" />;
}
