// src/generator/components/HistoryModal.tsx
import { useState } from "react";
import { useAppStore } from "../store";
import { formatSmartDate } from "../../utils/formatting";
import { useBackButton } from "../../hooks/useBackButton";

export function HistoryModal() {
  const isDark = useAppStore((s) => s.isDark);
  const isOpen = useAppStore((s) => s.historyModalOpen);
  const generationHistory = useAppStore((s) => s.generationHistory) || [];
  const update = useAppStore((s) => s.update);
  const clearHistory = useAppStore((s) => s.clearHistory);
  const loadFromHistory = useAppStore((s) => s.loadFromHistory);

  const [isClearing, setIsClearing] = useState(false);

  const close = () => {
    update({ historyModalOpen: false });
    setIsClearing(false);
  };

  useBackButton(isOpen, close);

  const load = (id: number) => {
    loadFromHistory(id);
  };

  const handleClear = () => {
    clearHistory();
    setIsClearing(false);
  };

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-[110] flex items-center justify-center p-4 sm:p-6 pt-[max(1rem,env(safe-area-inset-top))]"
      role="dialog"
      aria-modal="true"
      aria-label="История проектов"
    >
      <div className="absolute inset-0 bg-black/50 backdrop-blur-sm transition-opacity" onClick={close} />

      <div
        className={`relative z-10 w-full max-w-md max-h-[82dvh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-fade-in-up ${
          isDark ? "bg-gray-900 border border-gray-800" : "bg-white"
        }`}
      >
        {/* Шапка */}
        <div className={`flex items-center justify-between px-4 py-3 border-b ${isDark ? "border-gray-800" : "border-gray-200"}`}>
          <div>
            <h2 className={`text-sm font-bold ${isDark ? "text-gray-200" : "text-gray-800"}`}>
              История генераций
            </h2>
            <p className="text-[10px] text-gray-500 font-medium">
              {generationHistory.length} элементов в архиве
            </p>
          </div>
          <div className="flex items-center gap-1">
            {generationHistory.length > 0 && (
              <button
                onClick={() => setIsClearing(true)}
                className="w-8 h-8 rounded-lg flex items-center justify-center text-red-500 hover:bg-red-500/10 transition-colors"
                title="Очистить"
              >
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M3 6h18M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2" />
                </svg>
              </button>
            )}
            <button
              onClick={close}
              className="w-8 h-8 rounded-lg flex items-center justify-center text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800"
            >
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M18 6L6 18M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>

        {/* Контент */}
        <div className="flex-1 overflow-y-auto p-3 space-y-2 custom-scrollbar">
          {generationHistory.length === 0 ? (
            <div className="py-20 text-center text-gray-500 flex flex-col items-center gap-3">
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round" className="opacity-20">
                <path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <p className="text-sm font-bold opacity-40 uppercase tracking-widest">История пуста</p>
            </div>
          ) : (
            generationHistory.map((entry) => (
              <button
                key={entry.id}
                onClick={() => load(entry.id)}
                className={`w-full p-3 rounded-xl border transition-all text-left flex items-center gap-3 group active:scale-[0.98] ${
                  isDark
                    ? "bg-gray-800/40 border-gray-700 hover:border-indigo-500/50 hover:bg-indigo-500/5"
                    : "bg-gray-50 border-gray-100 hover:border-indigo-500/30 hover:bg-white hover:shadow-sm"
                }`}
              >
                <div className="w-14 h-14 rounded-lg overflow-hidden bg-gray-200 dark:bg-gray-700 shrink-0 border border-gray-100 dark:border-gray-600 shadow-sm relative">
                  <img
                    src={entry.originalImageStr || entry.correctedImageUrl || entry.originalImageUrl}
                    className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500"
                    alt=""
                    onError={(e) => { (e.target as HTMLImageElement).src = 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='; }}
                  />
                  {entry.result?.validLabels && (
                    <div className="absolute bottom-1 right-1 px-1.5 py-0.5 rounded-md bg-indigo-600 text-[8px] font-black text-white shadow-lg uppercase tracking-tighter">
                      {entry.result.validLabels instanceof Set ? entry.result.validLabels.size : Object.keys(entry.result.validLabels).length}цв
                    </div>
                  )}
                </div>

                <div className="flex-1 min-w-0">
                  <div className="flex justify-between items-start mb-0.5">
                    <span className={`text-[10px] font-black uppercase tracking-widest ${isDark ? "text-gray-400" : "text-gray-500"}`}>
                      {formatSmartDate(entry.timestamp)}
                    </span>
                  </div>
                  <div className={`text-xs font-black truncate uppercase tracking-tight ${isDark ? "text-gray-200" : "text-gray-900"}`}>
                    {entry.presetKey === "artistic" ? "Живопись" : "По номерам"}
                  </div>
                  <div className="flex items-center gap-2 mt-1">
                    <div className="flex -space-x-1 opacity-60">
                       {entry.result?.colorPalette ? Object.values(entry.result.colorPalette).slice(0, 5).map((c: any, i: number) => (
                         <div key={i} className="w-2.5 h-2.5 rounded-full border border-white dark:border-gray-800" style={{ backgroundColor: `rgb(${c[0]},${c[1]},${c[2]})` }} />
                       )) : null}
                    </div>
                    <span className="text-[8px] font-bold text-gray-400 uppercase tracking-tighter">
                      {entry.result?.imgW || 0}×{entry.result?.imgH || 0}
                    </span>
                  </div>
                </div>

                <div className="w-6 h-6 rounded-full flex items-center justify-center bg-white dark:bg-gray-700 shadow-sm opacity-0 group-hover:opacity-100 transition-all -translate-x-2 group-hover:translate-x-0">
                   <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
                </div>
              </button>
            ))
          )}
        </div>

        {/* Подтверждение очистки */}
        {isClearing && (
          <div className="absolute inset-0 z-20 flex flex-col items-center justify-center p-6 bg-red-600 animate-fade-in text-white">
            <h3 className="text-lg font-black uppercase tracking-tight mb-2">Удалить всё?</h3>
            <p className="text-xs font-bold text-red-100 text-center mb-6 leading-relaxed">
              Вы уверены, что хотите полностью очистить историю генераций? Это действие нельзя отменить.
            </p>
            <div className="flex flex-col w-full gap-2">
              <button
                onClick={handleClear}
                className="w-full py-3 rounded-xl bg-white text-red-600 font-black text-xs uppercase tracking-widest shadow-xl active:scale-95 transition-all"
              >
                Да, удалить
              </button>
              <button
                onClick={() => setIsClearing(false)}
                className="w-full py-3 rounded-xl bg-red-700 text-white font-black text-xs uppercase tracking-widest active:scale-95 transition-all"
              >
                Отмена
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
