// src/generator/components/PalettePanel.tsx
import { memo, useMemo } from "react";
import { useAppStore } from "../store";

export const PalettePanel = memo(function PalettePanel() {
  const isDark = useAppStore((s) => s.isDark);
  const result = useAppStore((s) => s.result);
  const activeColors = useAppStore((s) => s.activeColors);
  const toggleColor = useAppStore((s) => s.toggleColor);
  const isolateColor = useAppStore((s) => s.isolateColor);
  const toggleAllColors = useAppStore((s) => s.toggleAllColors);
  const expanded = useAppStore((s) => s.mobilePaletteExpanded);
  const update = useAppStore((s) => s.update);
  const presetKey = useAppStore((s) => s.presetKey);

  const isArtistic = presetKey === "artistic";

  const sorted = useMemo(() => {
    if (!result) return [];
    return [...result.validLabels].sort((a, b) => a - b);
  }, [result]);

  if (!result) return null;

  const allOn = activeColors.size === sorted.length;
  const maxCollapsed = 12;
  const needsExpand = sorted.length > maxCollapsed;
  const visibleColors = expanded || !needsExpand ? sorted : sorted.slice(0, maxCollapsed);

  return (
    <div
      className={`flex-shrink-0 border-t px-3 py-2 ${
        isDark ? "bg-gray-900 border-gray-800" : "bg-white border-gray-200"
      }`}
      role="region"
      aria-label="Палитра цветов"
    >
      {/* Header */}
      <div className="flex items-center gap-2 mb-2">
        <span
          className={`text-[11px] font-bold uppercase tracking-wider ${
            isDark ? "text-gray-500" : "text-gray-400"
          }`}
        >
          {sorted.length} {plural(sorted.length)}
        </span>

        <div className="flex-1" />

        {activeColors.size > 0 && activeColors.size < sorted.length && (
          <span
            className={`text-[10px] px-1.5 py-0.5 rounded-full ${
              isDark ? "bg-indigo-900 text-indigo-300" : "bg-indigo-50 text-indigo-600"
            }`}
            aria-live="polite"
          >
            {activeColors.size} выбрано
          </span>
        )}

        <button
          data-palette-action
          onClick={toggleAllColors}
          aria-label={allOn ? "Скрыть все цвета" : "Показать все цвета"}
          className={`inline-flex items-center justify-center gap-1 px-2 py-1 rounded-md text-[11px] font-semibold transition-all leading-none ${
            allOn
              ? isDark
                ? "text-indigo-400 hover:text-indigo-300"
                : "text-indigo-600 hover:text-indigo-700"
              : isDark
                ? "text-gray-500 hover:text-gray-400"
                : "text-gray-400 hover:text-gray-500"
          }`}
        >
          {allOn ? "Снять все" : "Выбрать все"}
        </button>
      </div>

      {/* Color swatches */}
      <div className="flex flex-wrap gap-1.5" role="group" aria-label="Цвета палитры">
        {visibleColors.map((id) => {
          const c = result.colorPalette[id];
          if (!c) return null;

          const [r, g, b] = c;
          const lum = 0.299 * r + 0.587 * g + 0.114 * b;
          const on = activeColors.has(id);

          return (
            <button
              key={id}
              data-swatch
              onClick={() => toggleColor(id)}
              onDoubleClick={(e) => {
                e.preventDefault();
                isolateColor(id);
              }}
              title={`Цвет ${id + 1}: rgb(${r},${g},${b})`}
              aria-pressed={on}
              aria-label={`Цвет ${id + 1}`}
              className={`inline-flex items-center justify-center rounded-lg text-[10px] font-bold transition-all duration-100 leading-none ${
                on
                  ? `ring-2 ring-indigo-500 scale-110 shadow-lg z-10 ${
                      isDark ? "ring-offset-gray-900" : "ring-offset-white"
                    } ring-offset-1`
                  : "hover:scale-105 opacity-40 hover:opacity-70"
              }`}
              style={{
                width: 36,
                height: 36,
                backgroundColor: `rgb(${r},${g},${b})`,
                color: lum > 140 ? "#000" : "#fff",
                border: lum > 230 ? "1px solid #d1d5db" : "none",
              }}
            >
              {id + 1}
            </button>
          );
        })}

        {needsExpand && (
          <button
            data-swatch
            onClick={() => update({ mobilePaletteExpanded: !expanded })}
            aria-label={
              expanded
                ? "Свернуть палитру"
                : `Показать ещё ${sorted.length - maxCollapsed} цветов`
            }
            className={`inline-flex items-center justify-center w-9 h-9 rounded-lg text-xs font-bold transition-all leading-none ${
              isDark
                ? "bg-gray-800 text-gray-400 hover:bg-gray-700"
                : "bg-gray-100 text-gray-500 hover:bg-gray-200"
            }`}
          >
            {expanded ? "▲" : `+${sorted.length - maxCollapsed}`}
          </button>
        )}
      </div>

      {/* Информационная подсказка для понимания режима */}
      <div className="mt-2">
        <p
          className={`text-[10px] leading-relaxed ${
            isDark ? "text-gray-500" : "text-gray-400"
          }`}
        >
          {isArtistic
            ? "Выбор цветов сохраняется отдельно для режима живописи."
            : "Выбор цветов сохраняется отдельно для режима по номерам."}
        </p>
      </div>
    </div>
  );
});

function plural(n: number): string {
  const m10 = n % 10;
  const m100 = n % 100;
  if (m100 >= 11 && m100 <= 19) return "цветов";
  if (m10 === 1) return "цвет";
  if (m10 >= 2 && m10 <= 4) return "цвета";
  return "цветов";
}