// src/calibration.ts
import type { RGB } from './config';
import { srgbToLinear, linearToSrgb } from './utils/colorMath';

/* ═══════════════════════════════════════════
   TYPES
   ═══════════════════════════════════════════ */
export interface CalibrationEntry {
  name: string;
  originalRgb: RGB;
  calibratedRgb: RGB;
  samplePoint?: { x: number; y: number };
}

export interface CalibrationResult {
  timestamp: number;
  whiteBalance: { r: number; g: number; b: number };
  entries: CalibrationEntry[];
}

export interface CalibrationFileData {
  version: 1;
  appName: 'Melura';
  timestamp: number;
  entries: { name: string; rgb: RGB; }[];
}

export interface SampleResult {
  rawRgb: RGB;
  correctedRgb: RGB;
  stdDev: number;
  warning: string | null;
}

/* ═══════════════════════════════════════════
   IMAGE LOADING
   ═══════════════════════════════════════════ */
export function loadImageFromFile(file: File): Promise<HTMLImageElement> {
  return new Promise((resolve, reject) => {
    if (!file.type.startsWith('image/')) {
      reject(new Error('Файл не является изображением'));
      return;
    }
    const img = new Image();
    const url = URL.createObjectURL(file);
    img.onload = () => { URL.revokeObjectURL(url); resolve(img); };
    img.onerror = () => { URL.revokeObjectURL(url); reject(new Error('Не удалось загрузить изображение')); };
    img.src = url;
  });
}

export function imageToCanvas(
  img: HTMLImageElement,
  maxSize = 2000,
): { canvas: HTMLCanvasElement; ctx: CanvasRenderingContext2D } {
  let { width, height } = img;
  if (width > maxSize || height > maxSize) {
    const scale = maxSize / Math.max(width, height);
    width = Math.round(width * scale);
    height = Math.round(height * scale);
  }
  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) throw new Error('Canvas 2D context unavailable');
  ctx.drawImage(img, 0, 0, width, height);
  return { canvas, ctx };
}

/* ═══════════════════════════════════════════
   WHITE BALANCE
   ═══════════════════════════════════════════ */
export interface WhiteBalanceCorrection {
  r: number; g: number; b: number;
}

export function calculateWhiteBalance(
  ctx: CanvasRenderingContext2D,
  x: number,
  y: number,
  radius = 20,
): WhiteBalanceCorrection {
  const sample = sampleArea(ctx, x, y, radius);
  
  // ИДЕАЛЬНЫЙ БАЛАНС БЕЛОГО В ЛИНЕЙНОМ ПРОСТРАНСТВЕ
  // Переводим sRGB целевого белого (250 - бумага) в линейный свет (0..1)
  const targetWhiteLin = srgbToLinear(250); 

  return {
    r: Math.min(2.5, Math.max(0.4, targetWhiteLin / Math.max(0.001, srgbToLinear(sample.rawRgb[0])))),
    g: Math.min(2.5, Math.max(0.4, targetWhiteLin / Math.max(0.001, srgbToLinear(sample.rawRgb[1])))),
    b: Math.min(2.5, Math.max(0.4, targetWhiteLin / Math.max(0.001, srgbToLinear(sample.rawRgb[2])))),
  };
}

export function applyWhiteBalance(rgb: RGB, wb: WhiteBalanceCorrection): RGB {
  // 1. В линейное пространство
  const lr = srgbToLinear(rgb[0]);
  const lg = srgbToLinear(rgb[1]);
  const lb = srgbToLinear(rgb[2]);

  // 2. Умножаем и возвращаем в sRGB (с гаммой)
  return [
    Math.round(Math.max(0, Math.min(255, linearToSrgb(lr * wb.r) * 255))),
    Math.round(Math.max(0, Math.min(255, linearToSrgb(lg * wb.g) * 255))),
    Math.round(Math.max(0, Math.min(255, linearToSrgb(lb * wb.b) * 255))),
  ];
}

/* ═══════════════════════════════════════════
   COLOR SAMPLING
   ═══════════════════════════════════════════ */
export function sampleArea(
  ctx: CanvasRenderingContext2D,
  centerX: number,
  centerY: number,
  radius = 15,
): { rawRgb: RGB; stdDev: number } {
  const { width, height } = ctx.canvas;
  const cx = Math.max(radius, Math.min(width - radius, Math.round(centerX)));
  const cy = Math.max(radius, Math.min(height - radius, Math.round(centerY)));
  const x0 = cx - radius, y0 = cy - radius;
  const size = radius * 2 + 1;
  const imageData = ctx.getImageData(x0, y0, size, size);
  const data = imageData.data;

  const reds: number[] = [], greens: number[] = [], blues: number[] = [];
  const r2 = radius * radius;

  for (let dy = -radius; dy <= radius; dy++) {
    for (let dx = -radius; dx <= radius; dx++) {
      if (dx * dx + dy * dy > r2) continue;
      const px = (dy + radius) * size + (dx + radius);
      const i = px * 4;
      if (data[i + 3] < 128) continue;
      reds.push(data[i]); greens.push(data[i + 1]); blues.push(data[i + 2]);
    }
  }

  if (reds.length === 0) return { rawRgb: [0, 0, 0], stdDev: 0 };

  const median = (arr: number[]): number => {
    const sorted = [...arr].sort((a, b) => a - b);
    const mid = Math.floor(sorted.length / 2);
    return sorted.length % 2 ? sorted[mid] : Math.round((sorted[mid - 1] + sorted[mid]) / 2);
  };

  const medR = median(reds), medG = median(greens), medB = median(blues);

  const stdDevChannel = (arr: number[], med: number): number => {
    const sum = arr.reduce((s, v) => s + (v - med) * (v - med), 0);
    return Math.sqrt(sum / arr.length);
  };

  const stdDev = (stdDevChannel(reds, medR) + stdDevChannel(greens, medG) + stdDevChannel(blues, medB)) / 3;

  return { rawRgb: [medR, medG, medB], stdDev };
}

export function sampleColorFromPhoto(
  ctx: CanvasRenderingContext2D,
  x: number,
  y: number,
  whiteBalance: WhiteBalanceCorrection,
  radius = 15,
): SampleResult {
  const { rawRgb, stdDev } = sampleArea(ctx, x, y, radius);
  const correctedRgb = applyWhiteBalance(rawRgb, whiteBalance);

  let warning: string | null = null;
  if (stdDev > 30) {
    warning = 'Область неоднородна. Попробуйте ткнуть в центр мазка.';
  } else if (stdDev > 20) {
    warning = 'Область немного неоднородна. Результат может быть неточным.';
  }

  const brightness = (correctedRgb[0] + correctedRgb[1] + correctedRgb[2]) / 3;
  if (brightness < 10) {
    warning = 'Слишком тёмная область. Возможно, это тень.';
  } else if (brightness > 250) {
    warning = 'Слишком светлая область. Возможно, это блик или чистая бумага.';
  }

  return { rawRgb, correctedRgb, stdDev, warning };
}

/* ═══════════════════════════════════════════
   COORDINATE CONVERSION
   ═══════════════════════════════════════════ */
export function screenToCanvasCoords(
  clickX: number, clickY: number, displayRect: DOMRect, canvasWidth: number, canvasHeight: number,
): { x: number; y: number } {
  const scaleX = canvasWidth / displayRect.width;
  const scaleY = canvasHeight / displayRect.height;
  return {
    x: Math.round((clickX - displayRect.left) * scaleX),
    y: Math.round((clickY - displayRect.top) * scaleY),
  };
}

export function quickColorDifference(rgb1: RGB, rgb2: RGB): number {
  const dr = rgb1[0] - rgb2[0], dg = rgb1[1] - rgb2[1], db = rgb1[2] - rgb2[2];
  const rmean = (rgb1[0] + rgb2[0]) / 2;
  return Math.sqrt((2 + rmean / 256) * dr * dr + 4 * dg * dg + (2 + (255 - rmean) / 256) * db * db) / 3;
}

export function exportCalibration(entries: CalibrationEntry[]): CalibrationFileData {
  return {
    version: 1,
    appName: 'Melura',
    timestamp: Date.now(),
    entries: entries.map(e => ({ name: e.name, rgb: e.calibratedRgb })),
  };
}

export function calibrationToJson(data: CalibrationFileData): string {
  return JSON.stringify(data, null, 2);
}

export function parseCalibrationFile(json: string): CalibrationFileData | null {
  try {
    const data = JSON.parse(json);
    if (data?.appName !== 'Melura' || data?.version !== 1 || !Array.isArray(data?.entries)) return null;
    for (const entry of data.entries) {
      if (typeof entry.name !== 'string' || !entry.name.trim()) return null;
      if (!Array.isArray(entry.rgb) || entry.rgb.length !== 3) return null;
      if (entry.rgb.some((v: unknown) => typeof v !== 'number' || v < 0 || v > 255)) return null;
    }
    return {
      version: 1, appName: 'Melura', timestamp: data.timestamp || Date.now(),
      entries: data.entries.map((e: { name: string; rgb: RGB }) => ({
        name: e.name.trim(),
        rgb: [
          Math.round(Math.max(0, Math.min(255, e.rgb[0]))),
          Math.round(Math.max(0, Math.min(255, e.rgb[1]))),
          Math.round(Math.max(0, Math.min(255, e.rgb[2]))),
        ] as RGB,
      })),
    };
  } catch { return null; }
}

export function downloadCalibrationFile(data: CalibrationFileData): void {
  const blob = new Blob([calibrationToJson(data)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = `calibration_${new Date().toISOString().slice(0, 10)}.json`;
  document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
}

export function readFileAsText(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = () => reject(new Error('Не удалось прочитать файл'));
    reader.readAsText(file);
  });
}

export function getOptimalSampleRadius(canvasWidth: number, canvasHeight: number): number {
  return Math.max(8, Math.min(40, Math.round(Math.min(canvasWidth, canvasHeight) * 0.015)));
}

export function getDisplayRadius(sampleRadius: number, canvasWidth: number, displayWidth: number): number {
  return Math.max(10, Math.round(sampleRadius * (displayWidth / canvasWidth)));
}