import { useEffect } from 'react';

export function useFocusTrap(ref: React.RefObject<HTMLDivElement | null>, active: boolean) {
  useEffect(() => {
    if (!active || !ref.current) return;
    const el = ref.current;
    const getFocusable = () => el.querySelectorAll<HTMLElement>('button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])');
    const focusable = getFocusable();
    if (focusable.length === 0) return;
    const first = focusable[0], last = focusable[focusable.length - 1];
    const prev = document.activeElement as HTMLElement | null;
    first.focus();
    const handler = (e: KeyboardEvent) => {
      if (e.key !== 'Tab') return;
      const current = getFocusable();
      if (current.length === 0) return;
      const f = current[0], l = current[current.length - 1];
      if (e.shiftKey) { if (document.activeElement === f) { e.preventDefault(); l.focus(); } }
      else { if (document.activeElement === l) { e.preventDefault(); f.focus(); } }
    };
    el.addEventListener('keydown', handler);
    return () => { el.removeEventListener('keydown', handler); prev?.focus(); };
  }, [active, ref]);
}
