// src/components/ui/WarningsBlock.tsx
export function WarningsBlock({ warnings }: { warnings: string[] }) {
  if (warnings.length === 0) return null;
  
  return (
    <div className="space-y-2.5">
      {warnings.map((w, i) => (
        <div key={i} className="group relative flex items-start gap-3.5 px-4 py-3.5 rounded-[1.5rem] bg-amber-50/50 dark:bg-amber-900/10 border-2 border-amber-100 dark:border-amber-900/30 shadow-sm overflow-hidden animate-fade-in-up" style={{ animationDelay: `${i * 100}ms` }}>
          <div className="absolute top-0 right-0 w-24 h-24 bg-amber-500/5 blur-2xl pointer-events-none" />
          
          <div className="flex-shrink-0 w-8 h-8 rounded-xl bg-amber-500 text-white flex items-center justify-center shadow-lg shadow-amber-500/20 group-hover:scale-110 transition-transform">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
              <path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z" />
              <line x1="12" y1="9" x2="12" y2="13" />
              <line x1="12" y1="17" x2="12.01" y2="17" />
            </svg>
          </div>
          
          <div className="flex-1 space-y-1">
             <div className="text-[10px] font-black uppercase tracking-[0.2em] text-amber-700 dark:text-amber-400 leading-none">Внимание</div>
             <p className="text-[11px] font-bold text-amber-800 dark:text-amber-200/80 leading-relaxed uppercase tracking-tight">{w}</p>
          </div>
        </div>
      ))}
    </div>
  );
}