import {
  applyArtisticStrategy,
  multiLevelNotan,
  temperatureMapColor,
  blendWithIntensity,
  customPaletteStrategy,
} from "../../../utils/colorStrategies";
import type { ArtisticPresetId, RGB } from "../../../config";
import type { ProcessingResult } from "./types";
import { buildSmoothChains, drawSmoothChain } from "../worker/geometry";

function getArtisticPalette(
  originalPalette: Record<number, [number, number, number]>,
  step: number,
  artisticPresetId?: ArtisticPresetId,
  notanLevels: number = 2,
  notanThreshold: number = 128,
  artIntensity: number = 100,
  customArtPalette?: RGB[],
  showTemperatureMap: boolean = false,
): Record<number, [number, number, number]> {
  const newPal: Record<number, [number, number, number]> = {};

  for (const [key, rgb] of Object.entries(originalPalette)) {
    const id = Number(key);
    if (showTemperatureMap) {
      newPal[id] = temperatureMapColor(rgb);
      continue;
    }

    if (step === 1) {
      newPal[id] = multiLevelNotan(rgb, notanLevels, notanThreshold);
    } else if (step === 2) {
      if (artisticPresetId === "original") {
        newPal[id] = rgb;
      } else if (customArtPalette && customArtPalette.length >= 2) {
        const styled = customPaletteStrategy(rgb, customArtPalette);
        newPal[id] = artIntensity < 100 ? blendWithIntensity(rgb, styled, artIntensity) : styled;
      } else {
        const preset = artisticPresetId || "original";
        newPal[id] = preset === "original" ? rgb : applyArtisticStrategy(rgb, preset, artIntensity);
      }
    } else {
      newPal[id] = rgb;
    }
  }
  return newPal;
}

let sharedFillCanvas: HTMLCanvasElement | null = null;

export function renderSchemeCanvas(
  canvas: HTMLCanvasElement,
  res: ProcessingResult,
  contourWeight: number,
  numberWeight: number,
  activeColors: Set<number>,
  showNumbers: boolean,
  scale: number = 2,
  isArtisticMode: boolean = false,
  artisticStep: number = 0,
  artisticPresetId?: ArtisticPresetId,
  notanLevels: number = 2,
  notanThreshold: number = 128,
  artIntensity: number = 100,
  customArtPalette?: RGB[],
  showTemperatureMap: boolean = false,
  zoneGuideActive: boolean = false,
  currentZoneContourId: number = -1,
  detailsPhotoOpacity: number = 60,
  showContours: boolean = true,
): void {
  const { imgW, imgH, labelMask, boundaryEdges, colorPalette, contoursData } = res;

  canvas.width = imgW * scale;
  canvas.height = imgH * scale;

  const ctx = canvas.getContext("2d");
  if (!ctx) return;

  if (isArtisticMode && artisticStep === 3) {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
  } else if (isArtisticMode && artisticStep === 0) {
    const bgAlpha = 1 - detailsPhotoOpacity / 100;
    ctx.fillStyle = `rgba(255, 255, 255, ${bgAlpha})`;
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  } else {
    ctx.fillStyle = "#fff";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  }

  const shouldFill = isArtisticMode
    ? (artisticStep > 0 && artisticStep < 3) || showTemperatureMap
    : activeColors.size > 0 || (zoneGuideActive && currentZoneContourId >= 0);

  if (shouldFill) {
    if (!sharedFillCanvas) sharedFillCanvas = document.createElement("canvas");
    sharedFillCanvas.width = imgW;
    sharedFillCanvas.height = imgH;

    const fCtx = sharedFillCanvas.getContext("2d");
    if (fCtx) {
      const imgData = fCtx.createImageData(imgW, imgH);
      const d = imgData.data;

      const activePalette = isArtisticMode
        ? getArtisticPalette(
            colorPalette,
            artisticStep,
            artisticPresetId,
            notanLevels,
            notanThreshold,
            artIntensity,
            customArtPalette,
            showTemperatureMap,
          )
        : colorPalette;

      for (let i = 0; i < imgW * imgH; i++) {
        const label = labelMask[i];

        if (zoneGuideActive && currentZoneContourId >= 0) {
          if (label === currentZoneContourId) {
            const c = activePalette[label] || [255, 255, 255];
            d[i * 4] = c[0];
            d[i * 4 + 1] = c[1];
            d[i * 4 + 2] = c[2];
            d[i * 4 + 3] = 255;
          } else if (isArtisticMode || activeColors.has(label)) {
            const c = activePalette[label] || [255, 255, 255];
            d[i * 4] = Math.round(c[0] * 0.15 + 240 * 0.85);
            d[i * 4 + 1] = Math.round(c[1] * 0.15 + 240 * 0.85);
            d[i * 4 + 2] = Math.round(c[2] * 0.15 + 240 * 0.85);
            d[i * 4 + 3] = 255;
          } else {
            d[i * 4] = 255;
            d[i * 4 + 1] = 255;
            d[i * 4 + 2] = 255;
            d[i * 4 + 3] = 255;
          }
        } else {
          if (isArtisticMode || activeColors.has(label)) {
            const c = activePalette[label];
            if (c) {
              d[i * 4] = c[0];
              d[i * 4 + 1] = c[1];
              d[i * 4 + 2] = c[2];
              d[i * 4 + 3] = 255;
            }
          } else {
            d[i * 4] = 255;
            d[i * 4 + 1] = 255;
            d[i * 4 + 2] = 255;
            d[i * 4 + 3] = 255;
          }
        }
      }

      fCtx.putImageData(imgData, 0, 0);
      ctx.imageSmoothingEnabled = !isArtisticMode;
      ctx.drawImage(sharedFillCanvas, 0, 0, imgW * scale, imgH * scale);
    }
  }

  ctx.save();
  ctx.scale(scale, scale);

  const shouldDrawLines = (isArtisticMode ? artisticStep === 0 || artisticStep === 3 : true) && showContours;

  if (shouldDrawLines) {
    // Используем общую функцию трассировки с параметрами для экрана
    const chains = buildSmoothChains(boundaryEdges, 0.4, 2);

    ctx.lineCap = "round";
    ctx.lineJoin = "round";

    if (isArtisticMode && artisticStep === 3 && contourWeight > 0) {
      const weightFactor = contourWeight / 50; // 1.0 при 50%
      for (const chain of chains) {
        ctx.lineWidth = 2.5 * weightFactor;
        ctx.strokeStyle = "rgba(0,0,0,0.4)";
        drawSmoothChain(ctx, chain);

        ctx.lineWidth = 1.0 * weightFactor;
        ctx.strokeStyle = "rgba(255,255,255,0.8)";
        drawSmoothChain(ctx, chain);
      }
    } else {
      const lineAlpha = contourWeight === 0 ? 0 : (isArtisticMode ? 0.6 : 0.2 + (contourWeight / 100) * 0.8);
      const lineWidth = contourWeight === 0 ? 0 : (isArtisticMode ? 1.0 : 0.5 + (contourWeight / 100) * 1.5);

      ctx.strokeStyle = `rgba(40,40,40,${lineAlpha})`;
      ctx.lineWidth = lineWidth;

      if (zoneGuideActive && currentZoneContourId >= 0) {
        ctx.strokeStyle = `rgba(40,40,40,${lineAlpha * 0.3})`;
        ctx.lineWidth = lineWidth * 0.5;

        for (const chain of chains) {
          drawSmoothChain(ctx, chain);
        }

        const currentContour = contoursData.find((cd) => cd.labelId === currentZoneContourId);
        if (currentContour && currentContour.points.length >= 3) {
          ctx.strokeStyle = "rgba(99, 102, 241, 0.9)";
          ctx.lineWidth = 2.5;
          ctx.setLineDash([]);
          ctx.beginPath();
          ctx.moveTo(currentContour.points[0][0], currentContour.points[0][1]);
          for (let i = 1; i < currentContour.points.length; i++) {
            ctx.lineTo(currentContour.points[i][0], currentContour.points[i][1]);
          }
          ctx.closePath();
          ctx.stroke();
        }
      } else {
        for (const chain of chains) {
          drawSmoothChain(ctx, chain);
        }
      }
    }
  }

  if (showNumbers && !isArtisticMode) {
    const numAlpha = numberWeight === 0 ? 0 : 0.15 + (numberWeight / 100) * 0.85;
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";

    for (const cd of contoursData) {
      for (const lbl of cd.labelPositions) {
        if (lbl.maxDist < 2) continue;
        const fs = Math.max(7, Math.min(16, lbl.maxDist * 1.3));
        ctx.font = `bold ${fs}px sans-serif`;

        const isActive = activeColors.has(cd.labelId);
        const col = colorPalette[cd.labelId];

        if (isActive && col) {
          const lum = 0.299 * col[0] + 0.587 * col[1] + 0.114 * col[2];
          ctx.fillStyle = lum > 140 ? `rgba(0,0,0,${numAlpha})` : `rgba(255,255,255,${numAlpha})`;
        } else {
          ctx.fillStyle = `rgba(51,51,51,${numAlpha})`;
        }
        ctx.fillText(String(cd.labelId + 1), lbl.x, lbl.y);
      }
    }
  }

  if (zoneGuideActive && currentZoneContourId >= 0) {
    const currentContour = contoursData.find((cd) => cd.labelId === currentZoneContourId);
    if (currentContour && currentContour.labelPositions.length > 0) {
      const lbl = currentContour.labelPositions[0];
      const col = colorPalette[currentContour.labelId];

      if (col) {
        const lum = 0.299 * col[0] + 0.587 * col[1] + 0.114 * col[2];
        const fs = Math.max(14, Math.min(40, lbl.maxDist * 2));
        ctx.font = `bold ${fs}px sans-serif`;
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";

        ctx.strokeStyle = lum > 140 ? "rgba(0,0,0,0.6)" : "rgba(255,255,255,0.8)";
        ctx.lineWidth = 3;
        ctx.strokeText(String(currentContour.labelId + 1), lbl.x, lbl.y);

        ctx.fillStyle = lum > 140 ? "rgba(0,0,0,0.8)" : "rgba(255,255,255,0.95)";
        ctx.fillText(String(currentContour.labelId + 1), lbl.x, lbl.y);
      }
    }
  }

  ctx.restore();
}