// src/generator/components/ExportModal.tsx
import { PAINT_PROFILES, SURFACE_PROFILES, type PaintType, type SurfaceType } from "../../config";
import { SmoothSlider } from "./SmoothSlider";
import { TotalPartsSlider } from "../../components/TotalPartsSlider";
import { useExport, PAPER_SIZES } from "../hooks/useExport";
import { useBackButton } from "../../hooks/useBackButton";
import { cn } from "../../utils/cn";

export function ExportModal() {
  const {
    exportPaintType, setExportPaintType,
    exportSurfaceType, setExportSurfaceType,
    paperSize, setPaperSize,
    dpi, setDpi,
    tileMode, setTileMode,
    includeRecipes, setIncludeRecipes,
    close,
    handlePdfExport,
    doExport,
    isArtistic,
    gs, s
  } = useExport();

  const isDark = s.isDark;
  const isOpen = s.exportModalOpen;
  const isExporting = s.isExporting;
  const progress = s.progress;
  const statusMsg = s.statusMsg;

  useBackButton(isOpen, close);

  if (!isOpen) return null;

  const selCls = `w-full px-4 py-3 rounded-2xl text-xs font-black uppercase tracking-wider border-2 outline-none transition-all appearance-none cursor-pointer ${
    isDark ? "bg-slate-800 border-slate-700 text-slate-200 focus:border-indigo-500/50 focus:ring-4 focus:ring-indigo-500/10" : "bg-slate-50 border-slate-100 text-slate-700 focus:border-indigo-500/50 focus:ring-4 focus:ring-indigo-500/10"
  }`;

  return (
    <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 sm:p-6 pt-[max(1rem,env(safe-area-inset-top))]" role="dialog" aria-modal="true" aria-label="Экспорт проекта">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity" onClick={close} />
      
      <div className={`relative z-10 w-full sm:max-w-xl max-h-[85dvh] flex flex-col rounded-[2.5rem] shadow-premium animate-fade-in-up overflow-hidden touch-pan-y overscroll-contain ${
        isDark ? "bg-slate-900 border border-slate-800" : "bg-white"
      }`}>
        <div className={`flex-shrink-0 flex flex-col px-6 pt-5 pb-4 border-b ${isDark ? "border-slate-800" : "border-slate-100"}`}>
          <div className="flex items-center justify-between mb-1">
            <div className="flex items-center gap-2.5">
              <div className={`p-1.5 rounded-xl ${isDark ? "bg-slate-800 text-indigo-400" : "bg-indigo-50 text-indigo-600"}`}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4M7 10l5 5 5-5M12 15V3" />
                </svg>
              </div>
              <h2 className={`text-base sm:text-lg font-bold ${isDark ? "text-slate-100" : "text-slate-900"}`}>
                {isArtistic ? "Экспорт урока" : "Экспорт проекта"}
              </h2>
            </div>
            <button onClick={close} className={`w-10 h-10 -mr-2 rounded-full flex items-center justify-center transition-all ${
              isDark ? "bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white" : "bg-slate-100 text-slate-500 hover:bg-slate-200 hover:text-slate-800"
            }`} aria-label="Закрыть">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M18 6L6 18M6 6l12 12" />
              </svg>
            </button>
          </div>
          <div className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 dark:text-slate-400 ml-10">
             Подготовка файлов для печати
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
          <section className="space-y-4">
            <div className="flex items-center gap-2 mb-2">
               <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
               <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 dark:text-slate-400">Параметры документа</h3>
               <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className={`block text-[10px] font-black uppercase tracking-widest ml-1 ${isDark ? "text-slate-400" : "text-slate-500"}`}>Размер бумаги</label>
                <div className="relative">
                  <select value={paperSize} onChange={(e) => setPaperSize(e.target.value as any)} className={selCls}>
                    {Object.entries(PAPER_SIZES).map(([k, v]) => (
                      <option key={k} value={k}>{v.label}</option>
                    ))}
                  </select>
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-500">
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="m6 9 6 6 6-6" /></svg>
                  </div>
                </div>
              </div>
              <div className="space-y-2">
                <label className={`block text-[10px] font-black uppercase tracking-widest ml-1 ${isDark ? "text-slate-400" : "text-slate-500"}`}>Качество (DPI)</label>
                <div className="relative">
                  <select value={dpi} onChange={(e) => setDpi(+e.target.value)} className={selCls}>
                    <option value={150}>150 DPI (Быстро)</option>
                    <option value={300}>300 DPI (Стандарт)</option>
                    <option value={600}>600 DPI (Максимум)</option>
                  </select>
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-500">
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="m6 9 6 6 6-6" /></svg>
                  </div>
                </div>
              </div>
            </div>

            {!isArtistic && (
              <label className={`flex items-start gap-4 cursor-pointer p-4 rounded-3xl border-2 transition-all active:scale-[0.98] ${tileMode ? (isDark ? "bg-indigo-500/5 border-indigo-500/50" : "bg-indigo-50 border-indigo-200") : (isDark ? "bg-slate-800/50 border-slate-800" : "bg-slate-50 border-slate-100")}`}>
                <div className="relative mt-1">
                   <input type="checkbox" checked={tileMode} onChange={(e) => setTileMode(e.target.checked)} className="peer sr-only" />
                   <div className="w-6 h-6 rounded-lg border-2 border-slate-200 dark:border-slate-700 peer-checked:bg-indigo-600 peer-checked:border-indigo-600 transition-all flex items-center justify-center">
                      <svg className="w-4 h-4 text-white scale-0 peer-checked:scale-100 transition-transform" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><polyline points="20 6 9 17 4 12"/></svg>
                   </div>
                </div>
                <div className="min-w-0 flex-1">
                  <span className={`text-xs font-black uppercase tracking-tight block ${isDark ? "text-slate-200" : "text-slate-800"}`}>Печать постера</span>
                  <span className={`text-[10px] font-medium block mt-1 leading-relaxed ${isDark ? "text-slate-500" : "text-slate-500"}`}>Схема будет разделена на 4 листа {PAPER_SIZES[paperSize].label}.</span>
                </div>
              </label>
            )}
          </section>

          {!isArtistic && (
            <section className="space-y-4">
              <div className="flex items-center gap-2 mb-2">
                 <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
                 <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500">Внешний вид схемы</h3>
                 <div className="h-px flex-1 bg-slate-100 dark:bg-slate-800" />
              </div>
              <div className={`p-5 rounded-3xl border-2 ${isDark ? "bg-slate-800/30 border-slate-800" : "bg-white border-slate-50 shadow-sm"}`}>
                <SmoothSlider label="Толщина контуров" storeValue={s.pbnContourWeight} defaultValue={50} min={0} max={100} onCommit={(v) => s.update({ pbnContourWeight: v, contourWeight: v })} isDark={isDark} suffix="%" compact />
                <SmoothSlider label="Яркость номеров" storeValue={s.numberWeight} defaultValue={50} min={0} max={100} onCommit={(v) => s.update({ numberWeight: v })} isDark={isDark} suffix="%" compact />
              </div>
            </section>
          )}

          {!isArtistic && (
            <section>
              <label className={`flex items-start gap-4 cursor-pointer p-5 rounded-[2rem] border-2 transition-all active:scale-[0.99] ${includeRecipes ? (isDark ? "bg-indigo-500/10 border-indigo-500/50" : "bg-indigo-50 border-indigo-300 shadow-md") : (isDark ? "bg-slate-800/50 border-slate-800" : "bg-slate-50 border-slate-100")}`}>
                <div className="relative mt-1">
                   <input type="checkbox" checked={includeRecipes} onChange={(e) => setIncludeRecipes(e.target.checked)} className="peer sr-only" />
                   <div className="w-7 h-7 rounded-xl border-2 border-slate-200 dark:border-slate-700 peer-checked:bg-indigo-600 peer-checked:border-indigo-600 transition-all flex items-center justify-center shadow-sm">
                      <svg className="w-4 h-4 text-white scale-0 peer-checked:scale-100 transition-transform" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="5"><polyline points="20 6 9 17 4 12"/></svg>
                   </div>
                </div>
                <div className="flex-1 min-w-0">
                  <span className={`text-sm font-black uppercase tracking-tight block leading-tight ${isDark ? "text-slate-100" : "text-slate-900"}`}>Книга рецептов</span>
                  <span className={`text-[11px] font-medium block mt-1.5 leading-relaxed ${isDark ? "text-slate-400" : "text-slate-600"}`}>Добавить в файл точные пропорции смешивания красок.</span>
                  
                  {includeRecipes && (
                    <div className={`mt-5 pt-5 border-t-2 ${isDark ? "border-slate-800" : "border-indigo-100"}`} onClick={(e) => e.stopPropagation()}>
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
                        <div className="space-y-2">
                          <label className="block text-[10px] font-black uppercase tracking-widest text-indigo-500 ml-1">Тип краски</label>
                          <div className="relative">
                            <select value={exportPaintType} onChange={(e) => setExportPaintType(e.target.value as PaintType)} className={selCls}>
                              {Object.entries(PAINT_PROFILES).map(([k, v]) => (
                                <option key={k} value={k as PaintType}>{v.name}</option>
                              ))}
                            </select>
                            <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-500">
                               <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="m6 9 6 6 6-6"/></svg>
                            </div>
                          </div>
                        </div>
                        {PAINT_PROFILES[exportPaintType].usesSubstrate && (
                          <div className="space-y-2">
                            <label className="block text-[10px] font-black uppercase tracking-widest text-indigo-500 ml-1">Поверхность</label>
                            <div className="relative">
                              <select value={exportSurfaceType} onChange={(e) => setExportSurfaceType(e.target.value as SurfaceType)} className={selCls}>
                                {Object.entries(SURFACE_PROFILES).map(([k, v]) => (
                                  <option key={k} value={k as SurfaceType}>{v.name}</option>
                                ))}
                              </select>
                              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-500">
                                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="m6 9 6 6 6-6"/></svg>
                              </div>
                            </div>
                          </div>
                        )}
                      </div>
                      <div className="mb-2 px-1">
                        <TotalPartsSlider value={gs.totalPartsLimit} onChange={gs.setTotalPartsLimit} profile={PAINT_PROFILES[exportPaintType]} />
                      </div>
                    </div>
                  )}
                </div>
              </label>
            </section>
          )}

          {isArtistic && (
            <div className={`p-5 rounded-3xl border-2 border-indigo-100 dark:border-indigo-500/20 bg-indigo-50/50 dark:bg-indigo-500/5 relative overflow-hidden`}>
              <div className="flex items-center gap-3 mb-3">
                <div className="w-8 h-8 rounded-xl bg-indigo-600 text-white flex items-center justify-center shrink-0 shadow-lg shadow-indigo-500/20">
                   <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="m18 13-1.5-7.5L2 2l3.5 14.5L13 18l5-5z" /><circle cx="11" cy="11" r="2" /></svg>
                </div>
                <h3 className={`font-black text-xs uppercase tracking-wider text-indigo-700 dark:text-indigo-300`}>Режим художника</h3>
              </div>
              <ul className={`text-[11px] space-y-2 font-medium text-indigo-800/80 dark:text-indigo-300/70`}>
                <li className="flex gap-2"><span>•</span> <b>PDF:</b> Инструкция из 6 шагов рисования.</li>
                <li className="flex gap-2"><span>•</span> <b>HTML:</b> Интерактивный плеер для браузера.</li>
                <li className="flex gap-2"><span>•</span> <b>SVG:</b> Векторная схема текущего шага.</li>
              </ul>
            </div>
          )}
        </div>

        <div className={`flex-shrink-0 flex flex-col-reverse sm:grid sm:grid-cols-3 gap-3 p-5 border-t ${isDark ? "border-slate-800 bg-slate-900/80" : "border-slate-100 bg-slate-50/80"}`}>
          {isExporting ? (
            <div className="sm:col-span-3 w-full py-2 animate-fade-in">
              <div className="flex justify-between items-end mb-2.5 px-1">
                 <div className="text-[10px] font-black uppercase tracking-widest text-indigo-600 dark:text-indigo-400">{statusMsg}</div>
                 <div className="text-xs font-black font-mono text-indigo-500">{Math.round(progress)}%</div>
              </div>
              <div className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden shadow-inner">
                <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${progress}%` }} />
              </div>
            </div>
          ) : (
            <>
              <div className="grid grid-cols-2 gap-3 sm:contents">
                <button onClick={() => doExport("svg")} className={`flex items-center justify-center gap-2.5 py-3.5 rounded-2xl text-[11px] font-black uppercase tracking-[0.1em] border-2 transition-all active:scale-95 ${isDark ? "bg-slate-800 border-slate-700 text-slate-300 hover:bg-slate-700" : "bg-white border-slate-100 text-slate-600 hover:bg-slate-100 shadow-sm"}`}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polygon points="12 2 2 22 22 22" /></svg>
                  SVG
                </button>
                <button onClick={() => doExport("html")} className={`flex items-center justify-center gap-2.5 py-3.5 rounded-2xl text-[11px] font-black uppercase tracking-[0.1em] border-2 transition-all active:scale-95 ${isDark ? "bg-slate-800 border-slate-700 text-slate-300 hover:bg-slate-700" : "bg-white border-slate-100 text-slate-600 hover:bg-slate-100 shadow-sm"}`}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="16 18 22 12 16 6" /><polyline points="8 6 2 12 8 18" /></svg>
                  HTML
                </button>
              </div>
              <button onClick={handlePdfExport} className="col-span-1 py-4 sm:py-3.5 rounded-2xl text-xs font-black uppercase tracking-[0.2em] bg-indigo-600 text-white shadow-lg shadow-indigo-600/25 hover:bg-indigo-700 transition-all active:scale-[0.98] flex items-center justify-center gap-2.5">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" /><polyline points="14 2 14 8 20 8" /></svg>
                PDF
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}