import type { RGB } from '../../config';

export function ColorCircle({ rgb, size = 24 }: { rgb: RGB; size?: number }) {
  return <div className="rounded-full shrink-0 border border-black/10 dark:border-white/10"
    style={{ width: size, height: size, backgroundColor: `rgb(${rgb[0]},${rgb[1]},${rgb[2]})` }} />;
}
