import type { RGB, ColorComponent, PaintType, DryingProfile } from '../config';
import { PAINT_PROFILES } from '../config';
import { rgbToHsl, hslToRgb } from '../utils/colorMath';
import { mixColors } from '../utils/mixing';
import type { WellComponent, LabWell, WellRecipe } from './types';

let wellIdCounter = 0;

export function createWellId(): string {
  return `well_${Date.now()}_${++wellIdCounter}`;
}

export function createSwatchId(): string {
  return `swatch_${Date.now()}_${++wellIdCounter}`;
}

export function createEmptyWell(paintType: PaintType = 'watercolor'): LabWell {
  return {
    id: createWellId(),
    paintType,
    components: [],
    wetColor: [240, 240, 240],
    dryColor: [240, 240, 240],
    createdAt: Date.now(),
    totalParts: 0,
  };
}

export function calculateWellColor(
  components: WellComponent[],
  paintType: PaintType,
): RGB {
  const total = components.reduce((s, c) => s + c.parts, 0);
  if (total === 0) return [240, 240, 240];
  const drops = components.map(c => c.parts);
  const rgbs = components.map(c => c.rgb);
  const profile = PAINT_PROFILES[paintType];
  return mixColors(drops, rgbs, profile, [255, 255, 255]);
}

export function calculateDryColor(wetColor: RGB, drying: DryingProfile): RGB {
  if (drying.brightnessFactor === 1.0 && drying.saturationShift === 0) {
    return [...wetColor] as RGB;
  }
  const [h, s, l] = rgbToHsl(wetColor);
  
  // Эвристика: Синие и фиолетовые оттенки (Hue 200-280) обычно светлеют при высыхании сильнее,
  // чем желтые и красные. Это добавляет реализма без необходимости хранить данные для каждого пигмента.
  const isCoolColor = h > 180 && h < 300;
  const hueModifier = isCoolColor ? 1.02 : 0.98; // Легкая корректировка в зависимости от теплоты

  const newL = Math.max(0, Math.min(1, l * drying.brightnessFactor * hueModifier));
  const newS = Math.max(0, Math.min(1, s + drying.saturationShift));
  return hslToRgb(h, newS, newL);
}

export function addColorToWell(
  well: LabWell,
  color: ColorComponent,
  parts: number,
): LabWell {
  const existing = well.components.find(c => c.name === color.name);
  let newComponents: WellComponent[];

  if (existing) {
    newComponents = well.components.map(c =>
      c.name === color.name ? { ...c, parts: Math.max(0, c.parts + parts) } : c
    ).filter(c => c.parts > 0);
  } else if (parts > 0) {
    newComponents = [...well.components, { name: color.name, rgb: color.rgb, parts }];
  } else {
    newComponents = well.components;
  }

  const totalParts = newComponents.reduce((s, c) => s + c.parts, 0);
  const wetColor = totalParts > 0 ? calculateWellColor(newComponents, well.paintType) : [240, 240, 240] as RGB;
  const dryColor = totalParts > 0 ? calculateDryColor(wetColor, PAINT_PROFILES[well.paintType].drying) : [240, 240, 240] as RGB;
  
  return { ...well, components: newComponents, wetColor, dryColor, totalParts, createdAt: Date.now() };
}

export function removeColorFromWell(
  well: LabWell,
  colorName: string,
  parts: number,
): LabWell {
  const newComponents = well.components
    .map(c => c.name === colorName ? { ...c, parts: Math.max(0, c.parts - parts) } : c)
    .filter(c => c.parts > 0);

  const totalParts = newComponents.reduce((s, c) => s + c.parts, 0);
  const wetColor = totalParts > 0 ? calculateWellColor(newComponents, well.paintType) : [240, 240, 240] as RGB;
  const dryColor = totalParts > 0 ? calculateDryColor(wetColor, PAINT_PROFILES[well.paintType].drying) : [240, 240, 240] as RGB;
  
  return { ...well, components: newComponents, wetColor, dryColor, totalParts, createdAt: Date.now() };
}

export function clearWell(well: LabWell): LabWell {
  return { ...well, components: [], wetColor: [240, 240, 240], dryColor: [240, 240, 240], totalParts: 0, createdAt: Date.now() };
}

export function changeWellPaintType(well: LabWell, newPaintType: PaintType): LabWell {
  const wetColor = well.totalParts > 0 ? calculateWellColor(well.components, newPaintType) : [240, 240, 240] as RGB;
  const dryColor = well.totalParts > 0 ? calculateDryColor(wetColor, PAINT_PROFILES[newPaintType].drying) : [240, 240, 240] as RGB;
  return { ...well, paintType: newPaintType, wetColor, dryColor };
}

export function mergeWells(wellA: LabWell, wellB: LabWell): LabWell {
  const merged = new Map<string, WellComponent>();
  
  for (const c of wellA.components) {
    const existing = merged.get(c.name);
    if (existing) existing.parts += c.parts;
    else merged.set(c.name, { ...c });
  }
  
  for (const c of wellB.components) {
    const existing = merged.get(c.name);
    if (existing) existing.parts += c.parts;
    else merged.set(c.name, { ...c });
  }

  const components = Array.from(merged.values());
  const totalParts = components.reduce((s, c) => s + c.parts, 0);
  const wetColor = calculateWellColor(components, wellA.paintType);
  const dryColor = calculateDryColor(wetColor, PAINT_PROFILES[wellA.paintType].drying);
  
  return { id: createWellId(), paintType: wellA.paintType, components, wetColor, dryColor, createdAt: Date.now(), totalParts };
}

export function getWellRecipe(well: LabWell): WellRecipe {
  const total = well.totalParts || 1;
  const components = well.components.map(c => ({
    name: c.name, rgb: c.rgb, parts: c.parts, percent: Math.round((c.parts / total) * 100),
  }));

  if (components.length > 0) {
    const sum = components.reduce((s, c) => s + c.percent, 0);
    if (sum !== 100 && sum > 0) {
      const maxIdx = components.reduce((mi, c, i) => c.percent > components[mi].percent ? i : mi, 0);
      components[maxIdx].percent += 100 - sum;
    }
  }

  const toHex = (rgb: RGB) => `#${rgb.map(v => Math.max(0, Math.min(255, v)).toString(16).padStart(2, '0')).join('').toUpperCase()}`;
  return { components, totalParts: well.totalParts, wetColor: well.wetColor, dryColor: well.dryColor, wetHex: toHex(well.wetColor), dryHex: toHex(well.dryColor) };
}