// src/utils/formatting.ts
import { formatParts, formatPartsFull, type PaintProfile } from '../config';
import type { HistoryEntry } from '../types';

export function formatSmartDate(ts: number): string {
  const now = new Date();
  const d = new Date(ts);
  
  const time = d.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' });
  
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const target = new Date(d.getFullYear(), d.getMonth(), d.getDate());
  
  const diffDays = Math.round((today.getTime() - target.getTime()) / 86400000);
  
  if (diffDays === 0) return `Сегодня ${time}`;
  if (diffDays === 1) return `Вчера ${time}`;
  if (diffDays < 7 && diffDays > 0) 
    return `${d.toLocaleDateString('ru-RU', { weekday: 'short' })} ${time}`;
    
  return d.toLocaleDateString('ru-RU', { day: 'numeric', month: 'short' }) + ` ${time}`;
}

export function favKey(entry: { hex: string; recipe: { name: string; parts: number }[] }): string {
  return `${entry.hex}|${entry.recipe.map(r => `${r.name}:${r.parts}`).join(',')}`;
}

export function formatRecipeText(entry: HistoryEntry, profile: PaintProfile): string {
  const lines = [
    `Melura — Рецепт`,
    `Цвет: ${entry.hex}`,
    `Краска: ${profile.name}`,
    `ΔE: ${entry.deltaE.toFixed(1)} · ${formatPartsFull(entry.totalDrops, profile)}`,
    ``,
    `Рецепт:`,
  ];

  for (const r of entry.recipe) {
    lines.push(`  ${r.name}: ${formatParts(r.parts, profile)} (${r.percent}%)`);
  }

  lines.push(``, `RGB результат: (${entry.approxRgb[0]}, ${entry.approxRgb[1]}, ${entry.approxRgb[2]})`);
  return lines.join('\n');
}